insert into platform_topic_master (subject_slug, topic_slug, page_name, sections)
values
('spanish', 'p-1-spanish-sounds-and-the-alphabet', 'P.1 Spanish Sounds and the Alphabet', '{"learn": {"enabled": true, "items": [{"title": "The five vowel sounds — short, pure, always the same", "html": "<p>Spanish has <strong>five</strong> vowel sounds and they <strong>never change</strong> — unlike English. Each is short and crisp. Tap 🔊 to hear them.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"a\">a</span> — like ‘cat’</td><td><span data-say=\"alto\">alto</span>, <span data-say=\"antes\">antes</span></td></tr>\n              <tr><td><span data-say=\"e\">e</span> — like ‘pet’</td><td><span data-say=\"español\">español</span>, <span data-say=\"medio\">medio</span></td></tr>\n              <tr><td><span data-say=\"i\">i</span> — like ‘see’</td><td><span data-say=\"idea\">idea</span>, <span data-say=\"iglesia\">iglesia</span></td></tr>\n              <tr><td><span data-say=\"o\">o</span> — like ‘hot’</td><td><span data-say=\"dos\">dos</span>, <span data-say=\"cinco\">cinco</span></td></tr>\n              <tr><td><span data-say=\"u\">u</span> — like ‘boot’</td><td><span data-say=\"universidad\">universidad</span>, <span data-say=\"instituto\">instituto</span></td></tr>\n            </table>\n            <p>Never let a vowel ‘glide’ the way English does — keep it pure and even.</p>", "check": {"question": "How many vowel sounds does Spanish have, and do they change?", "options": ["Five, and they stay the same", "Twelve different ones, like in English", "Five, but they glide", "Three main ones only"], "answer": 0, "explain": "Five pure vowels (a, e, i, o, u) that never change — the foundation of clear Spanish."}}, {"title": "The alphabet and the extra letter ñ", "html": "<p>The Spanish alphabet is the same as English plus one extra letter: <strong>ñ</strong> (‘eñe’). Some useful letter names: <span data-say=\"be\">be</span> (b), <span data-say=\"ce\">ce</span> (c), <span data-say=\"jota\">jota</span> (j), <span data-say=\"hache\">hache</span> (h), <span data-say=\"uve\">uve</span> (v), <span data-say=\"i griega\">i griega</span> (y).</p>\n            <ul>\n              <li><strong>ñ</strong> = the ‘ny’ sound in ‘onion’: <span data-say=\"mañana\">mañana</span>, <span data-say=\"cumpleaños\">cumpleaños</span>.</li>\n              <li>Spelling aloud matters for the exam — practise spelling your name and town.</li>\n            </ul>", "check": {"question": "Which letter is unique to the Spanish alphabet?", "options": ["ñ", "k", "w", "q"], "answer": 0, "explain": "ñ (eñe) is the extra letter; it makes the ‘ny’ sound as in mañana."}}, {"title": "Stress and the written accent (á é í ó ú)", "html": "<p>Two simple rules tell you which syllable is stressed:</p>\n            <ul>\n              <li>Words ending in a <strong>vowel, n or s</strong> → stress the <strong>second-to-last</strong> syllable: <span data-say=\"hablo\">hablo</span>, <span data-say=\"joven\">joven</span>.</li>\n              <li>Words ending in any <strong>other consonant</strong> → stress the <strong>last</strong> syllable: <span data-say=\"hablar\">hablar</span>, <span data-say=\"ciudad\">ciudad</span>.</li>\n              <li>A <strong>written accent</strong> overrides both and shows the stress: <span data-say=\"región\">región</span>, <span data-say=\"sonreír\">sonreír</span>.</li>\n            </ul>\n            <p>Accents can change meaning: <span data-say=\"sí\">sí</span> (yes) vs <em>si</em> (if); <span data-say=\"él\">él</span> (he) vs <em>el</em> (the). The upside-down <strong>¿ ¡</strong> open questions and exclamations.</p>", "check": {"question": "‘hablar’ ends in ‑r. Which syllable is stressed?", "options": ["the last one (ha-blar)", "none of them — it needs a written accent", "the first one (ha-blar)", "the middle one"], "answer": 0, "explain": "Ending in a consonant other than n/s → stress the final syllable: ha-BLAR."}}, {"title": "The letter C: two sounds (+ Z and QU)", "html": "<p>The letter <strong>c</strong> makes two different sounds depending on the next letter:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><strong>ca, co, cu</strong> → hard /k/</td><td><span data-say=\"casa\">casa</span>, <span data-say=\"coche\">coche</span>, <span data-say=\"escuchar\">escuchar</span></td></tr>\n              <tr><td><strong>ce, ci</strong> → soft ‘th’ (Spain)</td><td><span data-say=\"cerca\">cerca</span>, <span data-say=\"cinco\">cinco</span></td></tr>\n            </table>\n            <ul>\n              <li><strong>z</strong> makes the same soft sound as ce/ci: <span data-say=\"zona\">zona</span>, <span data-say=\"manzana\">manzana</span>.</li>\n              <li>To get a hard /k/ before e or i, Spanish uses <strong>que, qui</strong> (the u is silent): <span data-say=\"porque\">porque</span>, <span data-say=\"quince\">quince</span>.</li>\n            </ul>", "check": {"question": "How is the ‘c’ in ‘cinco’ pronounced?", "options": ["soft (like ‘th’ / ‘s’)", "just like an English ‘ch’ sound", "hard, like ‘k’", "silent"], "answer": 0, "explain": "c before e or i is soft; before a/o/u it is hard /k/. So cinco = ‘thin-ko’."}}, {"title": "The letter G, and GUE / GUI", "html": "<p>Like c, the letter <strong>g</strong> makes two sounds:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><strong>ga, go, gu</strong> → hard /g/</td><td><span data-say=\"gato\">gato</span>, <span data-say=\"largo\">largo</span>, <span data-say=\"preguntar\">preguntar</span></td></tr>\n              <tr><td><strong>ge, gi</strong> → throaty /x/ (like ‘loch’)</td><td><span data-say=\"gente\">gente</span>, <span data-say=\"gimnasio\">gimnasio</span></td></tr>\n            </table>\n            <ul>\n              <li>To keep a hard /g/ before e or i, add a silent <strong>u</strong>: <span data-say=\"hamburguesa\">hamburguesa</span>, <span data-say=\"guitarra\">guitarra</span>.</li>\n            </ul>", "check": {"question": "How is the ‘g’ in ‘gente’ pronounced?", "options": ["throaty, like the ‘ch’ in ‘loch’", "like an English ‘j’ as in the word ‘jam’ exactly", "hard, like ‘g’ in ‘go’", "silent"], "answer": 0, "explain": "g before e or i is the throaty /x/ sound; before a/o/u it is a hard /g/."}}, {"title": "Why sounds matter in the exam", "html": "<p>Sound-Symbol Correspondences (SSCs) are tested directly:</p>\n            <ul>\n              <li><strong>Paper 2 (Speaking): Read-aloud</strong> — you read a short text out loud and are marked on accurate sounds.</li>\n              <li><strong>Paper 1 (Listening): Dictation</strong> — you write down what you hear, so you must link sound → spelling.</li>\n            </ul>\n            <p>Master a few rules (soft c, throaty g, silent h, rolled r) and both tasks become far easier. <span class=\"tier-h\">H</span> Higher texts are longer, but the same rules apply.</p>", "check": {"question": "Which TWO papers test your sound knowledge most directly?", "options": ["Speaking (read-aloud) and Listening (dictation)", "The Reading paper and the Writing paper only, nothing else", "Writing and Speaking essays", "None — sounds aren''t assessed"], "answer": 0, "explain": "Read-aloud (Paper 2) and dictation (Paper 1) both reward accurate sound-symbol links."}}]}, "terms": {"enabled": true, "pairs": [{"term": "a, e, i, o, u", "definition": "five short, pure vowels"}, {"term": "ñ (eñe)", "definition": "the ‘ny’ sound — mañana"}, {"term": "ca, co, cu", "definition": "hard /k/ — casa, coche"}, {"term": "ce, ci", "definition": "soft ‘th’/‘s’ — cerca, cinco"}, {"term": "z", "definition": "soft sound — zona, manzana"}, {"term": "que, qui", "definition": "hard /k/, silent u — porque, quince"}, {"term": "ga, go, gu", "definition": "hard /g/ — gato, largo"}, {"term": "ge, gi", "definition": "throaty /x/ — gente, gimnasio"}, {"term": "gue, gui", "definition": "hard /g/, silent u — guitarra"}, {"term": "silent h", "definition": "not pronounced — hospital, hoy"}, {"term": "written accent (é)", "definition": "marks the stressed syllable"}, {"term": "¿ ? · ¡ !", "definition": "open a question / exclamation"}, {"term": "stress rule 1", "definition": "vowel/n/s → 2nd-to-last syllable"}, {"term": "stress rule 2", "definition": "other consonant → last syllable"}, {"term": "sí vs si", "definition": "yes vs if — accent changes meaning"}, {"term": "el alfabeto", "definition": "same as English + ñ"}, {"term": "jota (j)", "definition": "throaty sound — ojo, naranja"}, {"term": "uve (v)", "definition": "soft ‘b’ sound — verde, verdad"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"cinco\" data-listen></span><br>Listen. How is the ‘c’ sound here?", "options": ["soft, like ‘th’ / ‘s’", "hard, like ‘k’ in ‘cat’", "silent, not pronounced", "rolled like a Spanish ‘r’"], "answer": 0, "explain": "‘cinco’ — c before i is soft. (Before a/o/u it would be hard.)"}, {"question": "<span data-say=\"gato\" data-listen></span><br>Listen. The ‘g’ sound is…", "options": ["hard, like ‘g’ in ‘go’", "throaty, like the ‘ch’ in ‘loch’", "silent", "soft like an English ‘j’"], "answer": 0, "explain": "‘gato’ — g before a is hard. (Before e/i it is the throaty sound.)"}, {"question": "<span data-say=\"mañana\" data-listen></span><br>Listen. Which spelling did you hear?", "options": ["mañana", "manana", "manyana", "maniana"], "answer": 0, "explain": "The ‘ny’ sound is written ñ: mañana."}, {"question": "The five Spanish vowels are best described as…", "options": ["short and always the same", "long and changing, like English", "silent most of the time", "only used in stressed syllables"], "answer": 0, "explain": "Spanish vowels are pure, short and consistent."}, {"question": "‘hablar’ ends in ‑r. Where is the stress?", "options": ["the final syllable", "the first syllable", "spread evenly across it", "shown by a written accent"], "answer": 0, "explain": "Ending in a consonant (not n/s) → stress the last syllable: ha-BLAR."}, {"question": "To write a hard /k/ sound before ‘e’, Spanish uses…", "options": ["qu (as in porque)", "just the letter c (as in cerca)", "the letter k in every case", "z (as in zona)"], "answer": 0, "explain": "que/qui give a hard /k/ (silent u); ‘c’ before e/i is soft."}, {"question": "Which word has the throaty /x/ ‘g’ sound?", "options": ["gimnasio", "gato", "largo", "guitarra"], "answer": 0, "explain": "g before i (gimnasio) is throaty; the others are hard /g/."}, {"question": "<span data-say=\"zona\" data-listen></span><br>Listen. The ‘z’ sound matches which letters?", "options": ["ce / ci (soft)", "ca / co (hard)", "qu (hard k)", "ñ (ny)"], "answer": 0, "explain": "z makes the same soft sound as ce/ci."}, {"question": "Why does ‘guitarra’ have a ‘u’ after the g?", "options": ["to keep the g hard before ‘i’", "because every single g must be followed by a u", "to make the g throaty", "to add an extra syllable"], "answer": 0, "explain": "gue/gui keep a hard /g/ before e/i; the u is silent."}, {"question": "A written accent (as in ‘región’) tells you…", "options": ["which syllable is stressed", "that you should whisper the whole word", "the word is plural", "to roll the r"], "answer": 0, "explain": "The accent marks the stressed syllable (and can change meaning)."}]}, "fib": {"enabled": true, "questions": [{"text": "The word for ‘five’ is [cinco]. <span data-say=\"cinco\" data-listen>cinco</span>"}, {"text": "The ‘ny’ sound word for ‘tomorrow’ is ma[ñan]a. <span data-say=\"mañana\" data-listen>mañana</span>"}, {"text": "To keep a hard g before i, we write gu[it]arra. <span data-say=\"guitarra\" data-listen>guitarra</span>"}, {"text": "c before e or i sounds [soft]. (hard or soft?)"}, {"text": "Words ending in a vowel, n or s stress the [second]-to-last syllable. (which one?)"}, {"text": "The extra Spanish letter is [ñ]. (its symbol)"}, {"text": "g before e or i is [throaty]. (hard or throaty?)"}]}, "tf": {"enabled": true, "questions": [{"statement": "Spanish vowels change their sound depending on the word, like English.", "answer": false, "explain": "Spanish vowels are pure and always the same."}, {"statement": "‘ñ’ is a separate letter of the Spanish alphabet.", "answer": true, "explain": "ñ (eñe) is a distinct letter; it makes the ‘ny’ sound."}, {"statement": "c before e or i is pronounced soft (like ‘th’/‘s’).", "answer": true, "explain": "ce/ci are soft; ca/co/cu are hard /k/."}, {"statement": "The letter h is usually silent in Spanish.", "answer": true, "explain": "h is silent: hospital, hoy."}, {"statement": "‘que’ and ‘qui’ give a soft ‘s’ sound.", "answer": false, "explain": "They give a hard /k/ (the u is silent)."}, {"statement": "A written accent shows which syllable is stressed.", "answer": true, "explain": "It marks stress and can change meaning (sí vs si)."}, {"statement": "g before a, o or u is hard, as in ‘gato’.", "answer": true, "explain": "ga/go/gu are hard; ge/gi are throaty."}, {"statement": "Words ending in ‑r stress the second-to-last syllable.", "answer": false, "explain": "Ending in a consonant (not n/s) → stress the LAST syllable (ha-BLAR)."}]}, "misc": {"enabled": true, "items": [{"myth": "Pronouncing ‘v’ (verde) like an English ‘v’.", "truth": "Spanish v sounds almost like a soft ‘b’: verde.", "check": {"question": "How is Spanish ‘v’ (verde) pronounced?", "options": ["almost like a soft ‘b’", "exactly like an English ‘v’", "like an English ‘f’", "it is always silent"], "answer": 0, "explain": "v and b sound almost identical in Spanish — a soft ‘b’."}}, {"myth": "Saying the ‘h’ in ‘hospital’.", "truth": "The h is silent: ‘ospital’.", "check": {"question": "How do you pronounce the h in ‘hospital’?", "options": ["you don''t — it is silent", "as a strong English ‘h’ sound", "as a throaty sound", "as a ‘j’"], "answer": 0, "explain": "h is silent in Spanish (hospital, hoy)."}}, {"myth": "Reading ‘gente’ with a hard English ‘g’.", "truth": "g before e/i is throaty: ‘hente’.", "check": {"question": "The g in ‘gente’ should sound…", "options": ["throaty, like ‘loch’", "like an English ‘j’ in ‘jam’", "hard, like ‘go’", "silent"], "answer": 0, "explain": "g before e/i is the throaty /x/, not a hard g."}}, {"myth": "Reading ‘ce’ in ‘cerca’ as a hard ‘k’.", "truth": "c before e/i is soft: ‘therka’.", "check": {"question": "The c in ‘cerca’ is…", "options": ["soft (‘th’/‘s’)", "hard, like ‘k’", "silent", "a throaty sound"], "answer": 0, "explain": "c before e/i is soft; only ca/co/cu are hard."}}, {"myth": "Letting vowels glide, e.g. ‘no’ → ‘nou’.", "truth": "Keep vowels pure and short: ‘no’.", "check": {"question": "How should you say a Spanish vowel like the ‘o’ in ‘no’?", "options": ["short and pure, no glide", "long, gliding towards an ‘ou’ sound", "silent unless stressed", "rolled"], "answer": 0, "explain": "Spanish vowels never glide — keep them crisp."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 2 — Read-aloud (speaking)", "html": "Before you read, scan for the traps: soft c/z, throaty ge/gi, silent h, and the vowels. Read slowly and evenly — accurate sounds beat speed. Rolling the rr and keeping vowels pure make the biggest difference.", "check": {"question": "What matters most in the read-aloud task?", "options": ["accurate sounds, read steadily", "reading it as fast as you possibly can", "a loud English accent", "skipping the hard words"], "answer": 0, "explain": "You''re marked on accurate pronunciation, not speed."}}, {"title": "Paper 1 — Dictation (listening)", "html": "Link sound to spelling: a soft ‘th’ could be c (ce/ci) or z; a throaty sound is ge/gi or j; a silent h still gets written. Say the word in your head and picture the letters.", "check": {"question": "You hear a throaty sound before an ‘e’. It is most likely spelt…", "options": ["ge or j", "gue or gui", "ca", "qu"], "answer": 0, "explain": "The throaty /x/ before e is ge (or j); gue would be a hard g."}}, {"title": "Paper 4 — Accents in writing", "html": "In written Spanish, missing or wrong accents can cost accuracy marks and even change meaning (sí/si, él/el). When you learn a word, learn its accent as part of the spelling.", "check": {"question": "Why do written accents matter in Paper 4?", "options": ["they affect accuracy and can change meaning", "they only ever matter when you are speaking aloud", "they are optional decoration", "they show the plural"], "answer": 0, "explain": "Accents carry meaning and accuracy marks (sí = yes vs si = if)."}}]}, "exam": {"enabled": true, "questions": [{"question": "<strong>Read-aloud practice.</strong> Read this text out loud, then tick the sounds you produced correctly.<br><br><em>«Hola. Me llamo Guille. Vivo en una ciudad grande y voy al gimnasio los jueves. La gente aquí es muy simpática.»</em><br><br>Hear a model first: 🔊 <span data-say=\"Hola. Me llamo Guille. Vivo en una ciudad grande y voy al gimnasio los jueves. La gente aquí es muy simpática.\">model</span>", "marks": 5, "hint": "Watch: gui (hard g), ciudad (soft c), gimnasio & gente (throaty g), jueves (throaty j), the silent h in Hola, and pure vowels.", "markScheme": "<div class=\"marks-section\"><h5>Self-mark — 5 pronunciation points</h5><ul>\n                <li>Silent <strong>h</strong> in ‘Hola’ (not an English h).</li>\n                <li><strong>gui</strong> in ‘Guille’ = hard g (silent u).</li>\n                <li>Soft <strong>c</strong> in ‘ciudad’ (‘th’/‘s’, not ‘k’).</li>\n                <li>Throaty <strong>g/j</strong> in ‘gimnasio’, ‘gente’, ‘jueves’.</li>\n                <li>Pure, even <strong>vowels</strong> throughout.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Tick each feature you produced correctly. In the real NEA an examiner rewards clear, comprehensible pronunciation.</li>\n            </ul></div>"}, {"question": "<strong>Dictation.</strong> Listen and write the four words you hear, then check them.<br>🔊 <span data-say=\"cinco\" data-listen>word 1</span> &nbsp; 🔊 <span data-say=\"gente\" data-listen>word 2</span> &nbsp; 🔊 <span data-say=\"guitarra\" data-listen>word 3</span> &nbsp; 🔊 <span data-say=\"mañana\" data-listen>word 4</span>", "marks": 4, "hint": "Think about the sound rules: soft c, throaty g vs hard gui, the ‘ny’ = ñ.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 4 marks</h5><ul>\n                <li>1 = <strong>cinco</strong> (soft c) · 2 = <strong>gente</strong> (throaty g) · 3 = <strong>guitarra</strong> (hard gui) · 4 = <strong>mañana</strong> (ñ).</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>1 mark per correctly-spelt word. Minor accent slips are condoned once.</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', 'p-2-tricky-letters-ll-ch-j-h-r-v', 'P.2 Tricky Letters: ll, ch, ñ, j, h, r, v', '{"learn": {"enabled": true, "items": [{"title": "ll — one letter, one sound: the ‘y’ in ‘yes’", "html": "<p>The double letter <strong>ll</strong> is never two separate ‘l’ sounds — in most of the Spanish-speaking world it is pronounced like the English <strong>‘y’</strong> in ‘yes’.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"llamar\">llamar</span> — to call</td><td>sounds like ‘ya-MAR’</td></tr>\n              <tr><td><span data-say=\"calle\">calle</span> — street</td><td>sounds like ‘CA-ye’</td></tr>\n              <tr><td><span data-say=\"amarillo\">amarillo</span> — yellow</td><td>sounds like ‘a-ma-RI-yo’</td></tr>\n              <tr><td><span data-say=\"silla\">silla</span> — chair</td><td>sounds like ‘SI-ya’</td></tr>\n            </table>\n            <p>English speakers often say a hard ‘l’ sound (as in the word ‘llama’ mispronounced in English) — resist that instinct.</p>", "check": {"question": "How is the ‘ll’ in ‘calle’ pronounced?", "options": ["like the ‘y’ in ‘yes’", "as two separate English ‘l’ sounds run together", "silent — it isn''t pronounced at all", "like the throaty ‘ch’ in ‘loch’"], "answer": 0, "explain": "ll = ‘y’ sound: calle sounds like ‘CA-ye’, not ‘CAL-le’."}}, {"title": "ch — always the familiar English ‘ch’", "html": "<p><strong>ch</strong> is one of the easier tricky letters: it always sounds like the English ‘ch’ in ‘chip’ — and it never softens the way it can in French.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"leche\">leche</span> — milk</td><td>‘LE-che’, as in ‘chip’</td></tr>\n              <tr><td><span data-say=\"ocho\">ocho</span> — eight</td><td>‘O-cho’, as in ‘chip’</td></tr>\n              <tr><td><span data-say=\"noche\">noche</span> — night</td><td>‘NO-che’</td></tr>\n              <tr><td><span data-say=\"mucho\">mucho</span> — a lot</td><td>‘MU-cho’</td></tr>\n            </table>\n            <p>Because it is so close to the English sound, the real risk is skipping it or swapping it for a soft ‘sh’ — keep it crisp.</p>", "check": {"question": "How should you pronounce the ‘ch’ in ‘leche’?", "options": ["like the English ‘ch’ in ‘chip’", "silent — it isn''t pronounced at all", "like a soft French ‘sh’ sound", "like a hard English ‘k’ sound"], "answer": 0, "explain": "ch is always the familiar English ‘ch’ sound — leche = ‘LE-che’."}}, {"title": "ñ — a ‘ny’ glide, not a plain n", "html": "<p><strong>ñ</strong> (‘eñe’) is a separate letter from ‘n’ and always adds a ‘y’ glide, like the ‘ny’ in ‘canyon’.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"mañana\">mañana</span> — tomorrow</td><td>‘ma-NYA-na’</td></tr>\n              <tr><td><span data-say=\"cumpleaños\">cumpleaños</span> — birthday</td><td>‘cum-ple-A-nyos’</td></tr>\n              <tr><td><span data-say=\"pequeño\">pequeño</span> — small</td><td>‘pe-QUE-nyo’</td></tr>\n              <tr><td><span data-say=\"año\">año</span> — year</td><td>‘A-nyo’</td></tr>\n            </table>\n            <p>Dropping the tilde and saying a plain ‘n’ is a very common English-speaker error — the glide is essential, not optional decoration.</p>", "check": {"question": "What does the tilde on ‘ñ’ change about the sound?", "options": ["it adds a ‘y’ glide, giving ‘ny’", "it makes the letter completely silent, with no sound", "it turns the n into an ‘m’ sound", "nothing — ñ and n sound identical"], "answer": 0, "explain": "ñ = ‘ny’, as in cumpleaños (‘cum-ple-A-nyos’) — never a plain n."}}, {"title": "j and h — similar on the page, opposite in sound", "html": "<p>These two letters trip learners up because they sit close together conceptually, yet do opposite things.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><strong>j</strong> → throaty /x/</td><td><span data-say=\"ojo\">ojo</span>, <span data-say=\"naranja\">naranja</span>, <span data-say=\"trabajar\">trabajar</span></td></tr>\n              <tr><td><strong>h</strong> → always silent</td><td><span data-say=\"hospital\">hospital</span>, <span data-say=\"hoy\">hoy</span>, <span data-say=\"ahora\">ahora</span></td></tr>\n            </table>\n            <p><strong>j</strong> is pronounced from the back of the throat, like the Scottish ‘loch’ — never like an English ‘j’ (as in ‘jam’). <strong>h</strong> is never pronounced at all, even at the start of a word.</p>", "check": {"question": "Which statement correctly contrasts j and h?", "options": ["j is a throaty sound; h is always silent", "j is silent; h is a throaty sound instead", "both letters are completely silent in Spanish", "both letters sound like an English ‘j’ in ‘jam’"], "answer": 0, "explain": "j = throaty /x/ (ojo); h = never pronounced (hospital = ‘os-pi-TAL’)."}}, {"title": "r vs rr — a quick tap or a strong roll?", "html": "<p>Spanish has two different r-sounds, and mixing them up can change the meaning of a word entirely.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td>single <strong>r</strong> between vowels → one quick tap</td><td><span data-say=\"pero\">pero</span> (but), <span data-say=\"hablar\">hablar</span> (to speak)</td></tr>\n              <tr><td><strong>rr</strong>, or <strong>r</strong> at the start of a word → strongly rolled</td><td><span data-say=\"cerrar\">cerrar</span> (to close), <span data-say=\"sonreír\">sonreír</span> (to smile), <span data-say=\"perro\">perro</span> (dog)</td></tr>\n            </table>\n            <p>The signature exam trap is the minimal pair <span data-say=\"pero\">pero</span> (‘but’) vs <span data-say=\"perro\">perro</span> (‘dog’) — say the wrong one and the sentence stops making sense. <span class=\"tier-h\">H</span> Higher-tier read-aloud texts pack several of these r-sounds into one sentence, so practise the switch.</p>", "check": {"question": "What is the difference between ‘pero’ and ‘perro’?", "options": ["a single tap vs a strongly rolled r, and the meaning changes completely", "nothing at all — the two words are pronounced in exactly the same identical way", "‘pero’ has a silent r and ‘perro’ does not", "only the stress moves to a different syllable"], "answer": 0, "explain": "pero (single tap, ‘but’) vs perro (rolled rr, ‘dog’) — a classic minimal pair."}}, {"title": "v and b — the same soft ‘b’ sound", "html": "<p>In Spanish, <strong>v</strong> and <strong>b</strong> are pronounced almost identically — a soft ‘b’, made without fully closing the lips. Spanish speakers do not distinguish them the way English does.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"verde\">verde</span> — green</td><td>soft ‘b’, not an English ‘v’</td></tr>\n              <tr><td><span data-say=\"verdad\">verdad</span> — truth</td><td>soft ‘b’, not an English ‘v’</td></tr>\n              <tr><td><span data-say=\"vivir\">vivir</span> — to live</td><td>soft ‘b’ at the start too</td></tr>\n              <tr><td><span data-say=\"beber\">beber</span> — to drink</td><td>compare: also a soft ‘b’</td></tr>\n            </table>\n            <p>The letter''s own name — <span data-say=\"uve\">uve</span> — is a useful reminder: it borrows the ‘b’ sound, not an English ‘v’.</p>", "check": {"question": "How does Spanish ‘v’ (as in ‘verde’) sound?", "options": ["almost exactly like a soft ‘b’ sound", "exactly like an English ‘v’, as in ‘van’", "like an English ‘f’ sound instead", "it is completely silent"], "answer": 0, "explain": "Spanish v and b share the same soft ‘b’-like sound — verde is not an English ‘v’."}}]}, "terms": {"enabled": true, "pairs": [{"term": "ll (llamar)", "definition": "sounds like ‘y’ — ‘ya-MAR’"}, {"term": "ll (calle)", "definition": "sounds like ‘y’ — ‘CA-ye’"}, {"term": "ch (leche)", "definition": "English ‘ch’ — ‘LE-che’"}, {"term": "ch (ocho)", "definition": "English ‘ch’ — ‘O-cho’"}, {"term": "ñ (mañana)", "definition": "‘ny’ glide — ‘ma-NYA-na’"}, {"term": "ñ (cumpleaños)", "definition": "‘ny’ glide — ‘cum-ple-A-nyos’"}, {"term": "j (ojo)", "definition": "throaty /x/ — like Scottish ‘loch’"}, {"term": "j (naranja)", "definition": "throaty /x/ sound"}, {"term": "silent h (hospital)", "definition": "not pronounced — ‘os-pi-TAL’"}, {"term": "silent h (hoy)", "definition": "not pronounced at all"}, {"term": "single r (pero)", "definition": "one quick tap between vowels"}, {"term": "single r (hablar)", "definition": "one quick tap between vowels"}, {"term": "rr (cerrar)", "definition": "strongly rolled"}, {"term": "rr (perro)", "definition": "strongly rolled — ‘dog’"}, {"term": "word-initial r (sonreír)", "definition": "rolled, like rr"}, {"term": "v (verde)", "definition": "soft ‘b’ sound, not English v"}, {"term": "b (beber)", "definition": "same soft ‘b’ sound as v"}, {"term": "pero vs perro", "definition": "‘but’ vs ‘dog’ — single tap vs rolled rr"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"llamar\" data-listen></span><br>Listen. The ‘ll’ sound you hear is closest to the English…", "options": ["‘y’ in ‘yes’", "‘l’ sound, doubled up and held for longer", "‘j’ in the English word ‘jam’", "‘w’ in ‘wet’"], "answer": 0, "explain": "ll = ‘y’ sound: llamar sounds like ‘ya-MAR’."}, {"question": "<span data-say=\"leche\" data-listen></span><br>Listen. How is the ‘ch’ in this word pronounced?", "options": ["silent — it isn''t pronounced at all", "like the English ‘ch’ in ‘chip’", "like a soft French ‘sh’ sound", "like a hard English ‘k’ sound"], "answer": 1, "explain": "ch is always the familiar English ‘ch’ — leche = ‘LE-che’."}, {"question": "<span data-say=\"cumpleaños\" data-listen></span><br>Listen. Which spelling matches what you hear?", "options": ["cumpleanos", "cumplenos", "cumpleaños", "cumpleagnos"], "answer": 2, "explain": "The ‘ny’ glide is written with a tilde: cumpleaños."}, {"question": "Which pair of words BOTH contain the throaty j sound?", "options": ["ojo and naranja", "hoy and hospital", "calle and llamar", "leche and ocho"], "answer": 0, "explain": "ojo and naranja both use the throaty /x/ j sound."}, {"question": "<span data-say=\"perro\" data-listen></span><br>Listen. Is this r single-tap or rolled?", "options": ["silent, not pronounced at all", "pronounced like an English r, as in ‘red’", "a single quick tap of the tongue", "strongly rolled — this is the rr sound"], "answer": 3, "explain": "perro is spelt with rr, so the r is strongly rolled."}, {"question": "<span data-say=\"pero\" data-listen></span><br>Listen. Is this r single-tap or rolled?", "options": ["a single quick tap of the tongue", "strongly rolled, like the rr in perro", "silent — the r isn''t pronounced here", "pronounced with an English r sound"], "answer": 0, "explain": "A single r between vowels (pero) is just one quick tap."}, {"question": "Why do ‘pero’ (but) and ‘perro’ (dog) mean completely different things?", "options": ["they are actually pronounced exactly the same way", "one of them uses a silent h at the start that completely changes its meaning", "a single-tap r versus a strongly rolled rr changes the word", "the stress moves from the first to the second syllable"], "answer": 2, "explain": "The single r / rolled rr distinction is what separates pero from perro."}, {"question": "<span data-say=\"verde\" data-listen></span><br>Listen. The consonant sound you hear is closest to an English…", "options": ["‘f’ sound", "soft ‘b’ sound", "‘v’ sound, exactly as in English", "silent sound — nothing is pronounced"], "answer": 1, "explain": "Spanish v and b share the same soft ‘b’-like sound."}, {"question": "Which two words BOTH contain a silent letter?", "options": ["llamar and calle", "naranja and ojo", "verde and verdad", "hospital and hoy"], "answer": 3, "explain": "hospital and hoy both start with a silent h."}, {"question": "<span data-say=\"calle\" data-listen></span><br>Listen. Which spelling matches what you hear?", "options": ["carre", "calle", "cae", "calye"], "answer": 1, "explain": "The ‘y’ sound here is written ll: calle."}]}, "fib": {"enabled": true, "questions": [{"text": "The word for ‘street’ is [calle]. <span data-say=\"calle\" data-listen>calle</span>"}, {"text": "The word for ‘birthday’, with its ‘ny’ sound, is cumplea[ños]. <span data-say=\"cumpleaños\" data-listen>cumpleaños</span>"}, {"text": "ll sounds like the English letter [y]. (which one?)"}, {"text": "j is pronounced from the back of the throat, like the Scottish word ‘[loch]’."}, {"text": "A single r between vowels, as in ‘pero’, is a quick [tap]. (tap or roll?)"}, {"text": "‘perro’ has a strongly [rolled] r. (tap or roll?)"}, {"text": "The word for ‘green’ is [verde]. <span data-say=\"verde\" data-listen>verde</span>"}]}, "tf": {"enabled": true, "questions": [{"statement": "In most Spanish accents, ‘ll’ sounds like the English ‘y’.", "answer": true, "explain": "ll = ‘y’ sound: llamar, calle."}, {"statement": "The letter h is usually pronounced strongly in Spanish, just like in English.", "answer": false, "explain": "h is always silent: hospital, hoy."}, {"statement": "‘ch’ always sounds like the English ‘ch’ in ‘chip’.", "answer": true, "explain": "ch never softens — leche, ocho."}, {"statement": "A single r between vowels (as in ‘pero’) is rolled just as strongly as the rr in ‘perro’.", "answer": false, "explain": "Single r = one quick tap; rr = a strong roll."}, {"statement": "ñ adds a ‘y’ glide, making ‘mañana’ sound like ‘ma-NYA-na’.", "answer": true, "explain": "ñ = ‘ny’, never a plain n."}, {"statement": "Spanish ‘v’ is pronounced exactly like an English ‘v’.", "answer": false, "explain": "Spanish v sounds like a soft ‘b’, not an English v."}, {"statement": "‘j’ is pronounced from the back of the throat, similar to the Scottish ‘loch’.", "answer": true, "explain": "j = throaty /x/: ojo, naranja."}, {"statement": "‘pero’ and ‘perro’ are pronounced identically.", "answer": false, "explain": "pero (single tap) vs perro (rolled rr) — a minimal pair with different meanings."}]}, "misc": {"enabled": true, "items": [{"myth": "Pronouncing ‘ll’ (as in llamar) as two separate English ‘l’ sounds.", "truth": "‘ll’ is a single ‘y’ sound: llamar sounds like ‘ya-MAR’.", "check": {"question": "How should ‘ll’ in ‘llamar’ sound?", "options": ["like the English ‘y’ in ‘yes’", "like two separate English ‘l’ sounds run together", "like the throaty j sound instead", "silent, with no sound at all"], "answer": 0, "explain": "ll is a single ‘y’ sound, never two ‘l’ sounds."}}, {"myth": "Pronouncing the h in ‘hospital’ as a strong English h.", "truth": "h is always silent: ‘hospital’ sounds like ‘os-pi-TAL’.", "check": {"question": "How is the h in ‘hospital’ pronounced?", "options": ["it isn''t — the h is always silent", "as a strong English h sound, exactly like the start of ‘hospital’ in English", "as a throaty j sound instead", "as a soft ‘ch’ sound"], "answer": 0, "explain": "h is never pronounced in Spanish."}}, {"myth": "Rolling the r in ‘pero’ as strongly as in ‘perro’.", "truth": "A single r between vowels (pero) is just one quick tap.", "check": {"question": "How strongly should the r in ‘pero’ be rolled?", "options": ["barely at all — it is a single quick tap", "exactly as strongly as the rr in ‘perro’", "not pronounced at all", "rolled even more strongly than rr"], "answer": 0, "explain": "Single r between vowels = one quick tap, not a roll."}}, {"myth": "Pronouncing Spanish v (as in verde) like an English v.", "truth": "Spanish v sounds almost like a soft b: verde.", "check": {"question": "How is Spanish ‘v’ (verde) pronounced?", "options": ["almost like a soft ‘b’ sound", "exactly like an English ‘v’, as in ‘van’", "like an English ‘f’ sound instead", "it is always silent"], "answer": 0, "explain": "v and b sound almost identical in Spanish — a soft ‘b’."}}, {"myth": "Saying ‘mañana’ with a plain n instead of the ñ glide.", "truth": "ñ always adds a ‘y’ glide: ‘ma-NYA-na’.", "check": {"question": "What happens if you drop the tilde and say a plain n in ‘mañana’?", "options": ["you lose the essential ‘y’ glide the ñ adds", "nothing at all changes — n and ñ are pronounced exactly the same way", "the whole word becomes silent", "the stress moves to a different syllable"], "answer": 0, "explain": "ñ is a distinct letter with its own ‘ny’ sound."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 2 — Read-aloud (speaking)", "html": "Scan the text first for tricky-letter traps: ll (y sound), ch, ñ (ny), j (throaty), silent h, single r vs rolled rr, and v/b (soft b). Read steadily — accurate sounds are worth more than speed.", "check": {"question": "What should you do before reading a Paper 2 text aloud?", "options": ["scan it for tricky-letter traps like ll, ñ, j and rr", "read it as fast as possible without stopping to think", "skip over any word you find difficult to say", "translate every single word into English first"], "answer": 0, "explain": "Spotting the traps in advance stops you defaulting to English sounds mid-sentence."}}, {"title": "Paper 1 — Dictation (listening)", "html": "Listen for the minimal pairs: a single tap is r (pero), a strong roll is rr (perro) — this one difference changes the word''s meaning. A ‘y’ sound is almost always ll; a ‘ny’ glide is always ñ.", "check": {"question": "In dictation, a strongly rolled r sound should usually be written as…", "options": ["rr, or r at the very start of a word", "a single r written between two vowels only, never at the start", "ñ, with a tilde added", "silent — don''t write it at all"], "answer": 0, "explain": "A rolled r is written rr (or word-initial r); a single tap is a lone r."}}, {"title": "Paper 4 — Spelling tricky letters accurately", "html": "Confusing ll/y, ñ/n, v/b, or single r/rr in writing changes meaning (pero/perro) or reads as a spelling error. Learn each tricky letter as part of the word''s spelling, not as an afterthought.", "check": {"question": "Why does it matter if you write ‘pero’ instead of ‘perro’ in an exam answer?", "options": ["it is a completely different word with a different meaning", "examiners never distinguish between the two different spellings at all", "it only affects your pronunciation mark, not writing", "both spellings are always accepted as identical"], "answer": 0, "explain": "pero (‘but’) and perro (‘dog’) are different words — the spelling carries meaning."}}]}, "exam": {"enabled": true, "questions": [{"question": "<strong>Read-aloud practice.</strong> Read this text out loud, then tick the sounds you produced correctly.<br><br><em>«Mi amigo Guillermo tiene un perro que se llama Chico. Vivimos en una calle cerca del hospital, y mañana vamos a la playa. Mi hermano prefiere el chocolate, pero yo prefiero la naranja y llevo una camiseta verde.»</em><br><br>Hear a model first: 🔊 <span data-say=\"Mi amigo Guillermo tiene un perro que se llama Chico. Vivimos en una calle cerca del hospital, y mañana vamos a la playa. Mi hermano prefiere el chocolate, pero yo prefiero la naranja y llevo una camiseta verde.\">model</span>", "marks": 7, "hint": "Watch: Guillermo/llama/calle/llevo (ll = y), Chico/chocolate (ch), hospital (silent h), mañana (ñ), naranja (throaty j), perro vs pero (rolled rr vs single tap), verde (soft b, not v).", "markScheme": "<div class=\"marks-section\"><h5>Self-mark — 7 pronunciation points</h5><ul>\n                <li><strong>ll</strong> = ‘y’ sound in Guillermo, llama, calle, llevo.</li>\n                <li><strong>ch</strong> in Chico and chocolate sounds like English ‘ch’.</li>\n                <li>Silent <strong>h</strong> in ‘hospital’.</li>\n                <li><strong>ñ</strong> glide in ‘mañana’.</li>\n                <li>Throaty <strong>j</strong> in ‘naranja’.</li>\n                <li><strong>rr</strong> in ‘perro’ rolled strongly; <strong>r</strong> in ‘pero’ a single tap.</li>\n                <li><strong>v</strong> in ‘verde’ pronounced as a soft ‘b’.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Tick each feature you produced correctly. In the real NEA an examiner rewards clear, comprehensible pronunciation.</li>\n            </ul></div>"}, {"question": "<strong>Dictation.</strong> Listen and write the five words you hear, then check them.<br>🔊 <span data-say=\"llamar\" data-listen>word 1</span> &nbsp; 🔊 <span data-say=\"mañana\" data-listen>word 2</span> &nbsp; 🔊 <span data-say=\"hospital\" data-listen>word 3</span> &nbsp; 🔊 <span data-say=\"perro\" data-listen>word 4</span> &nbsp; 🔊 <span data-say=\"verde\" data-listen>word 5</span>", "marks": 5, "hint": "Think about the sound rules: ll = y, ñ = ny, silent h, rolled rr, v = soft b.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks</h5><ul>\n                <li>1 = <strong>llamar</strong> (ll) · 2 = <strong>mañana</strong> (ñ) · 3 = <strong>hospital</strong> (silent h) · 4 = <strong>perro</strong> (rr) · 5 = <strong>verde</strong> (v).</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>1 mark per correctly-spelt word. Minor accent slips are condoned once.</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', 'g-1-nouns-articles-and-gender', 'G.1 Nouns, Articles and Gender', '{"learn": {"enabled": true, "items": [{"title": "What is grammatical gender?", "html": "<p>Every Spanish noun (naming word) is either <strong>masculine</strong> or <strong>feminine</strong> — this is its <em>gender</em>. Gender decides which word for \"the\" or \"a\" you use in front of it.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el chico\">el chico</span></td><td>the boy (masc.)</td><td><span data-say=\"la chica\">la chica</span></td><td>the girl (fem.)</td></tr>\n              <tr><td><span data-say=\"el libro\">el libro</span></td><td>the book (masc.)</td><td><span data-say=\"la mesa\">la mesa</span></td><td>the table (fem.)</td></tr>\n            </table>\n            <p>Gender is not about meaning — <span data-say=\"la mesa\">la mesa</span> (table) is grammatically feminine even though a table has no gender in real life. You simply have to learn <strong>el</strong> or <strong>la</strong> with every new noun as you meet it.</p>", "check": {"question": "What does ''gender'' mean for a Spanish noun?", "options": ["it is masculine or feminine, shown by el or la before it", "it is singular or plural, shown by adding an -s or -es ending", "it is a person, a place or a thing in the sentence", "it carries a written accent on the final vowel"], "answer": 0, "explain": "Gender = masculine or feminine; it decides el/la, un/una and adjective endings, not number or word type."}}, {"title": "How do I know if a noun is masculine or feminine?", "html": "<p>The general rule: nouns ending in <strong>-o</strong> are usually masculine, and nouns ending in <strong>-a</strong> are usually feminine.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el coche\">el coche</span></td><td>the car</td><td><span data-say=\"la casa\">la casa</span></td><td>the house</td></tr>\n              <tr><td><span data-say=\"el gato\">el gato</span></td><td>the cat</td><td><span data-say=\"la ventana\">la ventana</span></td><td>the window</td></tr>\n            </table>\n            <p>But watch these common <strong>exceptions</strong> — words ending in -a that are actually masculine (many come from Greek):</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el día\">el día</span></td><td>the day</td><td><span data-say=\"el mapa\">el mapa</span></td><td>the map</td></tr>\n              <tr><td><span data-say=\"el problema\">el problema</span></td><td>the problem</td><td><span data-say=\"el clima\">el clima</span></td><td>the climate</td></tr>\n            </table>\n            <p>And one very common word ending in -o that is feminine instead: <span data-say=\"la mano\">la mano</span> (the hand).</p>\n            <p>Example: <span data-say=\"El problema es que la mano me duele.\">El problema es que la mano me duele.</span> — The problem is that my hand hurts.</p>", "check": {"question": "Which of these words is masculine, even though it ends in -a?", "options": ["el problema", "la habitación", "la ventana", "la mesa"], "answer": 0, "explain": "el problema, el día, el mapa and el clima end in -a but are masculine — common exceptions to learn by heart."}}, {"title": "Nouns ending in -ción, -sión or -dad", "html": "<p>Another reliable rule: nouns ending in <strong>-ción</strong>, <strong>-sión</strong> or <strong>-dad</strong> are always feminine — this rule has no exceptions.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la nación\">la nación</span></td><td>the nation</td><td><span data-say=\"la información\">la información</span></td><td>the information</td></tr>\n              <tr><td><span data-say=\"la televisión\">la televisión</span></td><td>the television</td><td><span data-say=\"la ciudad\">la ciudad</span></td><td>the city</td></tr>\n            </table>\n            <p>This is one of the most useful rules in GCSE Spanish because it always works — memorise it and you can always get the article right for these endings.</p>\n            <p>Example: <span data-say=\"La ciudad tiene mucha información sobre la nación.\">La ciudad tiene mucha información sobre la nación.</span></p>", "check": {"question": "What gender are nouns ending in -ción, -sión or -dad?", "options": ["always feminine, with no exceptions to learn", "always masculine, unless the word is very short", "masculine in the singular but feminine in the plural", "it depends on the very first letter of the word"], "answer": 0, "explain": "-ción/-sión/-dad nouns are always feminine — one of the few gender rules with no exceptions."}}, {"title": "Definite articles: el, la, los, las", "html": "<p>\"The\" changes depending on gender AND number (singular/plural):</p>\n            <table class=\"vocab-tbl\">\n              <tr><td>masc. singular</td><td><span data-say=\"el libro\">el libro</span></td><td>masc. plural</td><td><span data-say=\"los libros\">los libros</span></td></tr>\n              <tr><td>fem. singular</td><td><span data-say=\"la mesa\">la mesa</span></td><td>fem. plural</td><td><span data-say=\"las mesas\">las mesas</span></td></tr>\n            </table>\n            <p><span class=\"tier-h\">H</span> One tricky rule: a feminine singular noun that starts with a stressed <strong>a-</strong> sound takes <strong>el</strong> instead of <strong>la</strong>, just to avoid two a-sounds clashing — but it stays feminine, so the plural is still <strong>las</strong>: <span data-say=\"el agua\">el agua</span> (fem.) → <span data-say=\"las aguas\">las aguas</span>.</p>", "check": {"question": "What is the plural of ''la ciudad''?", "options": ["las ciudades", "los ciudades", "las ciudad", "el ciudades"], "answer": 0, "explain": "la → las for feminine plural, and ciudad adds -es because it ends in a consonant → las ciudades."}}, {"title": "Indefinite articles: un, una, unos, unas", "html": "<p>\"A / an\" is <strong>un</strong> (masc.) or <strong>una</strong> (fem.). The plural forms <strong>unos / unas</strong> mean \"some\":</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"un libro\">un libro</span></td><td>a book</td><td><span data-say=\"unos libros\">unos libros</span></td><td>some books</td></tr>\n              <tr><td><span data-say=\"una mesa\">una mesa</span></td><td>a table</td><td><span data-say=\"unas mesas\">unas mesas</span></td><td>some tables</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Tengo un problema y unas preguntas.\">Tengo un problema y unas preguntas.</span> — I have a problem and some questions.</p>", "check": {"question": "How do you say ''some cities'' in Spanish?", "options": ["unas ciudades", "unos ciudades", "unas ciudad", "un ciudades"], "answer": 0, "explain": "ciudad is feminine → unas; the plural adds -es because it ends in a consonant → unas ciudades."}}, {"title": "Forming plurals + the contractions del and al", "html": "<p>Plural rules for nouns:</p>\n            <ul>\n              <li>ends in a vowel → add <strong>-s</strong>: <span data-say=\"el coche\">el coche</span> → <span data-say=\"los coches\">los coches</span></li>\n              <li>ends in a consonant → add <strong>-es</strong>: <span data-say=\"el profesor\">el profesor</span> → <span data-say=\"los profesores\">los profesores</span></li>\n              <li>ends in <strong>-z</strong> → change to <strong>-c</strong> and add <strong>-es</strong>: <span data-say=\"el lápiz\">el lápiz</span> → <span data-say=\"los lápices\">los lápices</span>; <span data-say=\"la luz\">la luz</span> → <span data-say=\"las luces\">las luces</span></li>\n            </ul>\n            <p><span class=\"tier-h\">H</span> Two contractions are compulsory in Spanish: <strong>de + el = del</strong>, and <strong>a + el = al</strong> (Spanish never writes <em>de el</em> or <em>a el</em>).</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"del colegio\">del colegio</span></td><td>of / from the school</td><td><span data-say=\"al gimnasio\">al gimnasio</span></td><td>to the gym</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Voy al gimnasio después del colegio.\">Voy al gimnasio después del colegio.</span> — I go to the gym after school.</p>", "check": {"question": "Which sentence uses the contractions correctly?", "options": ["Voy al gimnasio después del colegio.", "Voy a el gimnasio después de el colegio.", "Voy al gimnasio después de el colegio.", "Voy a el gimnasio después del colegio."], "answer": 0, "explain": "a+el must always contract to al, and de+el must always contract to del — both together, every time."}}]}, "terms": {"enabled": true, "pairs": [{"term": "el chico / la chica", "definition": "the boy / the girl"}, {"term": "el libro / la mesa", "definition": "the book / the table"}, {"term": "el problema", "definition": "the problem (masc. exception)"}, {"term": "el día", "definition": "the day (masc. exception)"}, {"term": "el mapa", "definition": "the map (masc. exception)"}, {"term": "el clima", "definition": "the climate (masc. exception)"}, {"term": "la mano", "definition": "the hand (fem. exception)"}, {"term": "la nación", "definition": "the nation (-ción = feminine)"}, {"term": "la información", "definition": "the information"}, {"term": "la ciudad", "definition": "the city (-dad = feminine)"}, {"term": "un / una", "definition": "a, an (masc. / fem.)"}, {"term": "unos / unas", "definition": "some (masc. / fem. plural)"}, {"term": "los lápices", "definition": "the pencils (z → c plural)"}, {"term": "las luces", "definition": "the lights (z → c plural)"}, {"term": "los profesores", "definition": "the teachers (consonant + es)"}, {"term": "del (H)", "definition": "de + el = of / from the"}, {"term": "al (H)", "definition": "a + el = to the"}, {"term": "el agua (H)", "definition": "the water (fem. noun, el for the sound)"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"la ciudad\" data-listen></span><br>Listen. What is being said?", "options": ["the city", "the nation", "the day", "the problem"], "answer": 0, "explain": "‘la ciudad’ = the city. The traps are all other gender-rule nouns from this topic."}, {"question": "<span data-say=\"el mapa\" data-listen></span><br>Listen. Which word did you hear?", "options": ["el mapa", "la mapa", "el mano", "la mano"], "answer": 0, "explain": "mapa is a masculine exception → el mapa. The traps swap the gender or swap in a different exception word (mano)."}, {"question": "<span data-say=\"el problema\" data-listen></span><br>Listen and choose the correct English meaning.", "options": ["the problem", "the climate", "the day", "the map"], "answer": 0, "explain": "‘el problema’ = the problem. All four options are genuine masculine -a exceptions, so you must listen carefully."}, {"question": "Choose the correct article: ___ problema es difícil.", "options": ["El", "La", "Los", "Las"], "answer": 0, "explain": "problema is a masculine exception ending in -a → El problema. La/Los/Las are all wrong gender or number."}, {"question": "Choose the correct plural of ''el lápiz''.", "options": ["los lápices", "los lápizes", "las lápices", "los lápiz"], "answer": 0, "explain": "z changes to c before -es: el lápiz → los lápices. Trap B keeps the z; C changes the gender; D forgets the plural ending."}, {"question": "How do you say ''a house'' in Spanish?", "options": ["una casa", "un casa", "unos casa", "unas casas"], "answer": 0, "explain": "casa is feminine singular → una casa. B uses the masculine article; C and D wrongly make it plural."}, {"question": "Which is the correct way to say ''to the gym''?", "options": ["al gimnasio", "a el gimnasio", "del gimnasio", "a la gimnasio"], "answer": 0, "explain": "a + el must contract to al. B leaves it uncontracted; C confuses al with del (of/from); D mixes a with the wrong gender article."}, {"question": "Which of these nouns is feminine?", "options": ["la nación", "el día", "el mapa", "el problema"], "answer": 0, "explain": "nación ends in -ción, so it is always feminine. The other three are classic masculine exceptions ending in -a."}, {"question": "Choose the correct plural: ''una ciudad'' → ___", "options": ["unas ciudades", "unos ciudades", "unas ciudad", "un ciudades"], "answer": 0, "explain": "ciudad is feminine → unas; the consonant ending adds -es → unas ciudades."}, {"question": "Which phrase correctly means ''the boy''s book'' (el libro ___ chico)?", "options": ["del", "de el", "de la", "al"], "answer": 0, "explain": "de + el must contract to del. B leaves it uncontracted; C uses the wrong gender; D confuses del with al (to the)."}]}, "fib": {"enabled": true, "questions": [{"text": "[El] problema es muy grande. <span data-say=\"El problema es muy grande.\" data-listen>El problema es muy grande.</span>"}, {"text": "Voy [al] colegio a las ocho. <span data-say=\"Voy al colegio a las ocho.\" data-listen>Voy al colegio a las ocho.</span>"}, {"text": "Tengo [unas] preguntas sobre la tarea. <span data-say=\"Tengo unas preguntas sobre la tarea.\" data-listen>Tengo unas preguntas sobre la tarea.</span>"}, {"text": "Necesito dos [lápices] nuevos para el examen. <span data-say=\"Necesito dos lápices nuevos para el examen.\" data-listen>Necesito dos lápices nuevos para el examen.</span>"}, {"text": "[La] ciudad tiene mucha información. <span data-say=\"La ciudad tiene mucha información.\" data-listen>La ciudad tiene mucha información.</span>"}, {"text": "Salgo [del] gimnasio después de las clases. <span data-say=\"Salgo del gimnasio después de las clases.\" data-listen>Salgo del gimnasio después de las clases.</span>"}, {"text": "Escucha y escribe la palabra que falta: Me duele la [mano]. <span data-say=\"la mano\" data-listen></span>"}]}, "tf": {"enabled": true, "questions": [{"statement": "All nouns ending in -o are masculine, with no exceptions.", "answer": false, "explain": "la mano is a common exception — it ends in -o but is feminine."}, {"statement": "''el problema'' is masculine even though it ends in -a.", "answer": true, "explain": "el problema, el día, el mapa and el clima are exceptions ending in -a."}, {"statement": "Nouns ending in -ción, -sión or -dad are always feminine.", "answer": true, "explain": "This rule has no exceptions — la nación, la televisión, la ciudad."}, {"statement": "The plural of ''el lápiz'' is ''los lápizes''.", "answer": false, "explain": "z changes to c before -es: the correct plural is los lápices."}, {"statement": "''un'' and ''una'' both mean ''the''.", "answer": false, "explain": "un/una mean ''a/an''; el/la mean ''the''."}, {"statement": "''a + el'' must contract to ''al''.", "answer": true, "explain": "Spanish never writes ''a el'' — it always contracts to al."}, {"statement": "''de la casa'' should contract to ''dela casa''.", "answer": false, "explain": "Only de+el (→del) and a+el (→al) contract; de+la never changes."}, {"statement": "''unas ciudades'' means ''some cities''.", "answer": true, "explain": "unas = some (fem. plural); ciudades = cities."}]}, "misc": {"enabled": true, "items": [{"myth": "la problema", "truth": "el problema", "check": {"question": "Why is ''el problema'' correct, not ''la problema''?", "options": ["''problema'' is a masculine exception ending in -a", "''problema'' is only ever used in the plural form", "''la'' is used before every noun that starts with p", "''problema'' takes no article at all in Spanish"], "answer": 0, "explain": "problema, día, mapa and clima are masculine despite ending in -a."}}, {"myth": "el mano", "truth": "la mano", "check": {"question": "Why is ''la mano'' correct, not ''el mano''?", "options": ["''mano'' is a feminine exception ending in -o", "''mano'' is a masculine noun in every context", "''mano'' takes no article at all in Spanish", "''la'' is used only with plural nouns like manos"], "answer": 0, "explain": "la mano is one of the few -o nouns that is actually feminine."}}, {"myth": "de el chico", "truth": "del chico", "check": {"question": "Why must you write ''del chico'', not ''de el chico''?", "options": ["de + el always contracts to del", "de and el can never appear in the same sentence", "''del'' is only ever used with feminine nouns", "''chico'' automatically changes de into del"], "answer": 0, "explain": "de+el must contract to del — Spanish never writes de el."}}, {"myth": "lápizes", "truth": "lápices", "check": {"question": "Why is the plural ''lápices'', not ''lápizes''?", "options": ["z changes to c before adding the plural ending -es", "lápiz never has a plural form in Spanish at all", "you simply add -s after any consonant ending", "the written accent always moves onto the final syllable"], "answer": 0, "explain": "Nouns ending in -z change z→c before -es: lápiz→lápices, luz→luces."}}, {"myth": "el ciudad", "truth": "la ciudad", "check": {"question": "Why is ''la ciudad'' correct, not ''el ciudad''?", "options": ["nouns ending in -dad are always feminine", "''ciudad'' is a masculine exception like día or mapa", "''el'' is used before any word with more than two syllables", "ciudad has no fixed gender and either article works"], "answer": 0, "explain": "-dad nouns are always feminine — la ciudad, la verdad, la libertad."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 1 — Listening: gender clues", "html": "Even when you don''t catch every word, el/la/un/una/los/las tell you the gender and number before the noun arrives. Listen for ''del'' and ''al'' too — they signal ''from/of the'' and ''to the'', and both only ever attach to a masculine noun.", "check": {"question": "You hear ''del colegio''. What must the noun ''colegio'' be?", "options": ["masculine, because del can only exist as de + el", "feminine, because del always marks a feminine noun", "plural, because del is a special plural marker", "in the future tense, because del signals ''will''"], "answer": 0, "explain": "del only exists because de+el contract — colegio must be masculine."}}, {"title": "Paper 3 — Reading: spotting exceptions", "html": "Examiners love testing el día, el mapa, el problema, el clima and la mano because they break the -o/-a rule. If a text uses ''el'' before what looks like a feminine-shaped noun, check it isn''t one of these classic exceptions before you answer.", "check": {"question": "In a reading text you see ''el mapa''. What should you remember?", "options": ["mapa is a genuine masculine exception, not an error", "this must be a printing mistake somewhere in the exam paper", "mapa is always used in the plural in Spanish", "el is being used here instead of los by mistake"], "answer": 0, "explain": "el mapa is a genuine masculine exception, not an error."}}, {"title": "Paper 4 — Writing: agreement checks", "html": "Before you submit written work, re-read every noun phrase and check three things: the article''s gender matches the noun, the article''s number matches the noun, and de+el / a+el have been contracted to del/al. These small slips cost easy marks.", "check": {"question": "Which phrase is fully correct?", "options": ["Voy al gimnasio después del colegio", "Voy a el gimnasio después de el colegio", "Voy al gimnasio después de el colegio", "Voy a el gimnasio después del colegio"], "answer": 0, "explain": "Both contractions must be applied together: al and del."}}]}, "exam": {"enabled": true, "questions": [{"question": "For each noun, write the correct definite article (<strong>el</strong> or <strong>la</strong>) and its plural form. (5 marks — one mark per noun)<br>(1) problema &nbsp; (2) ciudad &nbsp; (3) mano &nbsp; (4) lápiz &nbsp; (5) mapa", "marks": 5, "hint": "Remember: -ma words are masculine exceptions; -dad words are feminine; mano is a feminine exception ending in -o; -z becomes -ces in the plural.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks</h5><ul>\n                <li><strong>(1)</strong> el problema → los problemas <em>(1)</em></li>\n                <li><strong>(2)</strong> la ciudad → las ciudades <em>(1)</em></li>\n                <li><strong>(3)</strong> la mano → las manos <em>(1)</em></li>\n                <li><strong>(4)</strong> el lápiz → los lápices <em>(1)</em></li>\n                <li><strong>(5)</strong> el mapa → los mapas <em>(1)</em></li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Award the mark only if BOTH the article and the plural form are correct.</li>\n            </ul></div>"}, {"question": "Translate these sentences <strong>into Spanish</strong>.<br>(a) The problem is big. <br>(b) I go to the gym after school. <br>(c) I have some questions.", "marks": 4, "hint": "''problem'' is a masculine exception; ''to the gym'' = al gimnasio; ''after school'' = después del colegio; ''some'' before a feminine plural = unas.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 4 marks (AO4 Writing: translation)</h5><ul>\n                <li><strong>(a)</strong> El problema es grande. <em>(1)</em></li>\n                <li><strong>(b)</strong> Voy al gimnasio <em>(1)</em> después del colegio <em>(1)</em>.</li>\n                <li><strong>(c)</strong> Tengo unas preguntas. <em>(1)</em></li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent errors. Both ''al'' and ''del'' must be contracted, not written as ''a el'' / ''de el''.</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', 'g-2-adjectives-and-agreement', 'G.2 Adjectives and Agreement', '{"learn": {"enabled": true, "items": [{"title": "How do adjectives agree with the noun?", "html": "<p>In Spanish, adjectives must <strong>agree</strong> with the noun they describe — in both <strong>gender</strong> (masculine/feminine) and <strong>number</strong> (singular/plural). Most adjectives end in <strong>-o</strong> for masculine and change to <strong>-a</strong> for feminine; add <strong>-s</strong> for the plural.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"alto\">alto</span></td><td>tall (m. sing.)</td><td><span data-say=\"alta\">alta</span></td><td>tall (f. sing.)</td></tr>\n              <tr><td><span data-say=\"altos\">altos</span></td><td>tall (m. pl.)</td><td><span data-say=\"altas\">altas</span></td><td>tall (f. pl.)</td></tr>\n              <tr><td><span data-say=\"pequeño\">pequeño</span></td><td>small (m.)</td><td><span data-say=\"pequeña\">pequeña</span></td><td>small (f.)</td></tr>\n            </table>\n            <p>Model sentences: <span data-say=\"Mi hermano es alto.\">Mi hermano es alto.</span> (My brother is tall.) — <span data-say=\"Mi hermana es alta.\">Mi hermana es alta.</span> (My sister is tall.) — <span data-say=\"Mis hermanos son altos.\">Mis hermanos son altos.</span> (My brothers are tall.)</p>", "check": {"question": "Why does ‘alto’ change to ‘alta’ in ‘Mi hermana es alta’?", "options": ["it must agree with the feminine noun ‘hermana’", "all adjectives ending in -o are irregular", "‘hermana’ is a plural noun, not singular", "the verb ‘ser’ forces every adjective to end in -a"], "answer": 0, "explain": "Adjectives agree with the gender of the noun they describe — hermana is feminine, so alto → alta."}}, {"title": "Adjectives ending in -e or a consonant", "html": "<p>Some adjectives do <strong>not</strong> change for gender — only for number. This includes adjectives ending in <strong>-e</strong> (add -s for the plural) and most ending in a <strong>consonant</strong> (add -es for the plural).</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"grande\">grande</span></td><td>big (m./f.)</td><td><span data-say=\"grandes\">grandes</span></td><td>big (pl.)</td></tr>\n              <tr><td><span data-say=\"inteligente\">inteligente</span></td><td>intelligent (m./f.)</td><td><span data-say=\"inteligentes\">inteligentes</span></td><td>intelligent (pl.)</td></tr>\n              <tr><td><span data-say=\"fácil\">fácil</span></td><td>easy (m./f.)</td><td><span data-say=\"fáciles\">fáciles</span></td><td>easy (pl., accent drops)</td></tr>\n              <tr><td><span data-say=\"azul\">azul</span></td><td>blue (m./f.)</td><td><span data-say=\"azules\">azules</span></td><td>blue (pl.)</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Es una casa grande.\">Es una casa grande.</span> (It is a big house.) — <span data-say=\"Son unos libros fáciles.\">Son unos libros fáciles.</span> (They are some easy books.)</p>", "check": {"question": "Why does ‘grande’ stay the same in both ‘un chico grande’ AND ‘una chica grande’?", "options": ["adjectives ending in -e do not change for gender", "grande must always be placed directly before the noun", "grande only describes masculine nouns", "grande behaves like a verb, not an adjective"], "answer": 0, "explain": "Adjectives ending in -e (grande, inteligente) have one form for masculine and feminine — only the plural changes."}}, {"title": "Adjectives of nationality", "html": "<p>Nationality adjectives ending in a <strong>consonant</strong> add <strong>-a</strong> for the feminine (unlike other consonant adjectives). Nationality adjectives already ending in <strong>-o</strong> or <strong>-e</strong> just follow the normal rules.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"español\">español</span></td><td>Spanish (m.)</td><td><span data-say=\"española\">española</span></td><td>Spanish (f.)</td></tr>\n              <tr><td><span data-say=\"francés\">francés</span></td><td>French (m.)</td><td><span data-say=\"francesa\">francesa</span></td><td>French (f., accent drops)</td></tr>\n              <tr><td><span data-say=\"inglés\">inglés</span></td><td>English (m.)</td><td><span data-say=\"inglesa\">inglesa</span></td><td>English (f.)</td></tr>\n              <tr><td><span data-say=\"canadiense\">canadiense</span></td><td>Canadian (-e, invariable)</td><td><span data-say=\"belga\">belga</span></td><td>Belgian (invariable)</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Tengo una amiga española.\">Tengo una amiga española.</span> (I have a Spanish friend.) Plural: <span data-say=\"franceses\">franceses</span> / <span data-say=\"francesas\">francesas</span>.</p>", "check": {"question": "How do you say ‘a French friend’ (female)?", "options": ["una amiga francesa", "un amigo francés", "una amiga francés", "unas amigas francesas"], "answer": 0, "explain": "francés adds -a for the feminine: francesa. ‘amiga’ is feminine so the adjective must agree — francés with no -a is left masculine."}}, {"title": "Where does the adjective go?", "html": "<p>Unlike English, most Spanish adjectives go <strong>AFTER</strong> the noun: <span data-say=\"una casa grande\">una casa grande</span> (a big house) — NOT “una grande casa”. <span data-say=\"un coche rojo\">un coche rojo</span> (a red car). <span data-say=\"unos libros interesantes\">unos libros interesantes</span> (some interesting books).</p>\n            <p>A few common adjectives can go <strong>before</strong> the noun and sometimes shorten: <span data-say=\"bueno\">bueno</span> → <span data-say=\"buen\">buen</span> (before a masculine singular noun): <span data-say=\"un buen amigo\">un buen amigo</span>. Likewise <span data-say=\"malo\">malo</span> → <span data-say=\"mal\">mal</span>: <span data-say=\"un mal día\">un mal día</span>. <span class=\"tier-h\">H</span> <span data-say=\"grande\">grande</span> shortens to <span data-say=\"gran\">gran</span> before either gender and changes meaning: <span data-say=\"un gran hombre\">un gran hombre</span> (a great man) vs <span data-say=\"un hombre grande\">un hombre grande</span> (a big man).</p>", "check": {"question": "Where does a normal Spanish adjective usually go?", "options": ["after the noun it describes", "before the noun, like in English", "at the very end of the sentence", "immediately after the verb ‘ser’"], "answer": 0, "explain": "Most Spanish adjectives follow the noun: una casa grande, not una grande casa."}}, {"title": "Comparatives and superlatives", "html": "<p>Comparatives: <span data-say=\"más que\">más + adjective + que</span> (more … than), <span data-say=\"menos que\">menos + adjective + que</span> (less … than), <span data-say=\"tan como\">tan + adjective + como</span> (as … as).</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"Soy más alto que mi hermano.\">Soy más alto que mi hermano.</span></td><td>I am taller than my brother.</td></tr>\n              <tr><td><span data-say=\"Es menos interesante que la otra película.\">Es menos interesante que la otra película.</span></td><td>It is less interesting than the other film.</td></tr>\n              <tr><td><span data-say=\"Ella es tan inteligente como su hermana.\">Ella es tan inteligente como su hermana.</span></td><td>She is as intelligent as her sister.</td></tr>\n            </table>\n            <p>Superlative: el/la (los/las) + más + adjective — <span data-say=\"Es el chico más alto de la clase.\">Es el chico más alto de la clase.</span> (He is the tallest boy in the class.)</p>", "check": {"question": "How do you say ‘as easy as’ in Spanish?", "options": ["tan fácil como", "más fácil que", "menos fácil que", "el más fácil de"], "answer": 0, "explain": "tan + adjective + como = as … as. más…que = more…than; menos…que = less…than."}}, {"title": "Higher: irregular comparatives, possessives, demonstratives", "html": "<p><span class=\"tier-h\">H</span> Four common adjectives have an <strong>irregular comparative</strong> — never say “más bueno” or “más malo”:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"bueno, mejor\">bueno → mejor</span></td><td>good → better</td></tr>\n              <tr><td><span data-say=\"malo, peor\">malo → peor</span></td><td>bad → worse</td></tr>\n              <tr><td><span data-say=\"viejo, mayor\">viejo → mayor</span></td><td>old → older</td></tr>\n              <tr><td><span data-say=\"joven, menor\">joven → menor</span></td><td>young → younger</td></tr>\n            </table>\n            <p><strong>Possessive adjectives</strong> agree in number (nuestro/-a agrees in gender too): <span data-say=\"mi casa\">mi casa</span> / <span data-say=\"mis casas\">mis casas</span> (my), <span data-say=\"tu libro\">tu libro</span> / <span data-say=\"tus libros\">tus libros</span> (your), <span data-say=\"su coche\">su coche</span> / <span data-say=\"sus coches\">sus coches</span> (his/her/their), <span data-say=\"nuestra familia\">nuestra familia</span> / <span data-say=\"nuestro perro\">nuestro perro</span> (our).</p>\n            <p><strong>Demonstratives</strong>: <span data-say=\"este libro\">este libro</span> / <span data-say=\"esta casa\">esta casa</span> / <span data-say=\"estos zapatos\">estos zapatos</span> / <span data-say=\"estas chicas\">estas chicas</span> (this/these, close by); <span data-say=\"ese chico\">ese chico</span> / <span data-say=\"esa chica\">esa chica</span> (that, further away).</p>", "check": {"question": "Why is ‘más mejor’ always wrong?", "options": ["mejor is already a comparative — you never add más in front", "mejor must always be placed immediately before the noun it describes", "mejor only exists in the plural form", "más can only combine with -e ending adjectives"], "answer": 0, "explain": "mejor, peor, mayor and menor are already comparative forms — combining them with más creates a double comparative, which is wrong."}}]}, "terms": {"enabled": true, "pairs": [{"term": "alto / alta / altos / altas", "definition": "tall (agrees in gender + number)"}, {"term": "grande", "definition": "big (-e ending, no gender change)"}, {"term": "inteligente", "definition": "intelligent (no gender change)"}, {"term": "fácil / fáciles", "definition": "easy (sing. / pl.)"}, {"term": "azul / azules", "definition": "blue (sing. / pl.)"}, {"term": "español / española", "definition": "Spanish (m. / f.)"}, {"term": "francés / francesa", "definition": "French (m. / f.)"}, {"term": "una casa grande", "definition": "a big house (adjective after noun)"}, {"term": "un gran hombre (H)", "definition": "a great man (gran before noun)"}, {"term": "más … que", "definition": "more … than"}, {"term": "menos … que", "definition": "less … than"}, {"term": "tan … como", "definition": "as … as"}, {"term": "el/la más …", "definition": "the most … (superlative)"}, {"term": "mejor / peor (H)", "definition": "better / worse"}, {"term": "mayor / menor (H)", "definition": "older / younger"}, {"term": "mi / tu / su", "definition": "my / your / his-her (agree in number)"}, {"term": "nuestro / nuestra", "definition": "our (agrees in gender + number)"}, {"term": "este/esta/estos/estas · ese/esa (H)", "definition": "this/these (near) · that (further)"}]}, "mcq": {"enabled": true, "questions": [{"question": "Which sentence correctly describes ‘the tall girls’?", "options": ["las chicas altas", "los chicas altas", "las chicas alta", "la chica alta"], "answer": 0, "explain": "las chicas altas — article, noun and adjective all agree feminine plural. B mismatches the article; C drops the plural -s; D is singular."}, {"question": "<span data-say=\"una camisa azul\" data-listen></span><br>Listen. What do you hear?", "options": ["a blue shirt", "some blue shirts", "a blue dress", "the blue shirts"], "answer": 0, "explain": "‘una camisa azul’ = a blue shirt (singular). B and D wrongly make it plural; C swaps the noun for ‘dress’."}, {"question": "Choose the correctly agreeing phrase: ‘unos coches ___’ (red)", "options": ["rojos", "rojo", "roja", "rojas"], "answer": 0, "explain": "‘unos coches’ is masculine plural, so the adjective must be rojos. rojo is singular, roja/rojas are feminine."}, {"question": "How do you say ‘a Spanish friend’ (female)?", "options": ["una amiga española", "un amigo español", "una amiga español", "unas amigas españolas"], "answer": 0, "explain": "amiga is feminine singular → española. B changes the noun to masculine; C fails to agree; D wrongly makes it plural."}, {"question": "Which sentence has the adjective in the correct position?", "options": ["una casa grande", "una grande casa", "grande una casa", "casa una grande"], "answer": 0, "explain": "Spanish adjectives normally follow the noun: una casa grande. The other options put grande before the noun or scramble the word order."}, {"question": "How do you say ‘taller than’?", "options": ["más alto que", "más alto de", "tan alto como", "menos alto que"], "answer": 0, "explain": "más…que = more…than (taller than). ‘de’ is wrong after más in a comparison; tan…como = as…as; menos…que = less…than."}, {"question": "How do you say ‘the most interesting book’?", "options": ["el libro más interesante", "el más interesante libro", "el libro interesante más", "un libro más interesante"], "answer": 0, "explain": "The superlative keeps the adjective after the noun: el libro más interesante. D uses ‘un’, not the definite article needed for a superlative."}, {"question": "How do you say ‘my older brother’?", "options": ["mi hermano mayor", "mi hermano más viejo", "mi hermano más grande", "mi más mayor hermano"], "answer": 0, "explain": "mayor is the irregular comparative of viejo. B avoids the irregular form; C confuses ‘big’ with ‘old’; D wrongly doubles the comparative."}, {"question": "How do you say ‘our house’ (la casa is feminine)?", "options": ["nuestra casa", "nuestro casa", "nuestras casa", "nuestros casa"], "answer": 0, "explain": "nuestro/-a agrees in gender AND number: casa is feminine singular → nuestra casa. The others fail to agree."}, {"question": "<span data-say=\"Quiero estos zapatos.\" data-listen></span><br>Listen. What does he want?", "options": ["these shoes", "that shoe", "those shoes over there", "this shoe"], "answer": 0, "explain": "‘estos zapatos’ = these shoes (close by, plural). B and D wrongly make it singular; C confuses ‘estos’ (this/these) with ‘aquellos’ (those over there)."}]}, "fib": {"enabled": true, "questions": [{"text": "Mi hermana es muy [alta]. (tall, feminine)"}, {"text": "Los libros son muy [interesantes]. (interesting, plural)"}, {"text": "Tengo un perro [negro]. (black, masculine)"}, {"text": "Es una camisa [azul]. <span data-say=\"Es una camisa azul.\" data-listen>Es una camisa azul.</span>"}, {"text": "Mi hermano [mayor] es más alto que yo. (older)"}, {"text": "Quiero comprar [estos] zapatos negros. (these, masculine plural)"}, {"text": "En [nuestra] casa vivimos con mis abuelos. (our, feminine singular)"}]}, "tf": {"enabled": true, "questions": [{"statement": "Adjectives change their ending depending on the gender and number of the noun they describe.", "answer": true, "explain": "alto/alta/altos/altas — Spanish adjectives agree with the noun."}, {"statement": "‘grande’ changes to ‘granda’ for a feminine noun.", "answer": false, "explain": "grande does not change for gender at all — una casa grande, un chico grande."}, {"statement": "Adjectives of nationality ending in a consonant, like ‘español’, add -a for the feminine.", "answer": true, "explain": "español → española, francés → francesa."}, {"statement": "In Spanish, adjectives are almost always placed BEFORE the noun.", "answer": false, "explain": "Most Spanish adjectives go AFTER the noun: una casa grande, not una grande casa."}, {"statement": "‘más alto que’ means ‘taller than’.", "answer": true, "explain": "más + adjective + que = more…than / -er than."}, {"statement": "The comparative of ‘bueno’ (good) is ‘más bueno’.", "answer": false, "explain": "bueno has an irregular comparative: mejor, not más bueno."}, {"statement": "‘mi’, ‘tu’ and ‘su’ have the same form for masculine and feminine singular nouns.", "answer": true, "explain": "mi casa / mi libro — mi, tu and su only change for number (mis, tus, sus), not gender."}, {"statement": "‘este’ is used for something close to the speaker, ‘ese’ for something further away.", "answer": true, "explain": "este/esta = this (near me); ese/esa = that (near you / a bit further away)."}]}, "misc": {"enabled": true, "items": [{"myth": "una casa alto", "truth": "una casa alta", "check": {"question": "Why is ‘una casa alto’ wrong?", "options": ["‘casa’ is feminine, so the adjective must be ‘alta’", "adjectives never change to agree with nouns", "‘alto’ must always be placed immediately before the noun ‘casa’", "‘casa’ is a masculine noun in Spanish"], "answer": 0, "explain": "casa is feminine, so alto must become alta to agree."}}, {"myth": "los chicas altos", "truth": "las chicas altas", "check": {"question": "What is wrong with ‘los chicas altos’?", "options": ["the article AND the adjective must both be feminine plural", "‘chicas’ should be spelt ‘chicos’ instead", "‘altos’ needs a written accent on its final letter to agree", "nothing — this sentence is already correct"], "answer": 0, "explain": "chicas is feminine plural, so both the article (las) and the adjective (altas) must agree with it."}}, {"myth": "más mejor", "truth": "mejor", "check": {"question": "Why can’t you say ‘más mejor’ for ‘better’?", "options": ["mejor is already the comparative — adding más creates a double comparative", "mejor is actually classified as an adverb, not an adjective, so más cannot apply to it", "más can only be used with colours", "mejor must always follow the noun it describes"], "answer": 0, "explain": "mejor already means ‘better’; putting más in front (‘more better’) is a double comparative and is always wrong."}}, {"myth": "una grande casa", "truth": "una casa grande", "check": {"question": "Why is ‘una grande casa’ wrong for ‘a big house’?", "options": ["most descriptive adjectives go AFTER the noun in Spanish", "grande must always be shortened to gran", "‘casa’ always needs to be placed at the very start of the sentence", "grande should change to grandes here"], "answer": 0, "explain": "In this everyday sense (size), grande follows the noun: una casa grande. Gran before the noun changes the meaning to ‘great’."}}, {"myth": "mi amigas", "truth": "mis amigas", "check": {"question": "What is missing from ‘mi amigas’?", "options": ["the plural -s on the possessive: ‘mis’", "an accent on the final letter of ‘amigas’", "the article ‘las’ before ‘amigas’", "a comma after ‘mi’"], "answer": 0, "explain": "Possessive adjectives agree in number with the noun — ‘amigas’ is plural, so it must be mis amigas."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 1 — Listening for agreement", "html": "Listen closely to adjective endings: -o/-a tells you the gender of what is being described, -s/-es tells you if it is plural. ‘Tengo dos hermanas altas’ tells you there is more than one sister before you even hear ‘dos’.", "check": {"question": "You hear ‘…mis primas simpáticas…’. What does the -as ending on ‘simpáticas’ tell you?", "options": ["more than one female cousin is being described", "only one male cousin is being described", "the sentence is set in the past", "nothing — adjective endings carry no information"], "answer": 0, "explain": "The -as ending agrees with feminine plural ‘primas’ — more than one female cousin."}}, {"title": "Paper 3 — Reading & translation into English", "html": "Nationality adjectives are a common trap: ‘francés’ changes to ‘francesa’ for a woman and drops its accent. Also watch adjective position — ‘un gran hombre’ (a great man) is not the same as ‘un hombre grande’ (a big man).", "check": {"question": "‘Mi profesora es una gran mujer’ means…", "options": ["My teacher is a great woman", "My teacher is a very tall woman", "My teacher is an old woman", "My teacher is a large woman"], "answer": 0, "explain": "gran before the noun means ‘great’ (character), not physical size — that would be grande after the noun."}}, {"title": "Paper 4 — Writing & translation into Spanish", "html": "For the top band, combine a comparative or superlative with a possessive and a demonstrative: ‘Este es mi mejor amigo; es más simpático que los otros.’ Higher students should also try mayor/menor and gran for range.", "check": {"question": "Which answer shows the widest range of grammar for top marks?", "options": ["Este es mi mejor amigo; es más simpático que los otros", "Tengo un amigo muy simpático. Es alto y también es inteligente", "Mi amigo es bueno", "Tengo amigos simpáticos"], "answer": 0, "explain": "It links a demonstrative, a possessive, an irregular comparative (mejor) and a full comparative structure — range plus accuracy, not just extra short sentences."}}]}, "exam": {"enabled": true, "questions": [{"question": "Make each adjective agree with the noun and write out the full phrase.<br>(a) unas casas (grande)<br>(b) el chico (español)<br>(c) la profesora (español)<br>(d) los libros (fácil)<br>(e) mis hermanos (mayor)", "marks": 5, "hint": "Check whether the noun is masculine/feminine and singular/plural, then check whether the adjective is an -o/-a type, an -e type, a nationality, or an irregular comparative.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (AO4 Writing: grammar)</h5><ul>\n                <li><strong>(a)</strong> unas casas grandes <em>(1)</em> — -e ending, plural +s only.</li>\n                <li><strong>(b)</strong> el chico español <em>(1)</em> — masculine singular, no change.</li>\n                <li><strong>(c)</strong> la profesora española <em>(1)</em> — nationality consonant ending +a for feminine.</li>\n                <li><strong>(d)</strong> los libros fáciles <em>(1)</em> — consonant ending, plural +es, accent drops.</li>\n                <li><strong>(e)</strong> mis hermanos mayores <em>(1)</em> — irregular comparative, plural +es, possessive agrees in number.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>One mark per fully correct phrase; accept minor accent slips if the agreement itself is correct.</li>\n            </ul></div>"}, {"question": "Translate these sentences <strong>into Spanish</strong>.<br>(a) My sister is taller than me.<br>(b) This is the best book.<br>(c) Our house is very big.", "marks": 4, "hint": "‘taller than’ = más alto/alta que. ‘the best’ = el/la mejor (irregular, no más). ‘our’ must agree with ‘casa’ (feminine).", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 4 marks (AO4 Writing: translation)</h5><ul>\n                <li><strong>(a)</strong> Mi hermana es más alta que yo. <em>(1)</em></li>\n                <li><strong>(b)</strong> Este es el mejor libro. <em>(2)</em> — 1 for este/es, 1 for el mejor libro (no ‘más bueno’).</li>\n                <li><strong>(c)</strong> Nuestra casa es muy grande. <em>(1)</em></li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent errors. ‘más alta’ must agree with the feminine subject (hermana).</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', 'g-3-present-tense-and-key-irregulars', 'G.3 Present Tense and Key Irregulars', '{"learn": {"enabled": true, "items": [{"title": "How do regular -ar, -er, -ir verbs work?", "html": "<p>The present tense describes what happens now or generally. Remove the -ar/-er/-ir ending and add the pattern endings. Model verb <span data-say=\"hablar\">hablar</span> (to speak):</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"hablo\">hablo</span></td><td>I speak</td><td><span data-say=\"hablamos\">hablamos</span></td><td>we speak</td></tr>\n              <tr><td><span data-say=\"hablas\">hablas</span></td><td>you speak</td><td><span data-say=\"habláis\">habláis</span></td><td>you all speak</td></tr>\n              <tr><td><span data-say=\"habla\">habla</span></td><td>he/she speaks</td><td><span data-say=\"hablan\">hablan</span></td><td>they speak</td></tr>\n            </table>\n            <p>-er verbs like <span data-say=\"comer\">comer</span> (to eat): <span data-say=\"como, comes, come, comemos, coméis, comen\">como, comes, come, comemos, coméis, comen</span>. -ir verbs like <span data-say=\"vivir\">vivir</span> (to live): <span data-say=\"vivo, vives, vive, vivimos, vivís, viven\">vivo, vives, vive, vivimos, vivís, viven</span>.</p>\n            <p>Model sentence: <span data-say=\"Vivo en Madrid y hablo dos idiomas.\">Vivo en Madrid y hablo dos idiomas.</span> — <em>I live in Madrid and I speak two languages.</em></p>", "check": {"question": "What is the ‘yo’ (I) ending for a regular -ir verb like ‘vivir’?", "options": ["-o (vivo)", "-as (vivas)", "-amos (vivamos)", "-en (viven)"], "answer": 0, "explain": "Regular -ar, -er and -ir verbs all take -o for ‘yo’: vivo, como, hablo."}}, {"title": "ser vs estar — two verbs for ‘to be’", "html": "<p>Spanish has two verbs for ‘to be’ and examiners test the difference constantly.</p>\n            <p><strong>ser</strong> — permanent/identity: <span data-say=\"soy, eres, es, somos, sois, son\">soy, eres, es, somos, sois, son</span>. Use for personality, nationality, jobs, time: <span data-say=\"Soy alta y soy española.\">Soy alta y soy española.</span> (I am tall and I am Spanish.)</p>\n            <p><strong>estar</strong> — temporary state/location: <span data-say=\"estoy, estás, está, estamos, estáis, están\">estoy, estás, está, estamos, estáis, están</span>. Use for feelings, mood, position: <span data-say=\"Estoy cansado porque estoy en el gimnasio.\">Estoy cansado porque estoy en el gimnasio.</span> (I am tired because I am at the gym.)</p>\n            <p>Compare: <span data-say=\"Es aburrido.\">Es aburrido.</span> (He is a boring person) vs <span data-say=\"Está aburrido.\">Está aburrido.</span> (He is bored right now).</p>", "check": {"question": "Which verb do you use to say WHERE something is located?", "options": ["estar (está en Madrid)", "ser (es en Madrid)", "tener (tiene en Madrid)", "hacer (hace en Madrid)"], "answer": 0, "explain": "Location always uses estar: está en Madrid. ‘ser en’ is a very common wrong-verb error."}}, {"title": "tener, ir, hacer — three essential irregulars", "html": "<p>These three verbs appear in almost every exam answer.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"tener\">tener</span></td><td>to have</td><td><span data-say=\"tengo, tienes, tiene, tenemos, tenéis, tienen\">tengo, tienes, tiene…</span></td></tr>\n              <tr><td><span data-say=\"ir\">ir</span></td><td>to go</td><td><span data-say=\"voy, vas, va, vamos, vais, van\">voy, vas, va…</span></td></tr>\n              <tr><td><span data-say=\"hacer\">hacer</span></td><td>to do/make</td><td><span data-say=\"hago, haces, hace, hacemos, hacéis, hacen\">hago, haces, hace…</span></td></tr>\n            </table>\n            <p>Remember <span data-say=\"tener que + infinitivo\">tener que + infinitive</span> (to have to) and <span data-say=\"ir a + infinitivo\">ir a + infinitive</span> (going to, near future): <span data-say=\"Tengo quince años y voy a hacer mis deberes.\">Tengo quince años y voy a hacer mis deberes.</span> — <em>I am fifteen and I am going to do my homework.</em></p>", "check": {"question": "How do you say ‘I have to study’?", "options": ["Tengo que estudiar", "Tengo estudiar", "Voy que estudiar", "Tengo que estudiando"], "answer": 0, "explain": "tener que + infinitive = to have to study. B is missing ‘que’; C uses the wrong verb; D wrongly uses the gerund instead of the infinitive."}}, {"title": "Radical-changing (stem-changing) verbs", "html": "<p>Some verbs change their stem vowel in ALL forms EXCEPT <strong>nosotros</strong> and <strong>vosotros</strong>. The endings stay regular.</p>\n            <ul>\n              <li><strong>e → ie</strong>: <span data-say=\"querer\">querer</span> (to want) → <span data-say=\"quiero, quieres, quiere, queremos, queréis, quieren\">quiero, quieres, quiere…</span>; <span data-say=\"preferir\">preferir</span> → <span data-say=\"prefiero\">prefiero</span></li>\n              <li><strong>o → ue</strong>: <span data-say=\"poder\">poder</span> (to be able to) → <span data-say=\"puedo, puedes, puede, podemos, podéis, pueden\">puedo, puedes, puede…</span>; <span data-say=\"dormir\">dormir</span> → <span data-say=\"duermo\">duermo</span></li>\n              <li><strong>e → i</strong>: <span data-say=\"pedir\">pedir</span> (to ask for) → <span data-say=\"pido, pides, pide, pedimos, pedís, piden\">pido, pides, pide…</span> <span class=\"tier-h\">H</span></li>\n            </ul>\n            <p>Example: <span data-say=\"No puedo salir porque quiero dormir.\">No puedo salir porque quiero dormir.</span> — <em>I can’t go out because I want to sleep.</em></p>", "check": {"question": "Why is ‘puedo’ correct and ‘podo’ wrong for ‘I can’?", "options": ["poder is a stem-changer: o → ue in ‘yo’", "podo is simply an alternative spelling of puedo", "podo is used only in the plural form", "puedo is only used with ‘nosotros’"], "answer": 0, "explain": "poder changes o→ue outside nosotros/vosotros: puedo, puedes, puede, podemos, podéis, pueden."}}, {"title": "Reflexive verbs in the present", "html": "<p>Reflexive verbs describe an action you do to yourself and need a pronoun (<strong>me, te, se, nos, os, se</strong>) before the verb.</p>\n            <p><span data-say=\"levantarse\">levantarse</span> (to get up): <span data-say=\"me levanto, te levantas, se levanta, nos levantamos, os levantáis, se levantan\">me levanto, te levantas, se levanta, nos levantamos, os levantáis, se levantan</span>.</p>\n            <p>Other common ones: <span data-say=\"ducharse\">ducharse</span> (to shower), <span data-say=\"vestirse\">vestirse</span> (to get dressed) <span class=\"tier-h\">H</span>, <span data-say=\"acostarse\">acostarse</span> (to go to bed).</p>\n            <p>Example: <span data-say=\"Me levanto a las siete y me ducho enseguida.\">Me levanto a las siete y me ducho enseguida.</span> — <em>I get up at seven and I shower straight away.</em></p>", "check": {"question": "What is missing from ‘Levanto a las siete’?", "options": ["the reflexive pronoun ‘me’ (me levanto)", "the accent on the final letter of the verb", "the linking word ‘que’ placed before the verb", "the article ‘el’"], "answer": 0, "explain": "levantarse is reflexive: you must include me/te/se — ‘me levanto’."}}, {"title": "gustar-type verbs", "html": "<p><span class=\"tier-h\">H</span> Verbs like <strong>gustar</strong> (to like) work backwards — the thing liked is the subject, so the verb agrees with IT, not with the person.</p>\n            <ul>\n              <li>ONE thing liked → <span data-say=\"me gusta\">me gusta</span>: <span data-say=\"Me gusta el fútbol.\">Me gusta el fútbol.</span> (I like football.)</li>\n              <li>MORE THAN ONE → <span data-say=\"me gustan\">me gustan</span>: <span data-say=\"Me gustan los deportes.\">Me gustan los deportes.</span> (I like sports.)</li>\n            </ul>\n            <p>Other verbs behaving the same way: <span data-say=\"interesar\">interesar</span> (to interest), <span data-say=\"encantar\">encantar</span> (to love — Me encanta…), <span data-say=\"doler\">doler</span> (to hurt) <span class=\"tier-h\">H</span>.</p>", "check": {"question": "Why is it ‘Me gustan las matemáticas’ and not ‘Me gusta las matemáticas’?", "options": ["‘las matemáticas’ is plural, so the verb is plural", "gustar is always plural in Spanish regardless of the subject", "‘matemáticas’ is a masculine noun", "it describes a future plan"], "answer": 0, "explain": "gustar agrees with the thing liked; ‘las matemáticas’ is plural → gustan (gustar is not always plural)."}}]}, "terms": {"enabled": true, "pairs": [{"term": "hablo, comes, vive", "definition": "I speak, you eat, he/she lives (-ar/-er/-ir)"}, {"term": "soy / eres / es", "definition": "I am / you are / he-she is (ser, identity)"}, {"term": "estoy / estás / está", "definition": "I am / you are / he-she is (estar, temporary)"}, {"term": "tengo, tienes, tiene", "definition": "I have, you have, he/she has"}, {"term": "voy, vas, va", "definition": "I go, you go, he/she goes"}, {"term": "hago, haces, hace", "definition": "I do/make, you do, he/she does"}, {"term": "tener que + infinitivo", "definition": "to have to…"}, {"term": "ir a + infinitivo", "definition": "to be going to… (near future)"}, {"term": "quiero, prefiero (e→ie)", "definition": "I want, I prefer"}, {"term": "puedo, duermo (o→ue)", "definition": "I can, I sleep"}, {"term": "pido (e→i)", "definition": "I ask for"}, {"term": "me levanto", "definition": "I get up (reflexive)"}, {"term": "me ducho", "definition": "I shower (reflexive)"}, {"term": "me acuesto", "definition": "I go to bed (reflexive)"}, {"term": "me gusta…", "definition": "I like… (one thing)"}, {"term": "me gustan…", "definition": "I like… (more than one thing)"}, {"term": "me interesa / me encanta (H)", "definition": "…interests me / I love… (gustar-type)"}, {"term": "me duele / me duelen (H)", "definition": "…hurts / …hurt (gustar-type)"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"Tengo quince años.\" data-listen></span><br>Listen. What is being said?", "options": ["I am fifteen years old", "I have fifteen brothers", "I am nearly fifteen years old", "My friend is fifteen years old"], "answer": 0, "explain": "‘tengo quince años’ = I am fifteen (tener + años, not ‘to be’). The traps add a false subject or age detail."}, {"question": "<span data-say=\"Me levanto a las siete.\" data-listen></span><br>Listen. What time?", "options": ["seven o’clock", "seven thirty exactly", "quarter past seven", "seventeen o’clock"], "answer": 0, "explain": "‘a las siete’ = at seven. Every distractor is longer and invents a time detail that was not said."}, {"question": "<span data-say=\"No puedo salir porque tengo que estudiar.\" data-listen></span><br>Listen. Why can’t they go out?", "options": ["because they have to study", "because they don’t want to study at all", "because they are already studying now", "because their parents will not allow it"], "answer": 0, "explain": "‘tengo que estudiar’ = I have to study. Every distractor is longer and changes the reason given."}, {"question": "How do you say ‘I like sports’ (plural)?", "options": ["Me gustan los deportes", "Me gusta los deportes", "Me gusto los deportes", "Yo gusto mucho los deportes"], "answer": 0, "explain": "gustar agrees with the plural subject ‘los deportes’ → gustan. B fails to agree; C/D conjugate gustar as if it were a normal verb."}, {"question": "Careful — which sentence means ‘I am bored’ (right now)?", "options": ["Estoy aburrido", "Soy aburrido", "Tengo aburrido", "Hago aburrido"], "answer": 0, "explain": "A temporary feeling takes estar: estoy aburrido. ‘Soy aburrido’ would mean ‘I am a boring person’ — a classic trap."}, {"question": "How do you say ‘I can’t sleep’?", "options": ["No puedo dormir", "No podo dormir", "No puedes dormir", "No puede dormir mucho"], "answer": 0, "explain": "poder is a stem-changer: puedo. ‘podo’ ignores the o→ue change; C/D use the wrong person."}, {"question": "Which sentence correctly uses a reflexive verb?", "options": ["Me ducho antes de desayunar", "Ducho antes de desayunar cada mañana", "Yo ducho muy temprano siempre", "Se ducho antes de desayunar"], "answer": 0, "explain": "ducharse is reflexive: (yo) me ducho. Dropping ‘me’ or using the wrong pronoun is wrong."}, {"question": "Complete: ‘Voy a ___ mis deberes esta tarde.’", "options": ["hacer", "hago", "haciendo", "hecho"], "answer": 0, "explain": "‘ir a’ takes an infinitive → hacer. The others are conjugated / non-finite forms."}, {"question": "‘Prefiero el fútbol al baloncesto’ — which stem-change is this?", "options": ["e → ie (preferir → prefiero)", "o → ue (preferir → prefuero)", "e → i (preferir → prifiero)", "no change at all"], "answer": 0, "explain": "preferir is an e→ie stem-changer: prefiero, prefieres, prefiere…"}, {"question": "‘¿Dónde está el gimnasio?’ uses ‘está’ because…", "options": ["it asks about location, which always takes estar", "location questions always use ‘ser’ instead of estar", "‘gimnasio’ is a feminine noun", "it is describing a permanent personality trait"], "answer": 0, "explain": "Location questions always use estar: ¿dónde está…?"}]}, "fib": {"enabled": true, "questions": [{"text": "Me [levanto] a las siete. <span data-say=\"Me levanto a las siete.\" data-listen>Me levanto a las siete.</span>"}, {"text": "No [puedo] salir porque tengo que estudiar. <span data-say=\"No puedo salir porque tengo que estudiar.\" data-listen>No puedo salir porque tengo que estudiar.</span>"}, {"text": "Voy a hacer mis [deberes]. <span data-say=\"Voy a hacer mis deberes esta tarde.\" data-listen>Voy a hacer mis deberes esta tarde.</span>"}, {"text": "[Estoy] cansado porque no duermo bien. (temporary state — estar)"}, {"text": "Me [gusta] el fútbol. (I like — singular subject)"}, {"text": "[Tengo] quince años. (age — with tener)"}, {"text": "Mi hermano [duerme] mucho por las noches. (o→ue stem-change: dormir)"}]}, "tf": {"enabled": true, "questions": [{"statement": "‘gustar’ works backwards — the verb agrees with the thing liked, not the person.", "answer": true, "explain": "Me gusta el fútbol / me gustan los deportes — the verb matches the thing liked."}, {"statement": "‘Soy aburrido’ and ‘Estoy aburrido’ mean exactly the same thing.", "answer": false, "explain": "Soy aburrido = I am a boring person (ser, permanent). Estoy aburrido = I am bored right now (estar, temporary)."}, {"statement": "‘tener que’ is followed by an infinitive.", "answer": true, "explain": "tengo que estudiar / trabajar / dormir — always an infinitive."}, {"statement": "‘poder’ changes e → ie in the present tense.", "answer": false, "explain": "poder changes o → ue: puedo, puedes, puede, podemos, podéis, pueden."}, {"statement": "For location (where something is) you use ‘estar’, not ‘ser’.", "answer": true, "explain": "está en Madrid, not es en Madrid."}, {"statement": "‘nosotros’ and ‘vosotros’ keep the regular stem in radical-changing verbs.", "answer": true, "explain": "queremos, podemos, pedimos — the nosotros/vosotros forms do NOT change the stem."}, {"statement": "‘ducharse’ is a reflexive verb, so ‘I shower’ is ‘me ducho’.", "answer": true, "explain": "Reflexive: me ducho, te duchas, se ducha."}, {"statement": "‘voy a’ + infinitive describes something you did in the past.", "answer": false, "explain": "ir a + infinitive = near future (going to…), not the past."}]}, "misc": {"enabled": true, "items": [{"myth": "Me gusta los deportes.", "truth": "Me gustan los deportes.", "check": {"question": "Why is ‘Me gusta los deportes’ wrong?", "options": ["‘los deportes’ is plural, so it must be ‘gustan’", "you must always put the verb ‘estar’ in front of it too", "‘deportes’ needs a written accent", "the pronoun should be ‘te’, not ‘me’"], "answer": 0, "explain": "gustar agrees with the thing liked; plural subject → gustan."}}, {"myth": "Soy aburrido. (= I am bored right now)", "truth": "Estoy aburrido. (= I am bored right now)", "check": {"question": "Which verb correctly says ‘I am bored right now’?", "options": ["Estoy aburrido — a temporary feeling uses estar", "Soy aburrido — feelings always use ser instead of estar", "Tengo aburrido — feelings use tener", "Hago aburrido — feelings use hacer"], "answer": 0, "explain": "Temporary feelings and moods take estar, not ser. ‘Soy aburrido’ describes a permanent personality trait instead."}}, {"myth": "Yo podo dormir mucho.", "truth": "Yo puedo dormir mucho.", "check": {"question": "Why is ‘podo’ wrong here?", "options": ["poder is a stem-changer: o → ue in ‘yo’ → puedo", "podo is simply an alternative spelling of puedo", "podo is only used in the plural form", "puedo is only used with ‘nosotros’"], "answer": 0, "explain": "poder changes o→ue outside nosotros/vosotros: puedo, puedes, puede, podemos, podéis, pueden."}}, {"myth": "Levanto a las siete.", "truth": "Me levanto a las siete.", "check": {"question": "What is missing in ‘Levanto a las siete’?", "options": ["the reflexive pronoun ‘me’ (me levanto)", "an accent on the final letter of the verb form", "the linking word ‘a’", "the article ‘el’"], "answer": 0, "explain": "levantarse is reflexive: you need me/te/se — ‘me levanto’."}}, {"myth": "Tengo que estudiar mañana obligatoriamente sin ninguna excusa posible.", "truth": "Tengo que estudiar mañana.", "check": {"question": "What is the actual problem with the ‘wrong’ sentence here?", "options": ["nothing grammatically — it is just unnecessarily long for the exam context", "‘tengo que’ is here followed by a fully conjugated verb instead of an infinitive", "‘estudiar’ should be ‘estudio’", "‘mañana’ should come before ‘tengo’"], "answer": 0, "explain": "The grammar (tengo que + infinitive) is correct; padding a sentence with unnecessary words does not add marks in a translation or writing task."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 1 — Dictation (listening)", "html": "Present-tense verb endings are easy to mishear. Listen for whether it is ‘gusta’ (one thing) or ‘gustan’ (more than one), and whether a stem-changer is used: ‘puedo’ not ‘podo’, ‘quiero’ not ‘quero’.", "check": {"question": "You hear ‘…gustan…’. What does that tell you?", "options": ["more than one thing is liked", "only one single thing is liked", "nothing is liked at all", "it is a future plan"], "answer": 0, "explain": "The -n ending of ‘gustan’ signals a plural subject (los deportes, las matemáticas…)."}}, {"title": "Paper 3 — Reading and translation into English", "html": "Watch ser vs estar: ‘es aburrido’ (he is boring) is very different from ‘está aburrido’ (he is bored). Keep ‘tengo quince años’ natural: ‘I am fifteen’, not ‘I have fifteen years’.", "check": {"question": "‘Está en el gimnasio y tiene que entrenar’ =", "options": ["He/she is at the gym and has to train", "He/she is a gym-like person and wants to train", "He/she was at the gym yesterday and trained", "He/she likes the gym but never trains"], "answer": 0, "explain": "estar en = to be (located) in; tener que = to have to."}}, {"title": "Paper 4 — Writing & translation into Spanish", "html": "Combine a routine, a preference and a plan: ‘Me levanto a las siete, prefiero el fútbol y voy a hacer mis deberes.’ At Higher, add gustar-type and a stem-changer to show range: ‘me interesan…’, ‘pido…’.", "check": {"question": "Which answer reaches the top band?", "options": ["Me levanto a las siete, prefiero el fútbol y voy a hacer mis deberes", "Me levanto y me levanto y me levanto todos los días sin parar nunca jamás", "Estoy bien", "Tengo deberes"], "answer": 0, "explain": "It links a routine action, a stem-changing preference and a near-future plan — range and accuracy, not just repeating one verb."}}]}, "exam": {"enabled": true, "questions": [{"question": "Read what Carlos says. Answer <strong>in English</strong>.<br>(a) What does Carlos do straight after getting up? (1)<br>(b) Why does he go to school by bus? (1)<br>(c) Why does he have to study a lot? (1)<br>(d) Why can’t he go out much at weekends? (1)", "marks": 4, "hint": "Find the routine action after ‘y’, the reason after ‘porque’ (twice), and the weekend reason after ‘pero’.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 4 marks (AO3 Reading)</h5><ul>\n                <li><strong>(a)</strong> he showers (straight away) <em>(1)</em>.</li>\n                <li><strong>(b)</strong> (because) school is quite far from his house <em>(1)</em>.</li>\n                <li><strong>(c)</strong> (because) sciences are difficult <em>(1)</em>.</li>\n                <li><strong>(d)</strong> (because) he has to help at home <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Answers in English; do not penalise spelling if the meaning is clear.</li>\n            </ul></div>"}, {"question": "Translate these sentences <strong>into Spanish</strong>.<br>(a) I get up at seven. <br>(b) I have to study a lot. <br>(c) I like sports, but I prefer football.", "marks": 5, "hint": "‘I get up’ = reflexive (Me levanto…). ‘I have to’ = tener que + infinitive. ‘I like… I prefer…’ = Me gusta(n)… / prefiero…", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (AO4 Writing: translation)</h5><ul>\n                <li><strong>(a)</strong> Me levanto a las siete. <em>(1)</em></li>\n                <li><strong>(b)</strong> Tengo que estudiar mucho. <em>(1)</em></li>\n                <li><strong>(c)</strong> Me gustan los deportes <em>(1)</em>, pero <em>(1)</em> prefiero el fútbol <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent errors. ‘Me gustan los deportes’ must use the plural ‘gustan’.</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', 'g-4-talking-about-the-past', 'G.4 Talking About the Past', '{"learn": {"enabled": true, "items": [{"title": "How do I form the preterite of regular -AR verbs?", "html": "<p>The preterite (<span data-say=\"el pretérito\">el pretérito</span>) describes a <strong>completed action in the past</strong> — something that happened and finished at a specific point in time.</p>\n            <p>Regular <strong>-AR</strong> verbs like <span data-say=\"hablar\">hablar</span> (to speak) follow this pattern:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td>yo</td><td><span data-say=\"hablé\">hablé</span></td><td>nosotros/as</td><td>hablamos</td></tr>\n              <tr><td>tú</td><td>hablaste</td><td>vosotros/as</td><td>hablasteis</td></tr>\n              <tr><td>él/ella/usted</td><td><span data-say=\"habló\">habló</span></td><td>ellos/ellas/ustedes</td><td>hablaron</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Ayer hablé con mi profesora por teléfono.\">Ayer hablé con mi profesora por teléfono.</span> — <em>Yesterday I spoke to my teacher on the phone.</em> Note the accent on <strong>hablé</strong> and <strong>habló</strong> — without it, the meaning changes!</p>", "check": {"question": "What is the ''yo'' (I) form of ''hablar'' in the preterite?", "options": ["hablé", "hablaba", "hablo", "he hablado"], "answer": 0, "explain": "The ''yo'' preterite ending for -AR verbs is -é (with an accent): hablé. ''hablaba'' is imperfect, ''hablo'' is present, ''he hablado'' is perfect."}}, {"title": "How do I form the preterite of regular -ER/-IR verbs?", "html": "<p><strong>-ER</strong> and <strong>-IR</strong> verbs share the SAME preterite endings. Compare <span data-say=\"comer\">comer</span> (to eat) and <span data-say=\"vivir\">vivir</span> (to live):</p>\n            <table class=\"vocab-tbl\">\n              <tr><td>yo</td><td><span data-say=\"comí\">comí</span></td><td><span data-say=\"viví\">viví</span></td></tr>\n              <tr><td>tú</td><td>comiste</td><td>viviste</td></tr>\n              <tr><td>él/ella/usted</td><td><span data-say=\"comió\">comió</span></td><td><span data-say=\"vivió\">vivió</span></td></tr>\n              <tr><td>nosotros/as</td><td>comimos</td><td>vivimos</td></tr>\n              <tr><td>ellos/ellas/ustedes</td><td>comieron</td><td>vivieron</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Anoche comimos pasta en el restaurante.\">Anoche comimos pasta en el restaurante.</span> — <em>Last night we ate pasta at the restaurant.</em></p>", "check": {"question": "Which ending do -ER and -IR verbs share for ''él/ella'' in the preterite?", "options": ["-ió (comió, vivió)", "-aba, used for every single verb", "-ía, with no exceptions at all", "-ando, added to the stem"], "answer": 0, "explain": "-ER/-IR verbs share preterite endings: comió, vivió both end in -ió. -aba/-ía are imperfect endings; -ando builds the gerund."}}, {"title": "What are the key irregular preterites?", "html": "<p>Some very common verbs are IRREGULAR in the preterite — they use different stems and take NO written accent.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"ser\">ser</span> / <span data-say=\"ir\">ir</span></td><td><span data-say=\"fui\">fui</span>, fuiste, <span data-say=\"fue\">fue</span>, fuimos, fuisteis, fueron</td></tr>\n              <tr><td><span data-say=\"hacer\">hacer</span></td><td><span data-say=\"hice\">hice</span>, hiciste, hizo, hicimos</td></tr>\n              <tr><td><span data-say=\"tener\">tener</span></td><td><span data-say=\"tuve\">tuve</span>, tuviste, tuvo, tuvimos</td></tr>\n              <tr><td><span data-say=\"estar\">estar</span></td><td><span data-say=\"estuve\">estuve</span>, estuviste, estuvo, estuvimos</td></tr>\n            </table>\n            <p><strong>ser and ir share IDENTICAL forms</strong> in the preterite — only context tells you which one is meant: <span data-say=\"Fui al cine.\">Fui al cine.</span> (I went) vs <span data-say=\"Fue muy interesante.\">Fue muy interesante.</span> (It was).</p>", "check": {"question": "''fui'' can mean ''I went'' OR ''I was'', because…", "options": ["ser and ir share identical preterite forms", "the word changes its spelling with meaning", "''fui'' only ever means ''I was'' in context", "''fui'' is a completely regular -IR verb"], "answer": 0, "explain": "ser (to be) and ir (to go) have exactly the same irregular preterite forms — fui, fuiste, fue… Context tells you which verb is meant."}}, {"title": "How do I form the imperfect tense?", "html": "<p>The imperfect (<span data-say=\"el imperfecto\">el imperfecto</span>) describes what you <strong>used to do</strong>, <strong>was doing</strong>, or how things <strong>were</strong> — no fixed end point.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td>yo</td><td><span data-say=\"hablaba\">hablaba</span></td><td><span data-say=\"comía\">comía</span></td><td><span data-say=\"vivía\">vivía</span></td></tr>\n              <tr><td>tú</td><td>hablabas</td><td>comías</td><td>vivías</td></tr>\n              <tr><td>él/ella</td><td>hablaba</td><td>comía</td><td>vivía</td></tr>\n              <tr><td>nosotros/as</td><td><span data-say=\"hablábamos\">hablábamos</span></td><td>comíamos</td><td>vivíamos</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Cuando era niño, jugaba al fútbol todos los días.\">Cuando era niño, jugaba al fútbol todos los días.</span> — <em>When I was a child, I used to play football every day.</em></p>", "check": {"question": "What does the imperfect tense express?", "options": ["a habitual or ongoing past action (''used to'')", "a single action completed at one exact moment", "an action that is going to happen soon", "an instruction telling someone what to do"], "answer": 0, "explain": "The imperfect describes habits, ongoing states or descriptions in the past — ''used to'' / ''was -ing''. A single finished action needs the preterite instead."}}, {"title": "Preterite or imperfect — which do I choose?", "html": "<p>Ask: is it a SINGLE completed event, or a HABIT / DESCRIPTION / ongoing background action?</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><strong>PRETERITE</strong> — one-off, finished</td><td><span data-say=\"ayer\">ayer</span>, <span data-say=\"el año pasado\">el año pasado</span>, <span data-say=\"el fin de semana pasado\">el fin de semana pasado</span>, <span data-say=\"anoche\">anoche</span></td></tr>\n              <tr><td><strong>IMPERFECT</strong> — habit, description, ongoing</td><td><span data-say=\"normalmente\">normalmente</span>, <span data-say=\"todos los días\">todos los días</span>, <span data-say=\"de pequeño\">de pequeño</span>, <span data-say=\"mientras\">mientras</span></td></tr>\n            </table>\n            <p>The two often combine: <span data-say=\"Mientras yo cocinaba, mi hermano llegó a casa.\">Mientras yo cocinaba, mi hermano llegó a casa.</span> — <em>While I was cooking (ongoing, imperfect), my brother arrived (interrupting event, preterite).</em></p>\n            <p>Irregular imperfects: <span data-say=\"ser\">ser</span> → <span data-say=\"era\">era</span>; <span data-say=\"ir\">ir</span> → <span data-say=\"iba\">iba</span>; <span data-say=\"ver\">ver</span> → <span data-say=\"veía\">veía</span>.</p>", "check": {"question": "In ''Mientras cocinaba, mi hermano llegó'', why is ''llegó'' in the preterite?", "options": ["it is the single event that interrupted the ongoing action", "every verb that comes after the word ''mientras'' must always be preterite too", "''llegó'' describes a repeated daily habit", "the whole sentence is describing the future"], "answer": 0, "explain": "''cocinaba'' (imperfect) sets the ongoing background; ''llegó'' (preterite) is the single completed event that broke in."}}, {"title": "Higher: the perfect tense", "html": "<p><span class=\"tier-h\">H</span> The perfect tense (<span data-say=\"el pretérito perfecto\">el pretérito perfecto</span>) links the past to NOW — recent past or experience, with no definite time marker like ''ayer''.</p>\n            <p>Form: <strong>haber</strong> + past participle.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td>he</td><td><span data-say=\"he hablado\">he hablado</span></td><td>hemos</td><td>hemos comido</td></tr>\n              <tr><td>has</td><td>has vivido</td><td>habéis</td><td>habéis hecho</td></tr>\n              <tr><td>ha</td><td><span data-say=\"ha comido\">ha comido</span></td><td>han</td><td>han ido</td></tr>\n            </table>\n            <p>Irregular participles: <span data-say=\"hecho\">hecho</span> (hacer), visto (ver), escrito (escribir).</p>\n            <p>Example: <span data-say=\"Nunca he comido paella.\">Nunca he comido paella.</span> — <em>I have never eaten paella.</em></p>", "check": {"question": "How is the perfect tense formed?", "options": ["haber (he/has/ha…) + past participle", "the preterite stem plus the ending -aba", "estar + a gerund ending in -ando/-iendo", "the plain infinitive with no changes"], "answer": 0, "explain": "Perfect = present of haber + past participle: he comido, ha hecho. estar+gerund is the continuous; -aba builds the imperfect."}}]}, "terms": {"enabled": true, "pairs": [{"term": "hablé", "definition": "I spoke"}, {"term": "hablaste", "definition": "you spoke"}, {"term": "habló", "definition": "he/she spoke"}, {"term": "comí", "definition": "I ate"}, {"term": "comió", "definition": "he/she ate"}, {"term": "viví", "definition": "I lived"}, {"term": "fui (ir)", "definition": "I went"}, {"term": "fui (ser)", "definition": "I was"}, {"term": "hice", "definition": "I did / made"}, {"term": "tuve", "definition": "I had"}, {"term": "estuve", "definition": "I was (place/state)"}, {"term": "hablaba", "definition": "I used to speak"}, {"term": "comía", "definition": "I used to eat / was eating"}, {"term": "vivía", "definition": "I used to live"}, {"term": "era", "definition": "I was (description)"}, {"term": "iba", "definition": "I used to go"}, {"term": "veía", "definition": "I used to see / watch"}, {"term": "he comido (H)", "definition": "I have eaten"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"Ayer fui al cine.\" data-listen></span><br>Listen. What happened?", "options": ["I went to the cinema yesterday", "I go to the cinema every single day", "I used to go to the cinema often", "I am going to the cinema later today"], "answer": 0, "explain": "''Ayer fui al cine'' = I went to the cinema yesterday (preterite, one-off past event). The distractors swap it for a habit, present routine or future plan."}, {"question": "<span data-say=\"Cuando era niño, jugaba en el parque todos los días.\" data-listen></span><br>Listen. What is being described?", "options": ["a childhood habit that happened repeatedly", "a single visit made to the park last Tuesday", "a plan to play at the park next weekend", "an instruction telling a child to go and play"], "answer": 0, "explain": "''jugaba… todos los días'' is the imperfect describing a repeated childhood habit. The others turn it into a single event, a future plan or a command."}, {"question": "Complete: \"Ayer, yo ___ (comer) una hamburguesa enorme.\"", "options": ["comí", "comía", "como", "he comido"], "answer": 0, "explain": "''Ayer'' signals a single completed action → preterite: comí. ''comía'' is imperfect, ''como'' present, ''he comido'' perfect (no definite time marker needed there)."}, {"question": "Complete: \"Cuando era pequeña, ___ (vivir) en Madrid.\"", "options": ["vivía", "viví", "vivo", "he vivido"], "answer": 0, "explain": "''Cuando era pequeña'' sets up a description of a past state → imperfect: vivía. ''viví'' is preterite (single event), ''vivo'' present, ''he vivido'' perfect."}, {"question": "Which form means ''I went'' (from ''ir'')?", "options": ["fui", "fue", "iba", "voy"], "answer": 0, "explain": "''fui'' (yo) = I went / I was. ''fue'' is él/ella, ''iba'' is the imperfect (I used to go), ''voy'' is present."}, {"question": "Which sentence correctly says ''I did my homework yesterday''?", "options": ["Hice los deberes ayer", "Hacía los deberes ayer siempre", "Hago los deberes cada día", "He hecho los deberes ayer"], "answer": 0, "explain": "''ayer'' plus a one-off completed action = preterite: Hice los deberes ayer. ''Hacía…siempre'' is imperfect, ''Hago…cada día'' is present, ''He hecho'' is perfect."}, {"question": "Complete: \"De pequeño, normalmente mi madre se ___ (levantarse) a las seis.\"", "options": ["levantaba", "levantó", "levanta", "ha levantado"], "answer": 0, "explain": "''normalmente'' plus a repeated childhood habit = imperfect: se levantaba. ''levantó'' is a single occasion, ''levanta'' present, ''ha levantado'' perfect."}, {"question": "Higher: which sentence correctly uses the perfect tense for ''I have never eaten paella''?", "options": ["Nunca he comido paella", "Nunca comí paella el sábado", "Nunca como paella los domingos", "Nunca comía paella de pequeño"], "answer": 0, "explain": "The perfect (haber + participle) links past experience to now with no definite time marker: Nunca he comido paella. The others add a preterite, present or imperfect time frame."}, {"question": "Complete: \"Mientras yo ___ (cocinar), mi hermano llegó a casa.\"", "options": ["cocinaba", "cociné", "cocino", "he cocinado"], "answer": 0, "explain": "''mientras'' introduces the ongoing background action → imperfect: cocinaba, interrupted by the preterite ''llegó''."}, {"question": "<span data-say=\"El año pasado, viajé a España con mi familia.\" data-listen></span><br>Listen. What is being said?", "options": ["Last year, I travelled to Spain with my family", "Every year, I travel to Spain with my family", "I used to travel to Spain with my family", "Next year, I will travel to Spain with my family"], "answer": 0, "explain": "''El año pasado, viajé'' = Last year, I travelled (preterite, a single trip). The others swap the time frame to present, habitual or future."}]}, "fib": {"enabled": true, "questions": [{"text": "Ayer, yo [hablé] (hablar) con mi profesora sobre el examen. <span data-say=\"Ayer, yo hablé con mi profesora sobre el examen.\" data-listen>Ayer, yo hablé con mi profesora sobre el examen.</span>"}, {"text": "El año pasado, nosotros [fuimos] (ir) de vacaciones a Francia. <span data-say=\"El año pasado, nosotros fuimos de vacaciones a Francia.\" data-listen>El año pasado, nosotros fuimos de vacaciones a Francia.</span>"}, {"text": "De pequeño, yo [vivía] (vivir) en Sevilla con mis abuelos. (imperfect — describes a past state)"}, {"text": "Normalmente, mi madre se [levantaba] (levantarse) a las seis. (imperfect — a repeated habit)"}, {"text": "Mientras yo cocinaba, mi hermano [llegó] (llegar) a casa. (the interrupting single event — preterite)"}, {"text": "Escucha y completa: Ayer [estuve] en el parque toda la tarde. <span data-say=\"Ayer estuve en el parque toda la tarde.\" data-listen></span>"}, {"text": "Higher: Nunca [he comido] (comer) paella antes. (perfect tense — haber + participle)"}]}, "tf": {"enabled": true, "questions": [{"statement": "The preterite describes a completed action in the past.", "answer": true, "explain": "hablé, comí, fui — all describe an action that finished at a specific point in time."}, {"statement": "''fui'' can only ever mean ''I was'', never ''I went''.", "answer": false, "explain": "ser and ir share identical preterite forms — ''fui'' can mean ''I went'' (ir) or ''I was'' (ser); context decides."}, {"statement": "-ER and -IR verbs share the same preterite endings.", "answer": true, "explain": "comí/comió and viví/vivió use identical endings once you strip the stem."}, {"statement": "The imperfect is used for a single, completed one-off event.", "answer": false, "explain": "The imperfect describes habits, ongoing states or descriptions; a single finished event needs the preterite."}, {"statement": "''era'', ''iba'' and ''veía'' are the only three irregular imperfect verbs.", "answer": true, "explain": "ser (era), ir (iba) and ver (veía) are the sole imperfect irregulars — every other verb is regular."}, {"statement": "''ayer'' is a time marker usually paired with the preterite.", "answer": true, "explain": "ayer, el año pasado, anoche all point to a finished one-off action → preterite."}, {"statement": "''normalmente'' usually signals the imperfect tense.", "answer": true, "explain": "normalmente, todos los días, de pequeño all point to a habit → imperfect."}, {"statement": "The perfect tense is formed with estar plus a gerund.", "answer": false, "explain": "The perfect is haber + past participle (he comido); estar + gerund (-ando/-iendo) builds the continuous instead."}]}, "misc": {"enabled": true, "items": [{"myth": "Ayer jugaba al fútbol con mis amigos.", "truth": "Ayer jugué al fútbol con mis amigos.", "check": {"question": "Why is ''Ayer jugaba…'' wrong here?", "options": ["''ayer'' signals a single finished event, so it needs the preterite", "''jugaba'' is spelt correctly but carries an accent mark it should not have", "''jugar'' cannot be used with ''ayer'' at all", "the sentence should be in the future tense instead"], "answer": 0, "explain": "''ayer'' = a one-off, completed action → preterite (jugué), not the imperfect (jugaba), which suits habits."}}, {"myth": "Cuando era niño, jugué en el parque todos los días.", "truth": "Cuando era niño, jugaba en el parque todos los días.", "check": {"question": "Why is ''jugué…todos los días'' wrong here?", "options": ["''todos los días'' describes a repeated habit, needing the imperfect", "''todos los días'' can only ever be used together with the present tense, never the past", "''todos los días'' can only pair with the perfect tense", "the sentence needs a reflexive pronoun instead"], "answer": 0, "explain": "''todos los días'' signals a repeated childhood habit → imperfect (jugaba), not the preterite (jugué), which suits one-off events."}}, {"myth": "Yo hací los deberes ayer.", "truth": "Yo hice los deberes ayer.", "check": {"question": "What is wrong with ''hací''?", "options": ["hacer''s irregular preterite stem is ''hic-'', giving ''hice''", "the ending ''-í'' used here is actually the completely correct and standard ending for hacer", "''hací'' is the correct imperfect form of hacer", "the accent mark has simply been left off ''hací''"], "answer": 0, "explain": "hacer is irregular in the preterite: hice, hiciste, hizo… There is no form ''hací'' — the stem changes to hic-."}}, {"myth": "Nunca comí paella.", "truth": "Nunca he comido paella.", "check": {"question": "Why does ''I have never eaten paella'' need the perfect, not the preterite?", "options": ["there is no definite past time marker, so the perfect links it to now", "''nunca'' can only ever be correctly followed by the imperfect tense in Spanish grammar", "''comí'' is actually spelt incorrectly in that sentence", "the preterite cannot be used with any negative word"], "answer": 0, "explain": "With no time marker like ''ayer'', an experience ''up to now'' takes the perfect: Nunca he comido paella."}}, {"myth": "Mientras cociné, mi hermano llegaba a casa.", "truth": "Mientras cocinaba, mi hermano llegó a casa.", "check": {"question": "Which verb should be the ongoing background action, and which the interrupting event?", "options": ["cocinaba is the ongoing background; llegó is the single interrupting event", "cociné is the ongoing background action here, while llegaba is meant to be the interrupting event", "both verbs must be in the preterite in this sentence", "both verbs must be in the imperfect in this sentence"], "answer": 0, "explain": "The wrong version swaps the tenses round: the ongoing action (cooking) needs the imperfect, and the single event that interrupts it (arriving) needs the preterite."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 1 — Listening for tense endings", "html": "Preterite and imperfect verbs often differ by a single sound. Listen for the stressed final vowel: -é/-ó (preterite: hablé, habló) vs -aba/-ía (imperfect: hablaba, comía). That one sound changes whether it was a finished event or a habit.", "check": {"question": "You hear the ending ''-aba'' on a verb. What does that most likely signal?", "options": ["an imperfect form describing a habit or description", "a preterite form that is describing one single finished action in the past", "a command telling someone to do something", "the perfect tense describing an experience"], "answer": 0, "explain": "-aba is the -AR imperfect ending (hablaba, jugaba) — habits, descriptions, ongoing past actions."}}, {"title": "Paper 3 — Reading: spot the accent", "html": "A missing or misread accent changes the tense entirely: ''hablo'' (I speak, present) vs ''habló'' (he/she spoke, preterite); ''hable'' (subjunctive) vs ''hablé'' (I spoke, preterite). Always check who is doing the action before you translate.", "check": {"question": "What is the key difference between ''hablo'' and ''habló'' in a reading text?", "options": ["''hablo'' is present tense (I), ''habló'' is preterite (he/she)", "they are simply two different but interchangeable spellings of the exact same word", "''habló'' is always the correct spelling to use", "there is no real difference in meaning between them"], "answer": 0, "explain": "The accent moves the stress and changes both tense and subject: hablo = I speak (now); habló = he/she spoke (finished)."}}, {"title": "Paper 4 — Writing: mix your past tenses", "html": "Top-band answers combine tenses naturally: a preterite for a single trip, an imperfect for a childhood habit, and (Higher) a perfect for an experience with no date. Example: ''El año pasado fui a España. Cuando era niño, iba todos los veranos. Nunca he visitado Barcelona.''", "check": {"question": "Which answer shows the widest and most accurate range of past tenses?", "options": ["El año pasado fui a España; de niño iba cada verano; nunca he visitado Barcelona", "Fui a España, fui a Francia, fui a Italia y también fui a Portugal el año pasado otra vez", "Voy a España todos los años porque me gusta mucho viajar", "España es un país muy bonito con playas y montañas"], "answer": 0, "explain": "It combines preterite (fui), imperfect (iba) and perfect (he visitado) accurately — range, not just length or repetition."}}]}, "exam": {"enabled": true, "questions": [{"question": "Complete each sentence with the correct form of the verb in brackets (preterite or imperfect).<br>(a) Ayer, yo ___ (ir) al cine con mi hermano. (1)<br>(b) De pequeño, mi abuelo ___ (vivir) en un pueblo pequeño. (1)<br>(c) El año pasado, nosotros ___ (hacer) un viaje a Italia. (1)<br>(d) Mientras mi madre ___ (cocinar), yo puse la mesa. (1)<br>(e) Normalmente, los sábados yo ___ (levantarse) tarde. (1)", "marks": 5, "hint": "Look for the time clue in each sentence: ''ayer''/''el año pasado'' = a single finished event (preterite); ''de pequeño''/''mientras''/''normalmente'' = a habit or ongoing background action (imperfect).", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (AO2 Grammar)</h5><ul>\n                <li><strong>(a)</strong> fui <em>(1)</em> — ''ayer'' = single event → preterite.</li>\n                <li><strong>(b)</strong> vivía <em>(1)</em> — ''de pequeño'' = past description → imperfect.</li>\n                <li><strong>(c)</strong> hicimos <em>(1)</em> — ''el año pasado'' = single event → preterite.</li>\n                <li><strong>(d)</strong> cocinaba <em>(1)</em> — ongoing background action interrupted by ''puse'' → imperfect.</li>\n                <li><strong>(e)</strong> me levantaba <em>(1)</em> — ''normalmente'' = repeated habit → imperfect.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>One mark per correctly-conjugated verb; accept minor accent slips if the tense is clearly right.</li>\n            </ul></div>"}, {"question": "Translate these sentences <strong>into Spanish</strong>.<br>(a) Last year I travelled to Mexico. <br>(b) When I was young, I used to go to the beach every summer. <br>(c) I have never visited Peru.", "marks": 6, "hint": "''Last year'' + a single trip = preterite (viajé). ''Used to go every summer'' = a repeated habit = imperfect (iba). ''I have never visited'' with no exact date = the perfect (he visitado).", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 6 marks (AO4 Writing: translation)</h5><ul>\n                <li><strong>(a)</strong> El año pasado <em>(1)</em> viajé a México <em>(1)</em>.</li>\n                <li><strong>(b)</strong> Cuando era joven/niño, iba a la playa <em>(1)</em> todos los veranos <em>(1)</em>.</li>\n                <li><strong>(c)</strong> Nunca <em>(1)</em> he visitado Perú <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent errors. The tense choice (preterite/imperfect/perfect) must be correct for the mark.</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', 'g-5-future-conditional-and-more-tenses', 'G.5 Future, Conditional and More Tenses', '{"learn": {"enabled": true, "items": [{"title": "How do I talk about near-future plans? (ir a + infinitivo)", "html": "<p>The easiest way to talk about the future is <strong>ir a + infinitivo</strong> — literally “to go to do something”. Conjugate <span data-say=\"ir\">ir</span> and add an infinitive.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"voy a\">voy a</span></td><td>I am going to</td><td><span data-say=\"vamos a\">vamos a</span></td><td>we are going to</td></tr>\n              <tr><td><span data-say=\"vas a\">vas a</span></td><td>you are going to</td><td><span data-say=\"vais a\">vais a</span></td><td>you all are going to</td></tr>\n              <tr><td><span data-say=\"va a\">va a</span></td><td>he/she is going to</td><td><span data-say=\"van a\">van a</span></td><td>they are going to</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Voy a estudiar en la universidad.\">Voy a estudiar en la universidad.</span> — <em>I am going to study at university.</em> Never drop the little word <strong>a</strong> — <span data-say=\"voy estudiar\">voy estudiar</span> is missing it and is wrong.</p>", "check": {"question": "What is wrong with ‘Voy estudiar mañana’?", "options": ["It is missing ‘a’ between voy and the infinitive", "It should not use the verb ‘ir’ at all here", "The infinitive ‘estudiar’ should be conjugated instead", "‘mañana’ must come before ‘voy’, not after it"], "answer": 0, "explain": "ir a + infinitive always needs ‘a’ linking the conjugated ir and the infinitive: voy a estudiar."}}, {"title": "How do I form the simple future for regular verbs?", "html": "<p>For regular verbs, add these endings to the <strong>whole infinitive</strong> — don’t remove -ar/-er/-ir first: <strong>-é, -ás, -á, -emos, -éis, -án</strong>. The same endings work for -ar, -er and -ir verbs.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"hablaré\">hablaré</span></td><td>I will speak</td><td><span data-say=\"hablaremos\">hablaremos</span></td><td>we will speak</td></tr>\n              <tr><td><span data-say=\"comerás\">comerás</span></td><td>you will eat</td><td><span data-say=\"comeréis\">comeréis</span></td><td>you all will eat</td></tr>\n              <tr><td><span data-say=\"vivirá\">vivirá</span></td><td>he/she will live</td><td><span data-say=\"vivirán\">vivirán</span></td><td>they will live</td></tr>\n            </table>\n            <p>Example: <span data-say=\"El año que viene, viviré en Madrid y estudiaré español.\">El año que viene, viviré en Madrid y estudiaré español.</span> — <em>Next year, I will live in Madrid and study Spanish.</em> Every future ending except <strong>-emos</strong> carries a written accent.</p>", "check": {"question": "Complete: ‘Mañana, tú ___ con el director.’ (you will speak)", "options": ["hablarás", "hablaras", "hablas", "hablarías"], "answer": 0, "explain": "hablarás is the future tú form — note the accented á. hablaras drops the accent, hablas is present tense, and hablarías is the CONDITIONAL, not future."}}, {"title": "Which verbs have an irregular stem in the future?", "html": "<p>A group of common verbs use a shortened or changed stem before the <strong>same endings</strong> (-é, -ás, -á, -emos, -éis, -án). Learn these:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"tendré\">tendré</span></td><td>I will have (tener)</td><td><span data-say=\"haré\">haré</span></td><td>I will do/make (hacer)</td></tr>\n              <tr><td><span data-say=\"podré\">podré</span></td><td>I will be able to (poder)</td><td><span data-say=\"saldré\">saldré</span></td><td>I will leave (salir)</td></tr>\n              <tr><td><span data-say=\"vendré\">vendré</span></td><td>I will come (venir)</td><td><span data-say=\"diré\">diré</span></td><td>I will say (decir)</td></tr>\n              <tr><td><span data-say=\"querré\">querré</span></td><td>I will want (querer)</td><td><span data-say=\"pondré\">pondré</span></td><td>I will put (poner)</td></tr>\n            </table>\n            <p>Example: <span data-say=\"El sábado, tendré que estudiar pero después saldré con mis amigos.\">El sábado, tendré que estudiar pero después saldré con mis amigos.</span> — <em>On Saturday I will have to study but afterwards I will go out with my friends.</em> Never write “tenerá” — the stem changes to <strong>tendr-</strong> before any future ending.</p>", "check": {"question": "Complete: ‘El sábado, ella ___ que estudiar.’ (she will have to)", "options": ["tendrá", "tenerá", "tiene", "tendría"], "answer": 0, "explain": "tener has the irregular future stem tendr-. ‘tenerá’ wrongly keeps the full infinitive stem, ‘tiene’ is present tense, and ‘tendría’ is the conditional, not future."}}, {"title": "How do I form the conditional? (would…)", "html": "<p>The conditional uses the <strong>same stem</strong> as the future (regular = whole infinitive; irregular = the same shortened stem), plus a different set of endings: <strong>-ía, -ías, -ía, -íamos, -íais, -ían</strong>.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"hablaría\">hablaría</span></td><td>I would speak</td><td><span data-say=\"viviríamos\">viviríamos</span></td><td>we would live</td></tr>\n              <tr><td><span data-say=\"tendría\">tendría</span></td><td>I would have</td><td><span data-say=\"haría\">haría</span></td><td>I would do/make</td></tr>\n              <tr><td><span data-say=\"podría\">podría</span></td><td>I would be able to</td><td><span data-say=\"saldrías\">saldrías</span></td><td>you would leave</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Con más dinero, viajaría por el mundo y compraría una casa grande.\">Con más dinero, viajaría por el mundo y compraría una casa grande.</span> — <em>With more money, I would travel the world and buy a big house.</em> Every conditional ending carries a written accent.</p>", "check": {"question": "Complete: ‘Con más tiempo, (yo) ___ más deporte.’ (I would do)", "options": ["haría", "haré", "hago", "harían"], "answer": 0, "explain": "haría is the conditional (would). haré is future (will), hago is present, and harían is conditional but for ‘ellos’ (they), not ‘yo’."}}, {"title": "How do I politely say what I would like? (me gustaría)", "html": "<p><span data-say=\"me gustaría\">me gustaría</span> (I would like) is one of the most useful exam phrases. It is the conditional of <strong>gustar</strong>, so it behaves just like <em>me gusta</em> and is followed by an infinitive.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"me gustaría\">me gustaría</span></td><td>I would like</td><td><span data-say=\"te gustaría\">te gustaría</span></td><td>you would like</td></tr>\n              <tr><td><span data-say=\"le gustaría\">le gustaría</span></td><td>he/she would like</td><td><span data-say=\"nos gustaría\">nos gustaría</span></td><td>we would like</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Me gustaría estudiar en el extranjero después del instituto.\">Me gustaría estudiar en el extranjero después del instituto.</span> — <em>I would like to study abroad after school.</em> Like <em>me gusta</em>, it does not agree with what follows — it stays as ‘gustaría’, never ‘gustarían’, when followed by an infinitive.</p>", "check": {"question": "What must follow ‘me gustaría’ in a sentence like ‘me gustaría estudiar’?", "options": ["an infinitive, exactly like after me gusta", "a verb conjugated to agree with ‘yo’, like hago", "the word ‘que’ followed by a new subject", "a plural noun with no verb at all"], "answer": 0, "explain": "me gustaría + infinitive = I would like to do something, exactly like me gusta + infinitive (me gusta estudiar)."}}, {"title": "Higher: the perfect, pluperfect and an intro to the subjunctive", "html": "<p><span class=\"tier-h\">H</span> The <strong>perfect tense</strong> (have/has done) = present of <em>haber</em> + past participle: <span data-say=\"he estudiado\">he estudiado</span> (I have studied), <span data-say=\"ha comido\">ha comido</span> (he/she has eaten).</p>\n            <p>The <strong>pluperfect</strong> (had done) = imperfect of <em>haber</em> + past participle: <span data-say=\"había terminado\">había terminado</span> (I had finished) — used for something that had ALREADY happened before another past event.</p>\n            <p><span class=\"tier-h\">H</span> After certain trigger phrases like <span data-say=\"es importante que\">es importante que</span> (it’s important that) or a future-time <span data-say=\"cuando\">cuando</span> (when), Spanish switches to the <strong>present subjunctive</strong>: <span data-say=\"Es importante que estudies mucho.\">Es importante que estudies mucho.</span> (It’s important that you study a lot.) / <span data-say=\"Cuando llegue a casa, cenaré.\">Cuando llegue a casa, cenaré.</span> (When I get home, I will have dinner.)</p>", "check": {"question": "Which sentence correctly uses the present subjunctive after a trigger phrase?", "options": ["Es importante que estudies mucho", "Es importante que estudias mucho", "Es importante estudiar que mucho", "Estudiarás mucho, es importante"], "answer": 0, "explain": "‘es importante que’ + a change of subject triggers the subjunctive (estudies), not the ordinary present indicative (estudias)."}}]}, "terms": {"enabled": true, "pairs": [{"term": "ir a + infinitivo", "definition": "near future: going to…"}, {"term": "voy a / vas a / va a", "definition": "I am / you are / he-she is going to"}, {"term": "hablaré", "definition": "I will speak"}, {"term": "comerás", "definition": "you will eat"}, {"term": "vivirá", "definition": "he/she will live"}, {"term": "tendré (tener)", "definition": "I will have"}, {"term": "haré (hacer)", "definition": "I will do / make"}, {"term": "podré (poder)", "definition": "I will be able to"}, {"term": "saldré (salir)", "definition": "I will leave / go out"}, {"term": "vendré (venir)", "definition": "I will come"}, {"term": "diré (decir)", "definition": "I will say"}, {"term": "hablaría", "definition": "I would speak"}, {"term": "tendría", "definition": "I would have"}, {"term": "me gustaría + infinitivo", "definition": "I would like to…"}, {"term": "he estudiado (H)", "definition": "I have studied"}, {"term": "había terminado (H)", "definition": "I had finished"}, {"term": "es importante que… (H)", "definition": "it’s important that… (+ subjunctive)"}, {"term": "cuando… (future time, H)", "definition": "when… (+ subjunctive)"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"Voy a estudiar esta noche.\" data-listen></span><br>Listen. What is the plan?", "options": ["To study tonight", "To study tomorrow morning instead", "To not study at all tonight", "I already studied last night"], "answer": 0, "explain": "‘voy a estudiar esta noche’ = I’m going to study tonight. The traps change the time, add a negative, or switch to the past."}, {"question": "<span data-say=\"Tendré que trabajar el sábado.\" data-listen></span><br>Listen. What is being said?", "options": ["I will have to work on Saturday", "I would have to work on Saturday", "I had to work last Saturday", "I don’t have to work on Saturday"], "answer": 0, "explain": "‘tendré que’ = I will have to (future). Trap B swaps it for the conditional (tendría), C for the past, D adds a negative."}, {"question": "Which is the correct future form of ‘vivir’ for ‘nosotros’?", "options": ["viviremos", "viviréis", "viviríamos", "vivimos"], "answer": 0, "explain": "The nosotros future ending is -emos → viviremos. viviréis is vosotros, viviríamos is conditional, vivimos is present."}, {"question": "Complete: ‘Si gano la lotería, ___ una casa nueva.’ (I would buy)", "options": ["compraría", "compraré", "compro", "comprarían"], "answer": 0, "explain": "compraría = I would buy (conditional). compraré is future, compro is present, comprarían is conditional but for ‘ellos’."}, {"question": "What does ‘me gustaría viajar a Japón’ mean?", "options": ["I would like to travel to Japan", "I am going to travel to Japan", "I travelled to Japan last year", "I like travelling, and Japan is nice"], "answer": 0, "explain": "me gustaría + infinitive = I would like to. B uses ir a, C is past tense, D breaks the phrase apart."}, {"question": "Which sentence correctly uses the irregular future stem for ‘hacer’?", "options": ["Mañana haré la tarea.", "Mañana haceré la tarea.", "Mañana hacía la tarea siempre.", "Mañana haría la tarea seguramente."], "answer": 0, "explain": "hacer → har- + é = haré. ‘haceré’ keeps the full infinitive wrongly, ‘hacía’ is imperfect, ‘haría’ is conditional."}, {"question": "<span data-say=\"Cuando tenga dieciocho años, aprenderé a conducir.\" data-listen></span><br>Listen. What will happen at 18?", "options": ["They will learn to drive", "They will buy a car", "They have already learned to drive", "They will not be allowed to drive"], "answer": 0, "explain": "‘aprenderé a conducir’ = I will learn to drive. The traps swap the action, the tense, or add a negative."}, {"question": "Complete: ‘Ellos ___ venir a la fiesta el viernes.’ (they will be able to)", "options": ["podrán", "poderán", "pueden", "podrían"], "answer": 0, "explain": "poder → podr- + án = podrán. ‘poderán’ wrongly keeps the infinitive stem, ‘pueden’ is present, ‘podrían’ is conditional."}, {"question": "Which sentence correctly uses the present subjunctive?", "options": ["Es importante que hagas los deberes.", "Es importante que haces los deberes.", "Es importante hacer que los deberes.", "Es importante harás los deberes pronto."], "answer": 0, "explain": "‘es importante que’ + new subject needs the subjunctive: hagas. B keeps the ordinary present, C and D are ungrammatical word orders."}, {"question": "What is the difference between ‘tendré’ and ‘tendría’?", "options": ["tendré = will have, tendría = would have", "tendré = would have, tendría = will have", "they mean exactly the same thing", "tendré is present tense, tendría is past tense"], "answer": 0, "explain": "The -é ending marks the future (will), the -ía ending marks the conditional (would) — same stem, different meaning."}]}, "fib": {"enabled": true, "questions": [{"text": "Yo [voy] a estudiar esta noche. <span data-say=\"Yo voy a estudiar esta noche.\" data-listen>Yo voy a estudiar esta noche.</span>"}, {"text": "Mañana, ella [tendrá] que trabajar. <span data-say=\"Mañana, ella tendrá que trabajar.\" data-listen>Mañana, ella tendrá que trabajar.</span>"}, {"text": "El año que viene, (yo) [viviré] en Madrid. (I will live — vivir)"}, {"text": "Con más dinero, (nosotros) [compraríamos] una casa grande. (we would buy — comprar)"}, {"text": "Me [gustaría] viajar a Japón algún día. (I would like)"}, {"text": "[haré] los deberes antes de salir. (I will do — hacer, yo)"}, {"text": "Es importante que (tú) [estudies] mucho para el examen. (present subjunctive of estudiar)"}]}, "tf": {"enabled": true, "questions": [{"statement": "The near future (ir a + infinitive) is formed with a conjugated form of ‘ir’, then ‘a’, then an infinitive.", "answer": true, "explain": "voy a estudiar, vas a comer, va a salir — always ir + a + infinitive."}, {"statement": "The simple future removes -ar/-er/-ir before adding the endings, like the imperfect tense.", "answer": false, "explain": "Future endings attach to the WHOLE infinitive (hablar+é); it is the stem for irregular verbs that changes, not a rule about all verbs."}, {"statement": "‘tendré’, ‘haré’, ‘podré’ and ‘saldré’ all have irregular stems in the future.", "answer": true, "explain": "tener→tendr-, hacer→har-, poder→podr-, salir→saldr- — all irregular future stems."}, {"statement": "The conditional uses a completely different stem from the future for irregular verbs.", "answer": false, "explain": "The conditional reuses the SAME stem as the future (e.g. tendr-); only the endings change."}, {"statement": "‘me gustaría’ is followed by an infinitive, just like ‘me gusta’.", "answer": true, "explain": "me gustaría estudiar / me gustaría viajar — same pattern as me gusta + infinitive."}, {"statement": "Every future and conditional ending carries a written accent, except the ‘nosotros’ future form.", "answer": true, "explain": "hablaremos has no accent, but every other future/conditional ending does (é, ás, á, éis, án / ía, ías, ía, íamos, íais, ían)."}, {"statement": "‘Es importante que estudies’ uses the present subjunctive because of ‘que’ plus a change of subject after a trigger phrase.", "answer": true, "explain": "es importante que + new subject triggers the subjunctive: estudies."}, {"statement": "The perfect tense is formed with the PRETERITE of haber plus a past participle.", "answer": false, "explain": "The perfect uses the PRESENT of haber (he/has/ha/hemos/habéis/han) + past participle."}]}, "misc": {"enabled": true, "items": [{"myth": "Voy estudiar esta noche.", "truth": "Voy a estudiar esta noche.", "check": {"question": "What is missing from ‘Voy estudiar esta noche’?", "options": ["the linking word ‘a’ (voy a estudiar)", "an accent on the final letter of ‘voy’", "the subject pronoun ‘yo’ at the start", "the word ‘esta’ before ‘noche’"], "answer": 0, "explain": "ir a + infinitive always needs ‘a’ between the conjugated ir and the infinitive."}}, {"myth": "Yo tenerá mucho dinero.", "truth": "Yo tendré mucho dinero.", "check": {"question": "Why is ‘tenerá’ wrong for the future of tener?", "options": ["tener has the irregular future stem tendr-, not tener-", "the ending should be -ería instead of the future ending -á", "‘tenerá’ is actually a correctly formed present-tense verb", "‘tenerá’ only needs an accent added on the very first e"], "answer": 0, "explain": "tener changes to the irregular stem tendr- before ANY future ending: tendré, tendrás, tendrá…"}}, {"myth": "Me gustaría estudio medicina.", "truth": "Me gustaría estudiar medicina.", "check": {"question": "Why is ‘Me gustaría estudio medicina’ wrong?", "options": ["‘gustaría’ must be followed by an infinitive, not a conjugated verb", "‘medicina’ should come before ‘gustaría’ at the start of the sentence", "‘me’ should be replaced with ‘yo’ at the front of the sentence", "‘gustaría’ should change to agree with ‘medicina’, becoming ‘gustarían’"], "answer": 0, "explain": "Like me gusta, me gustaría is followed by an infinitive: me gustaría estudiar."}}, {"myth": "Cuando llegaré a casa, cenaré.", "truth": "Cuando llegue a casa, cenaré.", "check": {"question": "Why does ‘cuando’ need the subjunctive here, not the future?", "options": ["‘cuando’ referring to a future event triggers the present subjunctive", "‘cuando’ is always followed by the preterite tense in absolutely every sentence", "‘llegaré’ is simply spelt incorrectly and needs an extra letter", "the second verb ‘cenaré’ should change too, to match the subjunctive"], "answer": 0, "explain": "A future-time ‘cuando’ clause takes the present subjunctive (llegue), while the main clause stays in the future (cenaré)."}}, {"myth": "Tendré muchas ganas de viajar si tuviera dinero.", "truth": "Tendría muchas ganas de viajar si tuviera dinero.", "check": {"question": "Why should ‘Tendré’ change to ‘Tendría’ here?", "options": ["a hypothetical ‘if I had…’ idea needs the conditional, not the future", "‘Tendré’ is missing the irregular stem tendr- at the very front", "‘viajar’ should be conjugated instead of being left as an infinitive here", "‘ganas’ needs to be made singular instead of staying plural"], "answer": 0, "explain": "A hypothetical ‘would’ idea needs the conditional (tendría), not the plain future (tendré)."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 1 — Listening for tense endings", "html": "Future and conditional endings sound very similar — the difference is often just one syllable: hablará (future, he will speak) vs hablaría (conditional, he would speak). Listen carefully for the extra ‘-í-’ sound that marks the conditional.", "check": {"question": "You hear ‘…comería…’ rather than ‘…comerá…’. What does the extra syllable tell you?", "options": ["it is the conditional (would eat), not the future (will eat)", "it is simply a longer, more formal way of saying the same thing", "nothing changes — they mean exactly the same", "it must be a reflexive verb"], "answer": 0, "explain": "The -ía sound is the conditional marker (would); -á alone is the future marker (will)."}}, {"title": "Paper 3/4 — Grammar accuracy in reading and writing", "html": "Examiners reward accurate irregular stems (tendré, not tenerá) and the little word ‘a’ after ir (voy a…, not voy…). Build a checklist before you submit any future/conditional sentence.", "check": {"question": "Which sentence would lose an accuracy mark?", "options": ["Voy estudiar mañana por la tarde.", "Voy a estudiar mañana por la tarde.", "Mañana voy a estudiar por la tarde.", "Por la tarde, voy a estudiar mañana."], "answer": 0, "explain": "‘Voy estudiar’ is missing the essential ‘a’ — ir a + infinitive."}}, {"title": "Paper 4 — Higher writing: range of tenses", "html": "Top-band answers combine several tenses and structures in one paragraph: a plan (voy a…), a firm future (estudiaré…), a conditional wish (me gustaría…) and, for the very top, the perfect/pluperfect or a subjunctive after ‘es importante que…’.", "check": {"question": "Which answer shows the widest range of tenses for the top band?", "options": ["Voy a estudiar mucho, estudiaré todos los días y me gustaría ir a la universidad", "Estudio mucho y estudio todos los días y quiero ir a la universidad siempre también", "Voy a estudiar", "Estudiaré"], "answer": 0, "explain": "It combines the near future, simple future and conditional in one answer, showing range and accuracy rather than just length."}}]}, "exam": {"enabled": true, "questions": [{"question": "Put each verb into the tense shown in brackets. Write the <strong>full Spanish verb form</strong> only.<br>(a) estudiar (yo — future)<br>(b) tener (ella — future)<br>(c) poder (nosotros — conditional)<br>(d) hacer (tú — future)<br>(e) gustar (a mí — conditional, meaning ‘I would like’)", "marks": 5, "hint": "Regular future/conditional endings attach to the whole infinitive. tener and hacer have irregular stems (tendr-, har-) in BOTH the future and the conditional. ‘I would like’ = me gustaría.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (AO4 Writing: grammar)</h5><ul>\n                <li><strong>(a)</strong> estudiaré <em>(1)</em>.</li>\n                <li><strong>(b)</strong> tendrá <em>(1)</em>.</li>\n                <li><strong>(c)</strong> podríamos <em>(1)</em>.</li>\n                <li><strong>(d)</strong> harás <em>(1)</em>.</li>\n                <li><strong>(e)</strong> me gustaría <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent slips only if the verb form is otherwise unambiguous; missing the irregular stem (e.g. ‘hacerás’) loses the mark.</li>\n            </ul></div>"}, {"question": "Translate these sentences <strong>into Spanish</strong>.<br>(a) I am going to travel to Spain next summer.<br>(b) I will study a lot for the exams.<br>(c) I would like to work abroad because it would be a good experience.", "marks": 5, "hint": "(a) ir a + infinitive. (b) simple future of estudiar. (c) me gustaría + infinitive, then ‘sería’ (conditional of ser) for ‘it would be’.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (AO4 Writing: translation)</h5><ul>\n                <li><strong>(a)</strong> Voy a viajar a España el verano que viene. <em>(1)</em></li>\n                <li><strong>(b)</strong> Estudiaré mucho para los exámenes. <em>(1)</em></li>\n                <li><strong>(c)</strong> Me gustaría trabajar en el extranjero <em>(1)</em> porque <em>(1)</em> sería una buena experiencia <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent errors. The irregular future/conditional stems must be recognisable to earn the mark.</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', 'g-6-pronouns-negatives-and-connectors', 'G.6 Pronouns, Negatives and Connectors', '{"learn": {"enabled": true, "items": [{"title": "When do I use (or drop) subject pronouns?", "html": "<p>Subject pronouns are <span data-say=\"yo\">yo</span> (I), <span data-say=\"tú\">tú</span> (you), <span data-say=\"él\">él</span> / <span data-say=\"ella\">ella</span> (he/she), <span data-say=\"nosotros\">nosotros / nosotras</span> (we), <span data-say=\"vosotros\">vosotros / vosotras</span> (you all) and <span data-say=\"ellos\">ellos</span> / <span data-say=\"ellas\">ellas</span> (they).</p>\n            <p>Spanish verb endings already show <em>who</em> is doing the action, so subject pronouns are usually <strong>dropped</strong>: <span data-say=\"Hablo español.\">Hablo español.</span> (I speak Spanish) needs no ‘yo’.</p>\n            <p>Keep the pronoun only for <strong>emphasis or contrast</strong>: <span data-say=\"Yo prefiero el fútbol, pero él prefiere el baloncesto.\">Yo prefiero el fútbol, pero él prefiere el baloncesto.</span> — <em>I prefer football, but he prefers basketball.</em></p>", "check": {"question": "Why does Spanish often drop ‘yo’, ‘tú’, etc.?", "options": ["the verb ending already shows who is doing the action", "subject pronouns are considered rude in spoken Spanish", "subject pronouns only exist for plural forms", "Spanish sentences never contain a conjugated verb"], "answer": 0, "explain": "The verb ending (hablo, hablas, habla…) already tells you the subject, so the pronoun is optional unless you need emphasis or contrast."}}, {"title": "Direct object pronouns: lo, la, los, las", "html": "<p>Use a <strong>direct object pronoun</strong> to avoid repeating a noun you have just mentioned: <span data-say=\"lo\">lo</span> (him/it, masc.), <span data-say=\"la\">la</span> (her/it, fem.), <span data-say=\"los\">los</span> (them, masc.), <span data-say=\"las\">las</span> (them, fem.).</p>\n            <p>Position: put it <strong>before a conjugated verb</strong> — <span data-say=\"¿Tienes el libro?\">¿Tienes el libro?</span> <span data-say=\"Sí, lo tengo.\">Sí, lo tengo.</span> (Yes, I have it) — or <strong>attach it to an infinitive</strong>: <span data-say=\"Voy a verlo.\">Voy a verlo.</span> (I’m going to watch it).</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"lo veo\">lo veo</span></td><td>I see him / it (masc.)</td></tr>\n              <tr><td><span data-say=\"la veo\">la veo</span></td><td>I see her / it (fem.)</td></tr>\n              <tr><td><span data-say=\"los veo\">los veo</span></td><td>I see them (masc.)</td></tr>\n              <tr><td><span data-say=\"las veo\">las veo</span></td><td>I see them (fem.)</td></tr>\n            </table>", "check": {"question": "Where does the direct object pronoun ‘lo’ go with a conjugated verb like ‘veo’?", "options": ["before the verb: lo veo", "after the verb with a gap: veo lo", "attached to the end of the conjugated verb: veolo", "it can never be used with a conjugated verb"], "answer": 0, "explain": "With a conjugated verb the pronoun goes immediately before it: lo veo. It only attaches to the END of an infinitive or gerund."}}, {"title": "Indirect object and reflexive pronouns", "html": "<p><strong>Indirect object pronouns</strong> (to/for whom) are <span data-say=\"me\">me</span>, <span data-say=\"te\">te</span>, <span data-say=\"le\">le</span>, <span data-say=\"nos\">nos</span>: <span data-say=\"Le doy el regalo a mi madre.\">Le doy el regalo a mi madre.</span> (I give the present to my mother.)</p>\n            <p><strong>Reflexive pronouns</strong> (me, te, se, nos, os, se) show the action is done <em>to yourself</em>: <span data-say=\"me levanto\">me levanto</span> (I get up), <span data-say=\"se levanta\">se levanta</span> (he/she gets up).</p>\n            <p><span class=\"tier-h\">H</span> When a direct AND indirect pronoun combine, ‘le’/‘les’ change to <strong>se</strong>: <span data-say=\"Se lo doy a mi hermano.\">Se lo doy a mi hermano.</span> — <em>I give it to my brother.</em></p>", "check": {"question": "Which set of pronouns is used for reflexive verbs like ‘levantarse’?", "options": ["me, te, se, nos, os, se", "lo, la, los, las", "que, quien, lo que", "muy, bastante, demasiado"], "answer": 0, "explain": "Reflexive verbs take me/te/se/nos/os/se, matching the subject doing the action to itself."}}, {"title": "Relative pronouns: que, quien, lo que", "html": "<p><span data-say=\"que\">que</span> (who/that/which) is the most common relative pronoun and works for <strong>both</strong> people and things: <span data-say=\"El chico que vive aquí es mi amigo.\">El chico que vive aquí es mi amigo.</span></p>\n            <p><span data-say=\"quien\">quien</span> / quienes <span class=\"tier-h\">H</span> means ‘who’ but is normally used only for people, especially after a preposition: <span data-say=\"la persona con quien hablo\">la persona con quien hablo</span> (the person I talk to).</p>\n            <p><span data-say=\"lo que\">lo que</span> <span class=\"tier-h\">H</span> means ‘what / that which’ — it refers to an <strong>idea</strong>, not one specific noun: <span data-say=\"Hago lo que quiero.\">Hago lo que quiero.</span> (I do what I want.)</p>", "check": {"question": "Which relative pronoun means ‘what/that which’ and refers to an idea rather than one noun?", "options": ["lo que", "que", "quien", "quienes"], "answer": 0, "explain": "‘lo que’ sums up a whole idea (‘what I want’), while ‘que’ and ‘quien(es)’ replace a specific noun."}}, {"title": "Negatives: nada, nunca, nadie, ni…ni", "html": "<p>Spanish uses a <strong>double negative</strong> — ‘no’ plus a negative word: <span data-say=\"no veo nada\">no veo nada</span> (I don’t see anything/I see nothing).</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"no...nada\">no … nada</span></td><td>nothing</td></tr>\n              <tr><td><span data-say=\"no...nunca\">no … nunca</span> / <span data-say=\"jamás\">jamás</span></td><td>never</td></tr>\n              <tr><td><span data-say=\"no...nadie\">no … nadie</span></td><td>nobody</td></tr>\n              <tr><td><span data-say=\"no...ni...ni\">no … ni … ni</span></td><td>neither … nor</td></tr>\n            </table>\n            <p>Examples: <span data-say=\"no como nunca carne\">No como nunca carne.</span> (I never eat meat.) <span data-say=\"no hay nadie\">No hay nadie.</span> (There’s nobody.) <span data-say=\"no me gusta ni el fútbol ni el tenis\">No me gusta ni el fútbol ni el tenis.</span> (I like neither football nor tennis.)</p>\n            <p><span class=\"tier-h\">H</span> You can drop ‘no’ if the negative word comes BEFORE the verb: <span data-say=\"nunca voy al gimnasio\">Nunca voy al gimnasio.</span> (I never go to the gym.)</p>", "check": {"question": "How do you say ‘I don’t see anything’ correctly in Spanish?", "options": ["No veo nada.", "No veo.", "Veo nada.", "No veo algo."], "answer": 0, "explain": "Spanish needs the double negative: no + veo + nada. Dropping ‘nada’, dropping ‘no’, or using ‘algo’ (something) are all wrong."}}, {"title": "Connectors and intensifiers", "html": "<p>Basic connectors join ideas: <span data-say=\"y\">y</span> (and), <span data-say=\"pero\">pero</span> (but), <span data-say=\"porque\">porque</span> (because), <span data-say=\"también\">también</span> (also), <span data-say=\"además\">además</span> (furthermore).</p>\n            <p><span class=\"tier-h\">H</span> For top marks add: <span data-say=\"sin embargo\">sin embargo</span> (however) and <span data-say=\"aunque\">aunque</span> (although) — <span data-say=\"aunque\">aunque</span> introduces a <strong>contrast</strong>, unlike ‘además’ which adds an idea.</p>\n            <p>Intensifiers strengthen or soften an adjective: <span data-say=\"muy\">muy</span> (very), <span data-say=\"bastante\">bastante</span> (quite), <span data-say=\"demasiado\">demasiado</span> (too much/many), <span data-say=\"un poco\">un poco</span> (a bit).</p>\n            <p>Example: <span data-say=\"Me gusta el deporte, pero prefiero la música. Además, toco la guitarra. Sin embargo, no tengo mucho tiempo.\">Me gusta el deporte, pero prefiero la música. Además, toco la guitarra. Sin embargo, no tengo mucho tiempo.</span></p>", "check": {"question": "Which connector means ‘although’ and introduces a contrast?", "options": ["aunque", "porque", "también", "además"], "answer": 0, "explain": "‘aunque’ (although) signals a contrast; ‘porque’ gives a reason, and ‘también’/‘además’ add extra ideas rather than contrast them."}}]}, "terms": {"enabled": true, "pairs": [{"term": "lo", "definition": "him / it (masculine)"}, {"term": "la", "definition": "her / it (feminine)"}, {"term": "los", "definition": "them (masculine)"}, {"term": "las", "definition": "them (feminine)"}, {"term": "me", "definition": "to/for me · myself (reflexive)"}, {"term": "te", "definition": "to/for you · yourself (reflexive)"}, {"term": "se", "definition": "himself / herself / themselves (reflexive)"}, {"term": "que", "definition": "who, that, which"}, {"term": "quien (H)", "definition": "who (after a preposition)"}, {"term": "lo que (H)", "definition": "what, that which"}, {"term": "no … nada", "definition": "nothing"}, {"term": "no … nunca", "definition": "never"}, {"term": "no … nadie", "definition": "nobody"}, {"term": "no … ni … ni", "definition": "neither … nor"}, {"term": "sin embargo (H)", "definition": "however"}, {"term": "aunque (H)", "definition": "although"}, {"term": "además", "definition": "furthermore, also"}, {"term": "un poco", "definition": "a bit"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"No veo nada.\" data-listen></span><br>Listen. What does she say?", "options": ["I don''t see anything", "I never see anything", "I don''t see anybody", "I always see everything"], "answer": 0, "explain": "‘No veo nada’ = I don''t see anything. The traps swap nada→nunca, nada→nadie, or reverse the negative entirely."}, {"question": "<span data-say=\"Se lo doy a mi hermano.\" data-listen></span><br>Listen. What is being described?", "options": ["I give it to my brother", "I give it to my sister", "I gave it to my brother yesterday", "I never give it to my brother"], "answer": 0, "explain": "‘Se lo doy a mi hermano’ = I give it to my brother (se lo = le + lo). Traps swap the gender, the tense, or add a negative."}, {"question": "Complete: ‘¿Tienes las llaves? Sí, ___ tengo.’", "options": ["las", "los", "la", "le"], "answer": 0, "explain": "‘las llaves’ is feminine plural, so the pronoun must be ‘las’. The others fail to agree in gender/number or are the wrong pronoun type."}, {"question": "Which sentence means ‘I speak Spanish’ and drops the unneeded pronoun, as native speakers usually do?", "options": ["Hablo español.", "Yo hablo español todos los días.", "Habla español.", "Hablas español."], "answer": 0, "explain": "‘Hablo español’ already shows ‘I’ through the verb ending — no pronoun needed. C and D conjugate for the wrong person."}, {"question": "Complete: ‘(Yo) ___ levanto a las siete.’", "options": ["me", "te", "se", "nos"], "answer": 0, "explain": "‘(Yo) me levanto’ — the reflexive pronoun must match the subject ‘yo’. The others are for a different person."}, {"question": "Complete: ‘La chica ___ vive al lado es mi vecina.’ (who/that)", "options": ["que", "quien", "lo que", "cual"], "answer": 0, "explain": "‘que’ links a noun (la chica) to extra information. ‘quien’ needs a preposition, ‘lo que’ refers to an idea, and ‘cual’ needs an article."}, {"question": "How do you say ‘There is nobody here’?", "options": ["No hay nadie aquí.", "Hay nadie aquí.", "No hay alguien aquí.", "No hay nada aquí."], "answer": 0, "explain": "‘No hay nadie aquí’ needs the double negative. B drops ‘no’; C wrongly pairs ‘no’ with ‘alguien’ (someone); D confuses nadie (nobody) with nada (nothing)."}, {"question": "Complete: ‘No voy a la fiesta ___ tengo mucha tarea.’ (because)", "options": ["porque", "aunque", "pero", "también"], "answer": 0, "explain": "‘porque’ gives the reason. ‘aunque’ (although) reverses the logic, ‘pero’ (but) and ‘también’ (also) don''t fit a cause."}, {"question": "Which best translates ‘un poco cansado’?", "options": ["a bit tired", "extremely tired", "never tired", "the most tired of all"], "answer": 0, "explain": "‘un poco’ softens the adjective to ‘a bit’. The distractors overstate it, negate it, or turn it into a superlative."}, {"question": "How do you say ‘I see it’, referring to ‘la película’ (feminine)?", "options": ["La veo.", "Veo la.", "Lo veo.", "La veo mucho."], "answer": 0, "explain": "‘la película’ is feminine, so the pronoun ‘la’ goes before the verb: La veo. B puts it after; C uses the wrong gender; D adds a meaning-changing ‘mucho’."}]}, "fib": {"enabled": true, "questions": [{"text": "¿Tienes el libro? Sí, [lo] tengo. (it — masculine, direct object pronoun)"}, {"text": "No veo [nada]. <span data-say=\"No veo nada.\" data-listen>No veo nada.</span>"}, {"text": "Voy a hacer más ejercicio, [porque] es bueno para la salud. (because)"}, {"text": "(Yo) [me] levanto a las siete. (myself — reflexive pronoun)"}, {"text": "La chica [que] vive aquí es mi amiga. (who/that)"}, {"text": "No voy [nunca] al gimnasio los domingos. (never)"}, {"text": "Juego al fútbol y, [además], hago natación. (also/furthermore)"}]}, "tf": {"enabled": true, "questions": [{"statement": "Spanish usually drops subject pronouns like ‘yo’ and ‘tú’ because the verb ending shows who is speaking.", "answer": true, "explain": "Hablo español needs no ‘yo’ — the -o ending already shows it."}, {"statement": "‘lo’ and ‘la’ are indirect object pronouns.", "answer": false, "explain": "‘lo’ and ‘la’ are DIRECT object pronouns; ‘le’ and ‘les’ are indirect."}, {"statement": "A direct object pronoun can attach to the end of an infinitive, e.g. ‘voy a verlo’.", "answer": true, "explain": "voy a verlo = I''m going to watch it, with ‘lo’ attached to the infinitive."}, {"statement": "Reflexive pronouns are only used in the plural.", "answer": false, "explain": "Reflexive pronouns exist for every person: me, te, se, nos, os, se."}, {"statement": "‘que’ can refer to both people and things.", "answer": true, "explain": "El chico que vive aquí… / El libro que compré… — que works for both."}, {"statement": "‘lo que’ means ‘the’ and goes before every noun.", "answer": false, "explain": "‘lo que’ means ‘what/that which’ and refers to a whole idea, not a single noun."}, {"statement": "Spanish uses a double negative, e.g. ‘no veo nada’.", "answer": true, "explain": "‘no’ plus a negative word (nada, nunca, nadie…) is the normal Spanish pattern."}, {"statement": "‘sin embargo’ and ‘aunque’ are examples of negatives.", "answer": false, "explain": "They are CONNECTORS (however / although), not negatives."}]}, "misc": {"enabled": true, "items": [{"myth": "Veo lo.", "truth": "Lo veo.", "check": {"question": "Why is ‘Veo lo’ wrong?", "options": ["the object pronoun must go BEFORE a conjugated verb (Lo veo)", "the pronoun ‘lo’ should be ‘la’ instead", "the verb ‘veo’ is spelt incorrectly", "object pronouns can never be used with a conjugated verb like ‘veo’, only with an infinitive such as ‘ver’"], "answer": 0, "explain": "With a conjugated verb the pronoun comes before it; it only attaches after an infinitive or gerund."}}, {"myth": "Yo yo hablo español.", "truth": "Hablo español.", "check": {"question": "What’s wrong with doubling the pronoun in ‘Yo yo hablo’?", "options": ["the subject pronoun only needs using once, or can be dropped, since the verb ending shows ‘yo’", "‘yo’ must always be repeated twice in a row for extra emphasis in every single Spanish sentence you write", "‘hablo’ needs two subject pronouns to agree", "Spanish verbs cannot be used without two pronouns"], "answer": 0, "explain": "‘Hablo’ already carries the meaning of ‘yo’; one pronoun (or none) is correct, never a double."}}, {"myth": "El libro quien compré es interesante.", "truth": "El libro que compré es interesante.", "check": {"question": "Why is ‘el libro quien compré’ wrong?", "options": ["‘quien’ only refers to people, not things — things need ‘que’", "‘quien’ must always follow the word ‘lo’ before any noun or pronoun", "‘compré’ should be changed to ‘compro’", "‘libro’ needs a written accent on the final syllable"], "answer": 0, "explain": "‘quien/quienes’ refers to people; a thing like ‘el libro’ needs ‘que’."}}, {"myth": "No veo.", "truth": "No veo nada.", "check": {"question": "Why is ‘No veo’ alone not correct for ‘I don’t see anything’?", "options": ["Spanish needs the double negative: no + veo + nada", "‘veo’ on its own already means ‘nothing’ without adding any other word", "‘no’ on its own already means ‘nothing’", "you should never use ‘no’ together with ‘ver’"], "answer": 0, "explain": "Without ‘nada’, ‘No veo’ just means ‘I don’t see’ — it is missing what you don’t see."}}, {"myth": "Me gusta el deporte, aunque prefiero la música.", "truth": "Me gusta el deporte, además prefiero la música.", "check": {"question": "What’s the problem with ‘aunque’ here if you mean ‘as well as that’?", "options": ["‘aunque’ means ‘although’ and introduces a contrast, not an addition", "‘aunque’ is spelt incorrectly and should not appear anywhere in the sentence", "‘aunque’ can only be used to start a question", "‘aunque’ is one of the negative words like ‘nada’"], "answer": 0, "explain": "‘aunque’ signals a contrast (although); to ADD an idea you need ‘además’ or ‘también’."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 1 — Listening: pronouns and negatives in context", "html": "Listen for whether the object pronoun is ‘lo/la’ (singular) or ‘los/las’ (plural), and for the negative word right after ‘no’ — ‘nada’, ‘nunca’ or ‘nadie’ completely change the meaning even though they sound similar.", "check": {"question": "You hear ‘no … nadie’. What does that tell you?", "options": ["nobody is involved", "nothing at all happened", "the action never happens", "everything is fine"], "answer": 0, "explain": "‘no … nadie’ = nobody, not ‘nada’ (nothing) or ‘nunca’ (never)."}}, {"title": "Paper 3 — Reading: relative pronouns link ideas", "html": "Long reading texts use ‘que’, ‘quien’ and ‘lo que’ to join sentences. Track WHO or WHAT each pronoun refers back to — that noun is usually a few words earlier in the sentence.", "check": {"question": "In ‘Hago lo que quiero’, what does ‘lo que’ refer to?", "options": ["a whole idea (‘what I want’), not one specific noun", "one masculine singular noun that was already mentioned earlier in the same sentence", "a person the speaker is talking to directly", "a place mentioned earlier in the text"], "answer": 0, "explain": "‘lo que’ sums up an idea, unlike ‘que’, which replaces one specific noun."}}, {"title": "Paper 4 — Writing: use connectors and pronouns for range", "html": "Top-band answers combine a pronoun (‘lo/la’), a negative (‘nunca’, ‘nada’) and a Higher connector (‘sin embargo’, ‘aunque’) in the same paragraph, instead of repeating ‘y’ and ‘pero’ throughout.", "check": {"question": "Which answer shows the widest range of structures?", "options": ["Me gusta el fútbol, pero nunca lo juego porque, sin embargo, prefiero nadar", "Me gusta el fútbol y me gusta nadar y me gusta el baloncesto y también me gusta el tenis", "Me gusta el deporte", "No me gusta nada"], "answer": 0, "explain": "It combines a pronoun (lo), a negative (nunca) and Higher connectors (pero, sin embargo) — range plus accuracy, not just repeated ‘y’."}}]}, "exam": {"enabled": true, "questions": [{"question": "Complete the text with <strong>one</strong> word from this list for each gap: <strong>lo, porque, que, nunca, aunque</strong>. Use each word once.<br>Mi amigo Carlos tiene un coche nuevo. Yo no (1)___ tengo, así que voy en bici. Me gusta el ciclismo (2)___ es bueno para la salud. Mi hermano, (3)___ vive cerca, viene conmigo a veces. (4)___ vamos en invierno porque hace demasiado frío. Me gusta el ciclismo, (5)___ prefiero nadar en verano.", "marks": 5, "hint": "(1) replaces ‘un coche nuevo’ (masculine). (2) gives a reason. (3) links back to ‘mi hermano’. (4) is a negative word before the verb. (5) introduces a contrast with what comes before it.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (grammar in context)</h5><ul>\n                <li><strong>(1)</strong> lo <em>(1)</em></li>\n                <li><strong>(2)</strong> porque <em>(1)</em></li>\n                <li><strong>(3)</strong> que <em>(1)</em></li>\n                <li><strong>(4)</strong> nunca <em>(1)</em></li>\n                <li><strong>(5)</strong> aunque <em>(1)</em></li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Each gap is worth one mark; the word must be spelt correctly and used only once.</li>\n            </ul></div>"}, {"question": "Translate this paragraph <strong>into Spanish</strong>: ‘I like football, but I prefer basketball. However, I never play at the weekend because I have too much homework.’", "marks": 4, "hint": "‘however’ = sin embargo; ‘I never play’ needs the double negative (no juego … nunca, or nunca before the verb); ‘too much/many’ = demasiado/demasiados.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 4 marks (AO4 Writing: translation)</h5><ul>\n                <li><strong>Me gusta el fútbol</strong> <em>(1)</em></li>\n                <li><strong>pero prefiero el baloncesto</strong> <em>(1)</em></li>\n                <li><strong>Sin embargo, nunca juego los fines de semana</strong> <em>(1)</em></li>\n                <li><strong>porque tengo demasiados deberes</strong> <em>(1)</em></li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent errors and ‘no juego nunca’ as an alternative to ‘nunca juego’.</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', '1-1-me-my-family-and-friends', '1.1 Me, My Family and Friends', '{"learn": {"enabled": true, "items": [{"title": "How do I introduce myself?", "html": "<p>The building blocks for talking about yourself — tap 🔊 to hear each one.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"me llamo\">me llamo…</span></td><td>my name is…</td><td><span data-say=\"tengo catorce años\">tengo… años</span></td><td>I am … years old</td></tr>\n              <tr><td><span data-say=\"soy de\">soy de…</span></td><td>I am from…</td><td><span data-say=\"vivo en\">vivo en…</span></td><td>I live in…</td></tr>\n            </table>\n            <p>Model: <span data-say=\"Me llamo Ana, tengo quince años y vivo en Madrid.\">Me llamo Ana, tengo quince años y vivo en Madrid.</span></p>\n            <p><strong>Big rule:</strong> for age Spanish uses <strong>tener</strong> (to have), not ‘ser’ — you literally ‘have’ years.</p>", "check": {"question": "How do you say ‘I am 15 years old’?", "options": ["Tengo quince años", "Soy quince años", "Estoy quince años", "Tengo quince año"], "answer": 0, "explain": "Age uses tener: ‘tengo quince años’ — never ‘soy’. ‘años’ is plural."}}, {"title": "How do I describe how I look?", "html": "<p>Use <strong>ser</strong> for build/height and <strong>tener</strong> for hair and eyes:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"soy alto\">soy alto / alta</span></td><td>I am tall</td><td><span data-say=\"soy bajo\">soy bajo / baja</span></td><td>I am short</td></tr>\n              <tr><td><span data-say=\"soy delgado\">soy delgado / delgada</span></td><td>I am slim</td><td><span data-say=\"llevo gafas\">llevo gafas</span></td><td>I wear glasses</td></tr>\n            </table>\n            <p>Model: <span data-say=\"Soy alta y delgada, y llevo gafas.\">Soy alta y delgada, y llevo gafas.</span> <em>(alt<strong>a</strong>, delgad<strong>a</strong> — female.)</em></p>", "check": {"question": "Which verb describes hair and eyes — ‘tengo el pelo…’?", "options": ["tener (to have)", "ser (to be)", "estar (to be)", "llevar (to wear)"], "answer": 0, "explain": "Spanish ‘has’ hair and eyes: tengo el pelo…, tengo los ojos… ‘llevar’ is for glasses/clothes."}}, {"title": "How do I describe my hair and eyes?", "html": "<p>Use <strong>tengo el pelo…</strong> (I have … hair) and <strong>tengo los ojos…</strong> (I have … eyes). Note the article (‘el’, ‘los’) — Spanish keeps it.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el pelo rubio\">el pelo rubio</span></td><td>blond hair</td><td><span data-say=\"el pelo moreno\">el pelo moreno</span></td><td>dark hair</td></tr>\n              <tr><td><span data-say=\"el pelo castaño\">el pelo castaño</span></td><td>brown hair</td><td><span data-say=\"corto o largo\">corto / largo</span></td><td>short / long</td></tr>\n              <tr><td><span data-say=\"los ojos azules\">los ojos azules</span></td><td>blue eyes</td><td><span data-say=\"los ojos marrones\">los ojos marrones</span></td><td>brown eyes</td></tr>\n            </table>\n            <p>Colours agree: eyes are plural, so <span data-say=\"Tengo los ojos verdes.\">Tengo los ojos verdes.</span></p>", "check": {"question": "How do you say ‘I have long hair’?", "options": ["Tengo el pelo largo", "Llevo el pelo largo casi siempre", "Soy el pelo largo", "Tengo el pelo larga"], "answer": 0, "explain": "Hair uses tener + the article ‘el’; ‘pelo’ is masculine so the colour/length agrees: largo (not larga)."}}, {"title": "Who is in my family?", "html": "<p>Family members (<strong>la familia</strong>):</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"los padres\">los padres</span></td><td>parents</td><td><span data-say=\"los abuelos\">los abuelos</span></td><td>grandparents</td></tr>\n              <tr><td><span data-say=\"el hermano mayor\">el hermano mayor</span></td><td>older brother</td><td><span data-say=\"la hermana menor\">la hermana menor</span></td><td>younger sister</td></tr>\n              <tr><td><span data-say=\"el tío\">el tío / la tía</span></td><td>uncle / aunt</td><td><span data-say=\"el primo\">el primo / la prima</span></td><td>cousin</td></tr>\n            </table>\n            <p><span data-say=\"Soy hijo único.\">Soy hijo único.</span> = I’m an only child. <span data-say=\"En mi familia hay cuatro personas.\">En mi familia hay cuatro personas.</span></p>", "check": {"question": "What does ‘mi hermana menor’ mean?", "options": ["my younger sister", "my older sister", "my younger brother", "my cousin"], "answer": 0, "explain": "hermana = sister; menor = younger. mayor = older."}}, {"title": "How do I say ‘my’ and ‘your’? (possessives)", "html": "<p>Possessive adjectives agree with the <strong>number</strong> of the thing owned (one or many), NOT with you:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"mi hermano\">mi</span> (one thing)</td><td>my — <span data-say=\"mi hermano\">mi hermano</span></td></tr>\n              <tr><td><span data-say=\"mis hermanos\">mis</span> (more than one)</td><td>my — <span data-say=\"mis hermanos\">mis hermanos</span></td></tr>\n              <tr><td><span data-say=\"tu casa\">tu / tus</span></td><td>your — tu casa, tus amigos</td></tr>\n              <tr><td><span data-say=\"su perro\">su / sus</span></td><td>his / her / their</td></tr>\n            </table>\n            <p>So it’s <strong>mi</strong> hermano but <strong>mis</strong> hermanos — the ‑s matches the plural noun.</p>", "check": {"question": "How do you say ‘my brothers’ (more than one)?", "options": ["mis hermanos", "mi hermanos", "mío hermanos", "mis hermano"], "answer": 0, "explain": "The possessive agrees with the plural noun: mis hermanos."}}, {"title": "Higher: longer, richer descriptions", "html": "<p><span class=\"tier-h\">H</span> Add quantifiers and join clauses to describe more precisely:</p>\n            <ul>\n              <li>Quantifiers: <span data-say=\"bastante alto\">bastante alto</span> (quite tall), <span data-say=\"un poco tímido\">un poco tímido</span> (a bit shy). <span class=\"tier-h\">H</span></li>\n              <li>Relative ‘que’: <span data-say=\"Tengo un hermano que se llama Luis.\">Tengo un hermano que se llama Luis.</span> <span class=\"tier-h\">H</span></li>\n              <li>Combine appearance + who: <span data-say=\"Mi hermana mayor, que es muy alta, tiene el pelo largo y rizado.\">Mi hermana mayor, que es muy alta, tiene el pelo largo y rizado.</span> <span class=\"tier-h\">H</span></li>\n            </ul>", "check": {"question": "‘Tengo un hermano que se llama Luis’ — what does ‘que’ do here?", "options": ["it links two ideas (‘who’ / ‘that’)", "it is used to ask a question meaning ‘what?’", "it means ‘because’", "it makes the sentence a plan"], "answer": 0, "explain": "Relative ‘que’ = who/that; it joins ‘I have a brother’ + ‘he is called Luis’."}}]}, "terms": {"enabled": true, "pairs": [{"term": "me llamo…", "definition": "my name is…"}, {"term": "tengo… años", "definition": "I am … years old"}, {"term": "soy de… · vivo en…", "definition": "I am from… · I live in…"}, {"term": "soy alto / bajo", "definition": "I am tall / short (ser)"}, {"term": "tengo el pelo rubio", "definition": "I have blond hair"}, {"term": "castaño · moreno", "definition": "brown · dark (hair)"}, {"term": "corto / largo · rizado / liso", "definition": "short / long · curly / straight"}, {"term": "tengo los ojos azules", "definition": "I have blue eyes"}, {"term": "los ojos marrones / verdes", "definition": "brown / green eyes"}, {"term": "llevo gafas", "definition": "I wear glasses"}, {"term": "los padres · los abuelos", "definition": "parents · grandparents"}, {"term": "el hermano mayor / menor", "definition": "older / younger brother"}, {"term": "el tío / la tía · el primo / la prima", "definition": "uncle/aunt · cousin"}, {"term": "hijo único / hija única", "definition": "only child"}, {"term": "mi / mis", "definition": "my (one / more than one)"}, {"term": "tu / tus · su / sus", "definition": "your · his/her/their"}, {"term": "bastante · un poco (H)", "definition": "quite · a bit (quantifiers)"}, {"term": "que (H)", "definition": "who / that (relative pronoun)"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"Tengo quince años.\" data-listen></span><br>Listen. What is being said?", "options": ["I am fifteen years old", "I have fifteen euros", "There are fifteen of us at home", "I am fifty years old"], "answer": 0, "explain": "‘tengo quince años’ = I am 15 (literally ‘I have 15 years’). Traps play on ‘tengo’ and the number."}, {"question": "<span data-say=\"Tengo el pelo largo y castaño.\" data-listen></span><br>Listen. How is the hair described?", "options": ["long and brown", "short and black", "long and blond", "curly and grey"], "answer": 0, "explain": "largo = long, castaño = brown. The distractors swap one or both features."}, {"question": "<span data-say=\"Mi hermano mayor lleva gafas.\" data-listen></span><br>Listen. Which is correct?", "options": ["My older brother wears glasses", "My younger brother has a beard", "My older sister wears glasses too", "My brother wants some new glasses"], "answer": 0, "explain": "hermano mayor = older brother; lleva gafas = wears glasses. Distractors change age, gender or add detail."}, {"question": "How do you say ‘I am 14 years old’?", "options": ["Tengo catorce años", "Soy catorce años", "Tengo catorce años de vida", "Estoy catorce años"], "answer": 0, "explain": "Age = tener: tengo catorce años. ‘Soy/Estoy’ are the classic English-speaker error."}, {"question": "Which is correct for ‘I have brown eyes’?", "options": ["Tengo los ojos marrones", "Tengo los ojos de color marrón", "Tengo los ojos marrón", "Soy los ojos marrones"], "answer": 0, "explain": "los ojos is plural → the colour agrees: marrones. ‘marrón’ singular does not agree; ‘soy’ is wrong."}, {"question": "Complete: ‘___ hermanos son altos.’ (my brothers)", "options": ["Mis", "Sus", "Mi", "Tu"], "answer": 0, "explain": "The possessive agrees with the plural noun ‘hermanos’ → mis. ‘Sus’ would mean ‘their/his/her’."}, {"question": "‘Soy hijo único’ means…", "options": ["I am an only child", "I am a unique person", "I am the eldest son", "I am someone''s only true friend"], "answer": 0, "explain": "hijo único = only child. (‘único’ here is ‘only’, not ‘unique’.)"}, {"question": "Complete: ‘___ el pelo rubio.’ (I have)", "options": ["Tengo", "Soy", "Está", "Llevo"], "answer": 0, "explain": "Hair uses tener → Tengo el pelo rubio."}, {"question": "Why ‘Tengo 15 años’, not ‘Soy 15 años’?", "options": ["Spanish uses ‘tener’ (to have) for age", "‘ser’ can only describe your job", "you must always use ‘estar’ with numbers", "‘años’ has to follow the verb ‘ser’"], "answer": 0, "explain": "Age is expressed with tener in Spanish: you ‘have’ years."}, {"question": "‘Mi hermana, que es alta, tiene el pelo rizado’ — what does ‘que’ do?", "options": ["links two ideas (‘who / that’)", "shows that it is a plan for the future", "turns it into a question", "means ‘because’"], "answer": 0, "explain": "Relative ‘que’ = who/that, joining ‘my sister’ + ‘she is tall’."}]}, "fib": {"enabled": true, "questions": [{"text": "[Tengo] quince años. <span data-say=\"Tengo quince años.\" data-listen>Tengo quince años.</span>"}, {"text": "Tengo el pelo largo y [castaño]. <span data-say=\"Tengo el pelo largo y castaño.\" data-listen>Tengo el pelo largo y castaño.</span>"}, {"text": "Mi hermano mayor [lleva] gafas. <span data-say=\"Mi hermano mayor lleva gafas.\" data-listen>Mi hermano mayor lleva gafas.</span>"}, {"text": "Tengo los ojos [marrones]. (brown — plural agreement!)"}, {"text": "[Mis] hermanos son altos. (my — more than one)"}, {"text": "Soy hijo [único]. (only child)"}, {"text": "Me [llamo] Ana y vivo en Madrid. (my name is)"}]}, "tf": {"enabled": true, "questions": [{"statement": "For age, Spanish uses ‘tener’ — ‘tengo quince años’.", "answer": true, "explain": "You literally ‘have’ years: tengo… años. ‘Soy… años’ is wrong."}, {"statement": "Hair and eyes use ‘tener’: ‘tengo el pelo rubio’.", "answer": true, "explain": "Spanish ‘has’ hair and eyes, and keeps the article (el/los)."}, {"statement": "‘hijo único’ means ‘a unique son’.", "answer": false, "explain": "It means ‘only child’ — único here = only."}, {"statement": "‘mis hermanos’ is correct because the possessive agrees with the plural noun.", "answer": true, "explain": "mi → mis to match a plural noun (hermanos)."}, {"statement": "‘mayor’ means ‘younger’.", "answer": false, "explain": "mayor = older; menor = younger."}, {"statement": "‘Tengo los ojos marrón’ is correct.", "answer": false, "explain": "Eyes are plural, so the colour must agree: los ojos marrones."}, {"statement": "‘llevar’ is used for glasses: ‘llevo gafas’.", "answer": true, "explain": "llevar = to wear (glasses, clothes)."}, {"statement": "Build/height uses ‘ser’: ‘soy alto’.", "answer": true, "explain": "ser describes what you are like: soy alto/alta."}]}, "misc": {"enabled": true, "items": [{"myth": "Soy quince años.", "truth": "Tengo quince años.", "check": {"question": "Why ‘Tengo quince años’, not ‘Soy…’?", "options": ["Spanish expresses age with ‘tener’ (to have)", "‘ser’ can only ever be used with jobs", "you must put the number after the verb ‘ser’", "age always needs the verb ‘estar’ instead"], "answer": 0, "explain": "In Spanish you ‘have’ years: tengo… años."}}, {"myth": "Tengo ojos azul.", "truth": "Tengo los ojos azules.", "check": {"question": "What is wrong with ‘Tengo ojos azul’?", "options": ["needs ‘los’ and the plural colour ‘azules’", "the verb here should really be ‘soy’ and not ‘tengo’", "‘ojos’ must be written in the singular", "you must add an accent to ‘azul’"], "answer": 0, "explain": "Keep the article ‘los’ and agree the colour in the plural: los ojos azules."}}, {"myth": "Mis hermano es alto.", "truth": "Mi hermano es alto.", "check": {"question": "Why ‘Mi hermano’, not ‘Mis hermano’?", "options": ["‘hermano’ is singular, so the possessive is ‘mi’", "the possessive always agrees with the person who is speaking", "you always use ‘mis’ before a family word", "‘hermano’ must become plural after ‘mis’"], "answer": 0, "explain": "The possessive matches the noun: one hermano → mi; many → mis."}}, {"myth": "único = unique (only meaning)", "truth": "hijo único = only child", "check": {"question": "In ‘hijo único’, what does ‘único’ mean?", "options": ["only (an only child)", "unique, exactly as in English", "the youngest of the family", "a lonely or sad child"], "answer": 0, "explain": "hijo único = only child; único here = only, not ‘unique’."}}, {"myth": "Tengo alto.", "truth": "Soy alto.", "check": {"question": "Why ‘Soy alto’, not ‘Tengo alto’?", "options": ["height/build uses ‘ser’ (soy alto)", "you must always use ‘estar’ for describing height", "‘alto’ is really a type of hair", "‘tener’ is only used for eyes"], "answer": 0, "explain": "Use ser for what you are like (tall/short); tener is for age, hair and eyes."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 1 — Dictation (listening)", "html": "Listen for the verb: ‘tengo’ (I have — age/hair/eyes) vs ‘soy’ (I am — build). Numbers for age come up a lot, and adjective endings (‑o/‑a) tell you if it is a male or female.", "check": {"question": "You hear ‘tengo… años’. What is being described?", "options": ["the person''s age", "the person''s height", "the person''s job", "where the person lives"], "answer": 0, "explain": "‘tengo… años’ = I am … years old — age uses tener."}}, {"title": "Paper 3 — Translation into English", "html": "‘Tengo quince años’ = ‘I am fifteen’, not ‘I have fifteen years’. Keep ‘hijo único’ natural as ‘only child’. Watch the articles: ‘tengo el pelo…’ = ‘I have … hair’.", "check": {"question": "‘Tengo el pelo corto y soy bastante alto’ =", "options": ["I have short hair and I am quite tall", "I have long flowing hair and I am very short", "My hair is short but I am rather old", "I want short hair and to be taller"], "answer": 0, "explain": "corto = short, bastante alto = quite tall."}}, {"title": "Paper 4 — Writing & translation into Spanish", "html": "Combine identity + appearance + family: ‘Me llamo Ana, tengo quince años y tengo el pelo largo. En mi familia hay cuatro personas.’ At Higher, add a relative ‘que’ or a quantifier (‘bastante’, ‘un poco’).", "check": {"question": "Which answer reaches the top band?", "options": ["Tengo quince años y el pelo castaño; vivo con mi hermana, que es muy graciosa", "Tengo pelo y tengo ojos y una familia y una casa y un perro y un gato también", "Me llamo Ana", "Soy alta"], "answer": 0, "explain": "It links age, appearance, family and a relative clause — range and accuracy, not just piling on words."}}]}, "exam": {"enabled": true, "questions": [{"question": "Read what Pablo says. Answer <strong>in English</strong>.<br>(a) How old is Pablo? (1)<br>(b) Give <strong>one</strong> detail about his appearance. (1)<br>(c) How many people are in his family? (1)<br>(d) Why does he mention Diego — what is Diego like? (1)", "marks": 4, "hint": "Find the number after ‘tengo’, the description after ‘soy/tengo el pelo’, ‘en mi familia somos…’, and the adjective after ‘que es…’.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 4 marks (AO3 Reading)</h5><ul>\n                <li><strong>(a)</strong> 16 (years old) <em>(1)</em>.</li>\n                <li><strong>(b)</strong> ANY ONE of: (quite) tall / short dark hair / wears glasses <em>(1)</em>.</li>\n                <li><strong>(c)</strong> five / 5 <em>(1)</em>.</li>\n                <li><strong>(d)</strong> Diego is (his best friend and is) funny <em>(1)</em>; also accept ‘lives near him’.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Answers in English; do not penalise spelling if the meaning is clear.</li>\n            </ul></div>"}, {"question": "Translate these sentences <strong>into Spanish</strong>.<br>(a) I am fifteen years old. <br>(b) I have short hair. <br>(c) In my family there are four people because I have two brothers.", "marks": 5, "hint": "Age = tener (Tengo… años). ‘I have short hair’ = Tengo el pelo corto. ‘there are’ = hay.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (AO4 Writing: translation)</h5><ul>\n                <li><strong>(a)</strong> Tengo quince años. <em>(1 — must use tener)</em></li>\n                <li><strong>(b)</strong> Tengo el pelo corto. <em>(1 — keep ‘el’)</em></li>\n                <li><strong>(c)</strong> En mi familia hay cuatro personas <em>(1)</em> porque <em>(1)</em> tengo dos hermanos <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent errors. ‘Tengo quince años’ must use tener, not ser.</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', '1-2-relationships-and-role-models', '1.2 Relationships and Role Models', '{"learn": {"enabled": true, "items": [{"title": "Who are the people in my life?", "html": "<p>Core people vocabulary — tap 🔊 to hear each word.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la familia\">la familia</span></td><td>family</td><td><span data-say=\"los padres\">los padres</span></td><td>parents</td></tr>\n              <tr><td><span data-say=\"el hermano\">el hermano</span></td><td>brother</td><td><span data-say=\"la hermana\">la hermana</span></td><td>sister</td></tr>\n              <tr><td><span data-say=\"los abuelos\">los abuelos</span></td><td>grandparents</td><td><span data-say=\"el amigo\">el amigo / la amiga</span></td><td>friend</td></tr>\n              <tr><td><span data-say=\"el novio\">el novio / la novia</span></td><td>boyfriend / girlfriend</td><td><span data-say=\"el hijo\">el hijo / la hija</span></td><td>son / daughter</td></tr>\n            </table>\n            <p>Model: <span data-say=\"En mi familia hay cinco personas: mis padres, mis dos hermanos y yo.\">En mi familia hay cinco personas: mis padres, mis dos hermanos y yo.</span></p>", "check": {"question": "What does ‘los padres’ mean?", "options": ["parents", "grandparents", "godparents", "priests"], "answer": 0, "explain": "los padres = parents. los abuelos = grandparents."}}, {"title": "How do I describe someone''s personality?", "html": "<p>Use <strong>ser</strong> (a permanent trait) + an adjective. The adjective must <strong>agree</strong>: change ‑o → ‑a for a female.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"simpático\">simpático / simpática</span></td><td>nice, friendly</td><td><span data-say=\"gracioso\">gracioso / graciosa</span></td><td>funny</td></tr>\n              <tr><td><span data-say=\"amable\">amable</span></td><td>kind</td><td><span data-say=\"hablador\">hablador / habladora</span></td><td>talkative</td></tr>\n              <tr><td><span data-say=\"cariñoso\">cariñoso / cariñosa</span></td><td>affectionate</td><td><span data-say=\"egoísta\">egoísta</span></td><td>selfish</td></tr>\n              <tr><td><span data-say=\"terco\">terco / terca</span></td><td>stubborn</td><td><span data-say=\"celoso\">celoso / celosa</span></td><td>jealous</td></tr>\n            </table>\n            <p><span data-say=\"Mi madre es muy cariñosa y mi hermano es gracioso.\">Mi madre es muy cariñosa y mi hermano es gracioso.</span> <em>(Note: cariños<strong>a</strong> for ‘madre’, gracios<strong>o</strong> for ‘hermano’.)</em></p>", "check": {"question": "How do you say ‘My sister is funny’?", "options": ["Mi hermana es graciosa", "Mi hermana es gracioso", "Mi hermana está graciosa", "Mi hermana es graciosos"], "answer": 0, "explain": "‘hermana’ is female → gracios­a; personality uses ser, not estar."}}, {"title": "How do I say I get on (or clash) with people?", "html": "<p>The key phrase is the reflexive <strong>llevarse bien / mal con</strong> — to get on well / badly with:</p>\n            <ul>\n              <li><span data-say=\"Me llevo bien con mi madre.\">Me llevo bien con mi madre.</span> — I get on well with my mum.</li>\n              <li><span data-say=\"Me llevo mal con mi hermano.\">Me llevo mal con mi hermano.</span> — I get on badly with my brother.</li>\n            </ul>\n            <p>Other useful verbs:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"pelearse\">pelearse</span></td><td>to fight / argue</td><td><span data-say=\"apoyar\">apoyar</span></td><td>to support</td></tr>\n              <tr><td><span data-say=\"respetar\">respetar</span></td><td>to respect</td><td><span data-say=\"confiar en\">confiar en</span></td><td>to trust</td></tr>\n            </table>", "check": {"question": "‘Me llevo bien con mi madre’ means…", "options": ["I get on well with my mum", "I look exactly like my mother does", "I take my mum out a lot", "I carry my mum''s bags"], "answer": 0, "explain": "llevarse bien con = to get on well with. (Don’t translate ‘llevo’ literally as ‘I carry’.)"}}, {"title": "How do I compare people?", "html": "<p>Use comparatives to make richer sentences:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"más… que\">más… que</span></td><td>more… than</td><td><span data-say=\"menos… que\">menos… que</span></td><td>less… than</td></tr>\n              <tr><td><span data-say=\"tan… como\">tan… como</span></td><td>as… as</td><td><span data-say=\"mejor / peor\">mejor / peor</span></td><td>better / worse</td></tr>\n            </table>\n            <p><span data-say=\"Mi hermana es más habladora que yo, pero yo soy más trabajador.\">Mi hermana es más habladora que yo, pero yo soy más trabajador.</span></p>\n            <p>Careful: ‘better’ is just <strong>mejor</strong> — never ‘más mejor’.</p>", "check": {"question": "How do you say ‘more talkative than me’?", "options": ["más habladora que yo", "más habladora de yo", "tan habladora que yo", "más mejor habladora"], "answer": 0, "explain": "‘more… than’ = más… que; ‘than me’ = que yo."}}, {"title": "How do I talk about role models?", "html": "<p>A role model is <span data-say=\"un modelo a seguir\">un modelo a seguir</span>. Say who and, crucially, <strong>why</strong>:</p>\n            <ul>\n              <li><span data-say=\"admirar\">admirar</span> — to admire; <span data-say=\"respetar\">respetar</span> — to respect</li>\n              <li><span data-say=\"trabajador\">trabajador / trabajadora</span> — hard-working; <span data-say=\"valiente\">valiente</span> — brave</li>\n            </ul>\n            <p><span data-say=\"Mi modelo a seguir es mi abuela porque es muy trabajadora y siempre me apoya.\">Mi modelo a seguir es mi abuela porque es muy trabajadora y siempre me apoya.</span></p>", "check": {"question": "What does ‘un modelo a seguir’ mean?", "options": ["a role model", "a fashion model", "a model railway", "a school subject"], "answer": 0, "explain": "un modelo a seguir = a role model (literally ‘a model to follow’)."}}, {"title": "Higher: relatives and the imperfect", "html": "<p><span class=\"tier-h\">H</span> Join ideas with relative pronouns and describe how things <em>used to be</em> with the imperfect:</p>\n            <ul>\n              <li><span data-say=\"que\">que</span> (who/that), <span data-say=\"quien\">quien</span> (who, after a preposition): <span data-say=\"Admiro a mi padre, que siempre me apoya.\">Admiro a mi padre, que siempre me apoya.</span> <span class=\"tier-h\">H</span></li>\n              <li>Imperfect for ‘used to’: <span data-say=\"De pequeño, me peleaba con mi hermano.\">De pequeño, me peleaba con mi hermano.</span> — When I was little, I used to fight with my brother. <span class=\"tier-h\">H</span></li>\n            </ul>", "check": {"question": "‘De pequeño, me peleaba con mi hermano’ means…", "options": ["When I was little, I used to fight with my brother", "As a young child, I am going to fight with my brother", "I fought with my little brother once", "My little brother fights with me now"], "answer": 0, "explain": "The imperfect ‘me peleaba’ = ‘I used to fight’; ‘de pequeño’ = when I was little."}}]}, "terms": {"enabled": true, "pairs": [{"term": "la familia", "definition": "family"}, {"term": "los padres", "definition": "parents"}, {"term": "los abuelos", "definition": "grandparents"}, {"term": "el hermano / la hermana", "definition": "brother / sister"}, {"term": "simpático / simpática", "definition": "nice, friendly (false friend!)"}, {"term": "gracioso / graciosa", "definition": "funny"}, {"term": "amable", "definition": "kind"}, {"term": "cariñoso / cariñosa", "definition": "affectionate"}, {"term": "egoísta", "definition": "selfish"}, {"term": "terco · celoso", "definition": "stubborn · jealous"}, {"term": "me llevo bien / mal con", "definition": "I get on well / badly with"}, {"term": "pelearse", "definition": "to argue / fight"}, {"term": "apoyar · respetar", "definition": "to support · to respect"}, {"term": "más… que · menos… que", "definition": "more… than · less… than"}, {"term": "mejor / peor", "definition": "better / worse"}, {"term": "un modelo a seguir", "definition": "a role model"}, {"term": "trabajador / trabajadora", "definition": "hard-working"}, {"term": "que / quien (H)", "definition": "who / that (relative pronouns)"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"Me llevo muy bien con mi madre.\" data-listen></span><br>Listen. What is being said?", "options": ["I get on very well with my mum", "I do not get on well with my mum at all", "I look a lot like my mum", "I live quite far from my mum"], "answer": 0, "explain": "‘me llevo bien con’ = I get on well with. Trap B flips bien to a negative; C/D translate ‘llevo’ wrongly."}, {"question": "<span data-say=\"Mi hermano es muy gracioso.\" data-listen></span><br>Listen. What is the brother like?", "options": ["funny", "boring and quiet", "hard-working", "very tall"], "answer": 0, "explain": "gracioso = funny. The distractors are other personality/appearance words that were not said."}, {"question": "<span data-say=\"A veces me peleo con mi hermana.\" data-listen></span><br>Listen. Which is correct?", "options": ["Sometimes I argue with my sister", "I never argue with my sister at all", "I always support my sister a lot", "I get on really well with my sister"], "answer": 0, "explain": "‘a veces me peleo’ = sometimes I argue/fight. The distractors are longer and reverse the meaning."}, {"question": "How do you say ‘My mother is kind’ (agreement + correct verb)?", "options": ["Mi madre es amable", "Mi madre es amablo", "Mi madre está amable", "Mi madre son amable"], "answer": 0, "explain": "‘amable’ has no ‑o/‑a change; personality uses ser (es), and ‘madre’ is singular (es, not son)."}, {"question": "‘simpático’ is a false friend. It means…", "options": ["nice / friendly", "sympathetic and understanding", "quite shy", "very clever"], "answer": 0, "explain": "simpático = nice/friendly, NOT ‘sympathetic’. That is the trap."}, {"question": "Which correctly says ‘more hard-working than me’?", "options": ["más trabajador que yo", "más trabajador de mí", "tan trabajador que yo", "más mejor trabajador"], "answer": 0, "explain": "‘more… than’ = más… que; ‘than me’ = que yo."}, {"question": "‘un modelo a seguir’ means a…", "options": ["role model", "fashion model", "model aeroplane", "new mobile model"], "answer": 0, "explain": "un modelo a seguir = a role model (‘a model to follow’)."}, {"question": "Complete: ‘Me llevo bien ___ mis padres.’", "options": ["con", "para", "de", "a"], "answer": 0, "explain": "llevarse bien CON = to get on well WITH."}, {"question": "Why is ‘Mi hermana es simpático’ wrong?", "options": ["‘hermana’ is female, so it needs ‘simpática’", "‘simpático’ should be in the plural form", "you must use ‘está’, not ‘es’, for people", "‘hermana’ always takes a masculine adjective"], "answer": 0, "explain": "Adjectives agree: a female (hermana) takes simpática."}, {"question": "‘De pequeño me peleaba con mi hermano’ uses which tense?", "options": ["the imperfect (used to)", "the simple future tense", "a one-off completed action", "the present tense right now"], "answer": 0, "explain": "‘me peleaba’ is the imperfect — a repeated past habit (‘used to fight’), a Higher feature."}]}, "fib": {"enabled": true, "questions": [{"text": "Me llevo bien [con] mis padres. <span data-say=\"Me llevo bien con mis padres.\" data-listen>Me llevo bien con mis padres.</span>"}, {"text": "Mi hermano es muy [gracioso]. <span data-say=\"Mi hermano es muy gracioso.\" data-listen>Mi hermano es muy gracioso.</span>"}, {"text": "Mi modelo a seguir es mi [abuela]. <span data-say=\"Mi modelo a seguir es mi abuela.\" data-listen>Mi modelo a seguir es mi abuela.</span>"}, {"text": "Mi madre es muy [cariñosa]. (affectionate — she is female!)"}, {"text": "Me [llevo] mal con mi hermano. (I get on badly — reflexive)"}, {"text": "Mi hermana es más habladora [que] yo. (than)"}, {"text": "Admiro a mi abuela porque es muy [trabajadora]. (hard-working, female)"}]}, "tf": {"enabled": true, "questions": [{"statement": "Personality traits use ‘ser’ (es simpático), not ‘estar’.", "answer": true, "explain": "ser describes permanent traits; estar is for temporary states/moods."}, {"statement": "‘simpático’ means ‘sympathetic’.", "answer": false, "explain": "False friend! simpático = nice / friendly."}, {"statement": "For a female, ‘gracioso’ becomes ‘graciosa’.", "answer": true, "explain": "Adjectives ending in ‑o change to ‑a to agree with a female."}, {"statement": "‘llevarse bien con’ means ‘to carry well with’.", "answer": false, "explain": "It means ‘to get on well with’ — don’t translate ‘llevo’ literally."}, {"statement": "‘better’ in Spanish is ‘más mejor’.", "answer": false, "explain": "‘better’ = mejor on its own; never ‘más mejor’."}, {"statement": "‘los abuelos’ means ‘grandparents’.", "answer": true, "explain": "los abuelos = grandparents; los padres = parents."}, {"statement": "‘un modelo a seguir’ means ‘a role model’.", "answer": true, "explain": "Literally ‘a model to follow’."}, {"statement": "The imperfect ‘me peleaba’ describes something you USED TO do.", "answer": true, "explain": "The imperfect expresses repeated/habitual past actions."}]}, "misc": {"enabled": true, "items": [{"myth": "Mi madre es simpático.", "truth": "Mi madre es simpática.", "check": {"question": "Why ‘simpática’ here?", "options": ["the adjective agrees with the female ‘madre’", "‘simpático’ has to be written in the plural", "you always use the masculine form as default", "the verb ‘ser’ forces an ‑o ending"], "answer": 0, "explain": "Adjectives agree in gender: madre is female → simpática."}}, {"myth": "simpático = sympathetic", "truth": "simpático = nice / friendly", "check": {"question": "What does ‘simpático’ actually mean?", "options": ["nice / friendly", "sympathetic, as you might guess", "extremely intelligent", "rather shy and quiet"], "answer": 0, "explain": "Classic false friend: simpático = nice/friendly."}}, {"myth": "Mi hermano está gracioso.", "truth": "Mi hermano es gracioso.", "check": {"question": "Why ‘es’, not ‘está’, for ‘funny’?", "options": ["a personality trait is permanent → ser", "you must always use ‘tener’ with people", "‘gracioso’ is a plural adjective", "‘estar’ only works in the past"], "answer": 0, "explain": "Permanent personality traits use ser; estar would suggest a temporary state."}}, {"myth": "Llevo bien con mi madre.", "truth": "Me llevo bien con mi madre.", "check": {"question": "What is missing in ‘Llevo bien con…’?", "options": ["the reflexive pronoun ‘me’ (me llevo)", "an accent on the first vowel of llevo", "the linking word ‘a’ after bien", "the article ‘la’ before madre"], "answer": 0, "explain": "llevarse is reflexive: me llevo, te llevas, se lleva."}}, {"myth": "Mi hermana es más mejor que yo.", "truth": "Mi hermana es mejor que yo.", "check": {"question": "Why is ‘más mejor’ wrong?", "options": ["‘mejor’ already means ‘better’ — no ‘más’", "you always need ‘de’ instead of ‘que’ in comparisons", "‘mejor’ should be written as two words", "‘mejor’ must agree and become ‘mejora’"], "answer": 0, "explain": "mejor is already the comparative ‘better’; adding más is a double comparative."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 1 — Dictation (listening)", "html": "Listen for the little words that flip the meaning: ‘bien’ vs ‘mal’ (get on well vs badly), ‘con’ (with), ‘pero’ (but). And catch adjective endings — ‑o or ‑a tells you if it’s about a male or a female.", "check": {"question": "You hear ‘me llevo mal con…’. What does ‘mal’ tell you?", "options": ["they get on badly", "they get on very well", "nobody was mentioned", "it happened in the past"], "answer": 0, "explain": "mal = badly, so ‘me llevo mal con’ = I get on badly with."}}, {"title": "Paper 3 — Translation into English", "html": "Beware false friends: ‘simpático’ = nice, not sympathetic. Don’t translate ‘me llevo bien’ literally — it means ‘I get on well’, not ‘I carry well’.", "check": {"question": "‘Mi primo es simpático pero un poco terco’ =", "options": ["My cousin is nice but a bit stubborn", "My cousin is sympathetic yet very brave", "My cousin is funny and rather generous", "My cousin is shy but really talkative"], "answer": 0, "explain": "simpático = nice; terco = stubborn."}}, {"title": "Paper 4 — Writing & translation into Spanish", "html": "Combine a description, an opinion and a reason: ‘Me llevo bien con mi hermana porque es graciosa, pero a veces es egoísta.’ At Higher, add a relative pronoun (‘…que siempre me apoya’) or the imperfect (‘de pequeño…’).", "check": {"question": "Which answer reaches the top band?", "options": ["Me llevo bien con mi hermana porque es graciosa, aunque a veces es egoísta", "Mi hermana es simpática y muy simpática y también simpática y graciosa siempre", "Tengo una hermana", "Mi hermana es maja"], "answer": 0, "explain": "It links a relationship, a reason and a contrast — range and accuracy, not just piling on words."}}]}, "exam": {"enabled": true, "questions": [{"question": "Read what Marta says. Answer <strong>in English</strong>.<br>(a) Why does she get on well with her mother? (1)<br>(b) Why does she sometimes argue with her brother? (1)<br>(c) Who is her role model? (1)<br>(d) Give <strong>one</strong> reason she admires that person. (1)", "marks": 4, "hint": "Find the reason after ‘porque’ (mum), the reason after ‘porque’ (brother), ‘mi modelo a seguir es…’, and the adjectives after ‘que es…’.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 4 marks (AO3 Reading)</h5><ul>\n                <li><strong>(a)</strong> (because) she is affectionate / always supports her (ANY ONE) <em>(1)</em>.</li>\n                <li><strong>(b)</strong> (because) he is a bit selfish <em>(1)</em>.</li>\n                <li><strong>(c)</strong> her grandmother <em>(1)</em>.</li>\n                <li><strong>(d)</strong> she is hard-working / brave (ANY ONE) <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Answers in English; do not penalise spelling if the meaning is clear.</li>\n            </ul></div>"}, {"question": "Translate these sentences <strong>into Spanish</strong>.<br>(a) My sister is funny. <br>(b) I get on well with my parents. <br>(c) My role model is my grandmother because she is hard-working.", "marks": 5, "hint": "Agreement: ‘sister’ is female → graciosa. ‘I get on well with’ = Me llevo bien con. ‘hard-working’ (female) = trabajadora.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (AO4 Writing: translation)</h5><ul>\n                <li><strong>(a)</strong> Mi hermana es graciosa. <em>(1 — must agree: graciosa)</em></li>\n                <li><strong>(b)</strong> Me llevo bien con mis padres. <em>(1)</em></li>\n                <li><strong>(c)</strong> Mi modelo a seguir es mi abuela <em>(1)</em> porque <em>(1)</em> es trabajadora <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent errors. ‘graciosa’ and ‘trabajadora’ must agree (female).</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', '2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', '{"learn": {"enabled": true, "items": [{"title": "What food and drink words do I need?", "html": "<p>Start with the core nouns for <strong>la comida</strong> (food) and <strong>la bebida</strong> (drink). Every Spanish word below is on the AQA list — tap 🔊 to hear it.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la fruta\">la fruta</span></td><td>fruit</td><td><span data-say=\"las verduras\">las verduras</span></td><td>vegetables</td></tr>\n              <tr><td><span data-say=\"la carne\">la carne</span></td><td>meat</td><td><span data-say=\"el pescado\">el pescado</span></td><td>fish</td></tr>\n              <tr><td><span data-say=\"el pan\">el pan</span></td><td>bread</td><td><span data-say=\"el queso\">el queso</span></td><td>cheese</td></tr>\n              <tr><td><span data-say=\"el agua\">el agua</span></td><td>water</td><td><span data-say=\"la leche\">la leche</span></td><td>milk</td></tr>\n              <tr><td><span data-say=\"el azúcar\">el azúcar</span></td><td>sugar</td><td><span data-say=\"la grasa\">la grasa</span></td><td>fat</td></tr>\n            </table>\n            <p>Two useful meal words: <span data-say=\"el desayuno\">el desayuno</span> (breakfast) and <span data-say=\"la cena\">la cena</span> (dinner).</p>", "check": {"question": "Which pair means ‘fruit and vegetables’?", "options": ["la fruta y las verduras", "las legumbres y el pescado", "la carne y el queso", "el agua y la leche"], "answer": 0, "explain": "la fruta = fruit, las verduras = vegetables. B mixes pulses and fish; C is meat and cheese."}}, {"title": "How do I describe a balanced diet?", "html": "<p>The headline phrase is <span data-say=\"una dieta equilibrada\">una dieta equilibrada</span> — <em>a balanced diet</em>. Notice the adjective <strong>equilibrada</strong> agrees with the feminine noun <strong>dieta</strong>.</p>\n            <ul>\n              <li><span data-say=\"sano\">sano</span> / <span data-say=\"saludable\">saludable</span> = healthy</li>\n              <li><span data-say=\"bueno para la salud\">bueno para la salud</span> = good for your health</li>\n              <li><span data-say=\"malo para la salud\">malo para la salud</span> = bad for your health</li>\n            </ul>\n            <p>Model sentence: <span data-say=\"Como una dieta equilibrada porque es buena para la salud.\">Como una dieta equilibrada porque es buena para la salud.</span> — <em>I eat a balanced diet because it is good for your health.</em></p>", "check": {"question": "Why does ‘equilibrada’ end in ‑a?", "options": ["It agrees with the feminine noun ‘dieta’", "It must copy the last letter of the word before it", "It is a verb ending", "It marks the plural"], "answer": 0, "explain": "Adjectives agree in gender and number with their noun: dieta is feminine singular → equilibrada (not a rule about the previous word)."}}, {"title": "How do I give advice? (se debe / hay que)", "html": "<p>To say what people <strong>should</strong> do, use these impersonal structures — each is followed by an <strong>infinitive</strong>:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"se debe\">se debe…</span></td><td>one must / you should…</td></tr>\n              <tr><td><span data-say=\"no se debe\">no se debe…</span></td><td>one must not…</td></tr>\n              <tr><td><span data-say=\"hay que\">hay que…</span></td><td>you have to…</td></tr>\n            </table>\n            <p>Examples:</p>\n            <ul>\n              <li><span data-say=\"Se debe comer más fruta.\">Se debe comer más fruta.</span> — One should eat more fruit.</li>\n              <li><span data-say=\"No se debe comer demasiada grasa.\">No se debe comer demasiada grasa.</span> — One must not eat too much fat.</li>\n              <li><span data-say=\"Hay que beber mucha agua.\">Hay que beber mucha agua.</span> — You have to drink lots of water.</li>\n            </ul>", "check": {"question": "What kind of word follows ‘se debe’, ‘no se debe’ and ‘hay que’?", "options": ["an infinitive verb", "a fully conjugated past-tense verb", "a plural noun", "an adjective"], "answer": 0, "explain": "All three advice structures are followed by an infinitive (comer, beber, evitar…), never a conjugated form."}}, {"title": "How do I say what I am going to change?", "html": "<p>Use the near future — <strong>voy a</strong> + <strong>infinitive</strong> — to state a plan or intention:</p>\n            <ul>\n              <li><span data-say=\"Voy a comer más verduras.\">Voy a comer más verduras.</span> — I am going to eat more vegetables.</li>\n              <li><span data-say=\"Voy a evitar la comida rápida.\">Voy a evitar la comida rápida.</span> — I am going to avoid fast food.</li>\n              <li><span data-say=\"Voy a beber menos azúcar.\">Voy a beber menos azúcar.</span> — I am going to have less sugar.</li>\n            </ul>\n            <p><strong>evitar</strong> = to avoid, <strong>la comida rápida</strong> = fast food. Add a time phrase to extend: <span data-say=\"todos los días\">todos los días</span> (every day), <span data-say=\"a menudo\">a menudo</span> (often).</p>", "check": {"question": "How do you say ‘I am going to avoid fast food’?", "options": ["Voy a evitar la comida rápida", "Se debe evitar la comida rápida", "Evito la comida rápida", "Hay que evitar la comida rápida"], "answer": 0, "explain": "voy a + infinitive = a future plan; ‘I am going to avoid’ = Voy a evitar."}}, {"title": "How do I give opinions and reasons?", "html": "<p>Opinions lift your mark. Use <strong>gustar</strong>-type verbs and join ideas with connectors:</p>\n            <ul>\n              <li><span data-say=\"Me gusta la fruta.\">Me gusta la fruta.</span> — I like fruit. <em>(singular thing)</em></li>\n              <li><span data-say=\"Me gustan las verduras.\">Me gustan las verduras.</span> — I like vegetables. <em>(plural → gusta<strong>n</strong>)</em></li>\n              <li><span data-say=\"Prefiero el pescado.\">Prefiero el pescado.</span> — I prefer fish.</li>\n            </ul>\n            <p>Connectors: <span data-say=\"porque\">porque</span> (because), <span data-say=\"pero\">pero</span> (but), <span data-say=\"también\">también</span> (also). Example: <span data-say=\"Me gusta la carne, pero no como carne todos los días porque es mala para la salud.\">Me gusta la carne, pero no como carne todos los días porque es mala para la salud.</span></p>", "check": {"question": "Why is it ‘Me gustan las verduras’ (not ‘gusta’)?", "options": ["verduras is plural, so the verb agrees", "it expresses a future plan, not a preference", "verduras is a feminine singular noun here", "it is simply someone’s opinion"], "answer": 0, "explain": "gustar agrees with the THING liked; verduras is plural → gustan (nothing to do with plans or opinions)."}}, {"title": "Higher: reach for the top band", "html": "<p><span class=\"tier-h\">H</span> To push into the higher band, add a <strong>conditional</strong> recommendation and a <strong>concession</strong>:</p>\n            <ul>\n              <li><span data-say=\"Se debería reducir el azúcar.\">Se debería reducir el azúcar.</span> — One <em>should</em> reduce sugar. <span class=\"tier-h\">H</span></li>\n              <li><span data-say=\"Lo más importante es llevar una dieta variada.\">Lo más importante es llevar una dieta variada.</span> — The most important thing is to have a varied diet. <span class=\"tier-h\">H</span></li>\n              <li><span data-say=\"Aunque me gusta el chocolate, intento comer sano.\">Aunque me gusta el chocolate, intento comer sano.</span> — Although I like chocolate, I try to eat healthily. <span class=\"tier-h\">H</span></li>\n            </ul>\n            <p>Aim for: <strong>opinion + reason + connector + a second tense</strong> in one sentence.</p>", "check": {"question": "Which sentence shows a typically Higher-tier feature?", "options": ["Se debería reducir el azúcar", "Me gusta mucho la fruta fresca del país", "Como pan casi todos los días", "Bebo bastante agua con las comidas"], "answer": 0, "explain": "‘se debería’ is a conditional — a Higher feature. Option B is longer but only present-tense opinion."}}]}, "terms": {"enabled": true, "pairs": [{"term": "la fruta", "definition": "fruit"}, {"term": "las verduras", "definition": "vegetables"}, {"term": "el pescado", "definition": "fish"}, {"term": "el agua", "definition": "water"}, {"term": "el azúcar", "definition": "sugar"}, {"term": "la grasa", "definition": "fat"}, {"term": "una dieta equilibrada", "definition": "a balanced diet"}, {"term": "sano / saludable", "definition": "healthy"}, {"term": "se debe + infinitive", "definition": "one should / must…"}, {"term": "no se debe + infinitive", "definition": "one must not…"}, {"term": "hay que + infinitive", "definition": "you have to…"}, {"term": "voy a + infinitive", "definition": "I am going to… (plan)"}, {"term": "evitar", "definition": "to avoid"}, {"term": "la comida rápida", "definition": "fast food"}, {"term": "bueno / malo para la salud", "definition": "good / bad for your health"}, {"term": "porque · pero · también", "definition": "because · but · also"}, {"term": "se debería (H)", "definition": "one should… (conditional)"}, {"term": "aunque (H)", "definition": "although"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"Se debe comer más fruta y verduras.\" data-listen></span><br>Listen. What is the advice?", "options": ["One should eat more fruit and vegetables", "One must not eat so much fruit or fatty food", "They always eat their fruit and vegetables first", "You have to grow your own fruit and vegetables"], "answer": 0, "explain": "‘se debe comer más’ = one should eat more. Trap B flips it to a negative; C and D change the verb — you have to actually hear ‘se debe … más’."}, {"question": "<span data-say=\"Voy a beber menos azúcar.\" data-listen></span><br>Listen. What does the speaker plan to do?", "options": ["Have less sugar", "Drink more sugary things", "Give up fizzy drinks completely", "Stop drinking coffee with sugar"], "answer": 0, "explain": "‘voy a beber menos azúcar’ = I’m going to have less sugar. Trap B swaps menos→more; C and D add detail that was never said."}, {"question": "<span data-say=\"No se debe comer demasiada grasa.\" data-listen></span><br>Listen. Which is correct?", "options": ["One must not eat too much fat", "One should add a little healthy fat", "You are allowed to eat as much as you like", "It is fine to fry your food in lots of oil"], "answer": 0, "explain": "‘no se debe comer demasiada grasa’ = one must not eat too much fat. Every distractor is longer AND reverses the meaning — you must hear the ‘no’."}, {"question": "‘una dieta equilibrada’ means…", "options": ["a balanced diet", "a varied menu", "a healthy lifestyle", "a strict weight-loss plan"], "answer": 0, "explain": "equilibrada = balanced. ‘variada’ (varied), ‘vida sana’ (lifestyle) and a diet-plan are close but wrong."}, {"question": "Only ONE sentence is fully correct. Which?", "options": ["Me gustan las verduras", "Me gusta las verduras", "A mí me gusta mucho las verduras", "Yo gusto las verduras todos los días"], "answer": 0, "explain": "The thing liked is plural (verduras) so the verb is gustan. B fails to agree; C still uses gusta with a plural; D wrongly conjugates gustar as ‘yo gusto’."}, {"question": "How do you say ‘I am going to eat more vegetables’?", "options": ["Voy a comer más verduras", "Como muchas más verduras ahora", "Se debe comer más verduras hoy", "Voy comer más verduras cada día"], "answer": 0, "explain": "A plan = voy a + infinitive. B is present tense; C is impersonal advice; D drops the ‘a’ that ‘voy a’ needs."}, {"question": "In ‘Voy a evitar la comida rápida’, ‘evitar’ means to…", "options": ["avoid", "prepare it quickly", "cut down on it", "order it less often"], "answer": 0, "explain": "evitar = to avoid. The longer options are tempting ‘sort of healthy’ ideas, but none means avoid."}, {"question": "‘Bebo mucha ___.’ — which word fits BOTH the grammar and ‘I drink lots of water’?", "options": ["agua", "leche", "zumo", "café con leche"], "answer": 0, "explain": "‘mucha’ is feminine, so leche/agua both fit grammatically — but only ‘agua’ = water. zumo is masculine (mucho zumo)."}, {"question": "Which word means ‘because’ (gives a reason)?", "options": ["porque", "aunque", "también", "pero"], "answer": 0, "explain": "porque = because. ‘aunque’ (although) is the closest trap; también = also; pero = but."}, {"question": "Why is ‘Se debería reducir el azúcar’ a strong Higher-tier phrase?", "options": ["It uses the conditional", "It is in the present tense", "It gives a direct command", "It describes a completed past action"], "answer": 0, "explain": "‘se debería’ = one should (conditional) — a Higher feature. The traps name other tenses/moods of similar length."}]}, "fib": {"enabled": true, "questions": [{"text": "Se [debe] comer más fruta. <span data-say=\"Se debe comer más fruta.\" data-listen>Se debe comer más fruta.</span>"}, {"text": "Voy a [evitar] la comida rápida. <span data-say=\"Voy a evitar la comida rápida.\" data-listen>Voy a evitar la comida rápida.</span>"}, {"text": "Hay que beber mucha [agua]. <span data-say=\"Hay que beber mucha agua.\" data-listen>Hay que beber mucha agua.</span>"}, {"text": "Me [gustan] las verduras. (I like vegetables — plural!)"}, {"text": "Como una dieta [equilibrada]. (balanced)"}, {"text": "No se debe comer demasiado [azúcar]. (sugar)"}, {"text": "Prefiero el pescado [porque] es bueno para la salud. (because)"}]}, "tf": {"enabled": true, "questions": [{"statement": "‘una dieta equilibrada’ means ‘a balanced diet’.", "answer": true, "explain": "equilibrada = balanced."}, {"statement": "‘se debe’ is followed by a past-tense verb.", "answer": false, "explain": "It is followed by an infinitive: se debe comer / beber / evitar."}, {"statement": "‘Me gustan las verduras’ is correct because ‘verduras’ is plural.", "answer": true, "explain": "gustar agrees with the thing liked; plural → gustan."}, {"statement": "‘evitar’ means ‘to enjoy’.", "answer": false, "explain": "evitar = to avoid."}, {"statement": "‘voy a comer’ describes a future plan.", "answer": true, "explain": "voy a + infinitive = near future."}, {"statement": "‘el azúcar’ means ‘salt’.", "answer": false, "explain": "el azúcar = sugar; salt = la sal."}, {"statement": "‘porque’ means ‘but’.", "answer": false, "explain": "porque = because; ‘but’ = pero."}, {"statement": "‘Se debería reducir el azúcar’ uses the conditional and suits Higher tier.", "answer": true, "explain": "se debería = one should (conditional)."}]}, "misc": {"enabled": true, "items": [{"myth": "Me gusta las verduras.", "truth": "Me gustan las verduras.", "check": {"question": "Why is it ‘Me gustan las verduras’?", "options": ["verduras is plural, so it becomes gustan", "the subject ‘yo’ is what forces the ending gustan here", "verduras is a masculine noun", "the sentence is in the past"], "answer": 0, "explain": "gustar agrees with the thing liked (verduras, plural) → gustan. It is NOT the person that drives the ending — that is the classic error."}}, {"myth": "una dieta equilibrado", "truth": "una dieta equilibrada", "check": {"question": "Why must it be ‘equilibrada’?", "options": ["the adjective agrees with the feminine noun ‘dieta’", "it copies the gender of whichever verb happens to be closest to it", "the masculine form is the safe default", "adjectives only change in the plural"], "answer": 0, "explain": "Adjectives agree with their noun in gender AND number: dieta is feminine singular → equilibrada."}}, {"myth": "Se debe comí más fruta.", "truth": "Se debe comer más fruta.", "check": {"question": "What must follow ‘se debe’?", "options": ["an infinitive (comer)", "a verb written in a past tense form", "a plural noun", "an adjective"], "answer": 0, "explain": "‘se debe’ always takes an infinitive, never a conjugated past form."}}, {"myth": "Voy comer más verduras.", "truth": "Voy a comer más verduras.", "check": {"question": "What is missing in ‘Voy comer…’?", "options": ["the linking word ‘a’ (voy a + infinitive)", "an accent on the final vowel of the infinitive comer", "the pronoun ‘me’", "the article ‘las’"], "answer": 0, "explain": "The near future is voy/vas/va + a + infinitive; the ‘a’ is compulsory."}}, {"myth": "Como comida sensible.", "truth": "Como comida sana.", "check": {"question": "Why is ‘sensible’ wrong here for ‘healthy’?", "options": ["it is a false friend meaning ‘sensitive’", "it is the plural of an adjective you can’t use", "it is a verb, not an adjective", "it simply needs a written accent"], "answer": 0, "explain": "False friend: Spanish ‘sensible’ = sensitive. Healthy = sano/sana/saludable."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 1 — Dictation (listening)", "html": "In the dictation you hear short sentences and write them down. Listen for whole chunks you know (‘se debe comer…’, ‘voy a…’) rather than single sounds. Get the accents where you can, but a minor accent slip is not always penalised — spelling the word right matters most.", "check": {"question": "What is the best dictation strategy?", "options": ["Write the whole chunks you recognise, not single sounds", "Write down each and every individual letter that you hear", "Only ever write the very first word of each sentence", "Translate it straight into English as you listen"], "answer": 0, "explain": "You already know whole phrases (‘se debe comer’, ‘voy a…’); catching them as chunks is far more reliable than letter-by-letter."}}, {"title": "Paper 3 — Translation into English", "html": "Don’t translate word-for-word. ‘Se debe comer fruta’ is ‘One should / you should eat fruit’, not ‘It must to eat fruit’. Keep the tense: ‘voy a evitar’ = ‘I am going to avoid’.", "check": {"question": "‘Voy a evitar la comida rápida’ means…", "options": ["I am going to avoid fast food", "I am not going to avoid fast food", "I used to avoid fast food a lot", "I have already avoided fast food"], "answer": 0, "explain": "voy a + infinitive = the near future. The traps flip the meaning to a negative or a different tense — all longer than the answer."}}, {"title": "Paper 4 — Writing & translation into Spanish", "html": "For top marks combine an opinion, a reason and a second tense in one sentence: ‘Me gusta la carne, pero voy a comer menos porque es mala para la salud.’ At Higher, add ‘se debería…’ or ‘aunque…’.", "check": {"question": "Which sentence would score highest?", "options": ["Me gusta la carne, pero voy a comer menos porque es mala para la salud", "A mí me gusta mucho la carne y como carne y la carne está muy rica siempre", "Me gusta la carne", "Como carne todos los días"], "answer": 0, "explain": "The winner combines an opinion, a connector, a second tense (future) AND a reason. Option B is even longer but just repeats one idea in the present — length alone is not what scores."}}]}, "exam": {"enabled": true, "questions": [{"question": "Read what Carlos says. Answer the questions <strong>in English</strong>.<br>(a) What does Carlos have for breakfast? (2)<br>(b) Why doesn’t he like fast food? (1)<br>(c) Name <strong>one</strong> thing he is going to change next year. (1)", "marks": 4, "hint": "Find ‘el desayuno’, then the reason after ‘porque’, then the ‘voy a…’ plans.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 4 marks (AO3 Reading)</h5><ul>\n                <li><strong>(a)</strong> fruit / cereals <em>(1 mark each, 2 total)</em>; also accept ‘drinks lots of water’ as an alternative detail.</li>\n                <li><strong>(b)</strong> (because) it is bad for your/his health <em>(1)</em>.</li>\n                <li><strong>(c)</strong> ANY ONE of: eat less sugar / do more exercise <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Answers in English. Do not penalise spelling if the meaning is clear.</li>\n                <li>(a) needs two distinct items for both marks.</li>\n            </ul></div>"}, {"question": "Translate these sentences <strong>into Spanish</strong>.<br>(a) I like fruit. <br>(b) One should eat vegetables. <br>(c) I am going to avoid fast food because it is bad for your health.", "marks": 5, "hint": "‘I like’ + singular = Me gusta. ‘One should eat’ = Se debe comer. ‘I am going to avoid’ = Voy a evitar.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (AO4 Writing: translation)</h5><ul>\n                <li><strong>(a)</strong> Me gusta la fruta. <em>(1)</em></li>\n                <li><strong>(b)</strong> Se debe comer verduras / las verduras. <em>(1)</em></li>\n                <li><strong>(c)</strong> Voy a evitar la comida rápida <em>(1)</em> porque <em>(1)</em> es mala para la salud <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent errors; ‘mala/malo’ must agree sensibly. ‘comida rápida’ spelt without the accent is condoned once.</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', '2-2-exercise-health-problems-and-advice', '2.2 Exercise, Health Problems and Advice', '{"learn": {"enabled": true, "items": [{"title": "How do I talk about exercise and sport?", "html": "<p>The key verb is <span data-say=\"hacer ejercicio\">hacer ejercicio</span> (to do exercise / to work out). Here is the core vocabulary — tap 🔊 to hear each one.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el deporte\">el deporte</span></td><td>sport</td><td><span data-say=\"correr\">correr</span></td><td>to run</td></tr>\n              <tr><td><span data-say=\"nadar\">nadar</span></td><td>to swim</td><td><span data-say=\"montar en bicicleta\">montar en bicicleta</span></td><td>to cycle</td></tr>\n              <tr><td><span data-say=\"el gimnasio\">el gimnasio</span></td><td>the gym</td><td><span data-say=\"entrenar\">entrenar</span></td><td>to train</td></tr>\n              <tr><td><span data-say=\"estar en forma\">estar en forma</span></td><td>to be fit</td><td><span data-say=\"activo\">activo / activa</span></td><td>active</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"Para estar en forma, hago ejercicio tres veces por semana.\">Para estar en forma, hago ejercicio tres veces por semana.</span> — <em>To be fit, I exercise three times a week.</em></p>", "check": {"question": "What does ‘estar en forma’ mean?", "options": ["to be fit", "to run a race", "to go to the gym building", "to fill in a paper form"], "answer": 0, "explain": "estar en forma = to be fit / in shape. It is a false friend — ‘forma’ here is not a paper ‘form’."}}, {"title": "How do I say what hurts? (me duele / me duelen)", "html": "<p>To say something hurts, use <strong>doler</strong> — and it behaves <em>exactly like</em> <strong>gustar</strong>: the verb agrees with the body part, not with you.</p>\n            <ul>\n              <li>ONE thing hurts → <span data-say=\"me duele\">me duele</span>: <span data-say=\"Me duele la cabeza.\">Me duele la cabeza.</span> (My head hurts.)</li>\n              <li>MORE THAN ONE → <span data-say=\"me duelen\">me duelen</span>: <span data-say=\"Me duelen los pies.\">Me duelen los pies.</span> (My feet hurt.)</li>\n            </ul>\n            <p>Body parts (<strong>el cuerpo</strong>):</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la cabeza\">la cabeza</span></td><td>head</td><td><span data-say=\"el estómago\">el estómago</span></td><td>stomach</td></tr>\n              <tr><td><span data-say=\"la garganta\">la garganta</span></td><td>throat</td><td><span data-say=\"la espalda\">la espalda</span></td><td>back</td></tr>\n              <tr><td><span data-say=\"las piernas\">las piernas</span></td><td>legs</td><td><span data-say=\"los ojos\">los ojos</span></td><td>eyes</td></tr>\n            </table>", "check": {"question": "Why is it ‘Me duelen los pies’ and not ‘Me duele los pies’?", "options": ["‘los pies’ is plural, so the verb is plural", "‘doler’ is a verb that is always plural in Spanish", "‘pies’ is a masculine noun", "it describes a future plan"], "answer": 0, "explain": "Like gustar, doler agrees with the body part; ‘los pies’ is plural → duelen (doler is NOT always plural)."}}, {"title": "How do I describe health problems?", "html": "<p>Use <strong>estar</strong> (a temporary state) for how you feel:</p>\n            <ul>\n              <li><span data-say=\"estar enfermo\">estar enfermo / enferma</span> — to be ill</li>\n              <li><span data-say=\"estar cansado\">estar cansado / cansada</span> — to be tired</li>\n              <li><span data-say=\"estar resfriado\">estar resfriado / resfriada</span> — to have a cold</li>\n              <li><span data-say=\"el estrés\">el estrés</span> — stress; <span data-say=\"estar estresado\">estar estresado</span> — to be stressed</li>\n            </ul>\n            <p>Example: <span data-say=\"Estoy muy cansado porque no duermo bien.\">Estoy muy cansado porque no duermo bien.</span> — <em>I am very tired because I don’t sleep well.</em></p>", "check": {"question": "Which verb do you use for ‘I am tired’ — a temporary state?", "options": ["estar → estoy cansado", "ser → soy cansado", "tener → tengo cansado", "hacer → hago cansado"], "answer": 0, "explain": "Temporary states and feelings use estar: estoy cansado. ‘ser’ would describe a permanent trait."}}, {"title": "How do I give health advice?", "html": "<p>Reuse the advice structures from 2.1 — each is followed by an <strong>infinitive</strong>:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"se debe descansar\">se debe descansar</span></td><td>one should rest</td></tr>\n              <tr><td><span data-say=\"no se debe fumar\">no se debe fumar</span></td><td>one must not smoke</td></tr>\n              <tr><td><span data-say=\"hay que dormir ocho horas\">hay que dormir ocho horas</span></td><td>you have to sleep eight hours</td></tr>\n              <tr><td><span data-say=\"deberías relajarte\">deberías relajarte</span> <span class=\"tier-h\">H</span></td><td>you should relax</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Para evitar el estrés, se debe descansar y hacer ejercicio.\">Para evitar el estrés, se debe descansar y hacer ejercicio.</span></p>", "check": {"question": "What follows ‘se debe’, ‘hay que’ and ‘deberías’?", "options": ["an infinitive (descansar, dormir…)", "a verb conjugated in the preterite past tense", "an adjective that agrees", "a noun on its own"], "answer": 0, "explain": "All the advice structures take an infinitive."}}, {"title": "How do I talk about bad habits?", "html": "<p>Common ‘malos hábitos’ (bad habits) and how to reject them:</p>\n            <ul>\n              <li><span data-say=\"fumar\">fumar</span> — to smoke; <span data-say=\"el tabaco\">el tabaco</span> — tobacco</li>\n              <li><span data-say=\"beber alcohol\">beber alcohol</span> — to drink alcohol; <span data-say=\"las drogas\">las drogas</span> — drugs</li>\n              <li><span data-say=\"dejar de fumar\">dejar de + infinitive</span> — to stop doing something: <span data-say=\"dejar de fumar\">dejar de fumar</span> (to stop smoking)</li>\n            </ul>\n            <p><span data-say=\"No se debe fumar porque es muy malo para la salud.\">No se debe fumar porque es muy malo para la salud.</span></p>", "check": {"question": "‘dejar de fumar’ means…", "options": ["to stop smoking", "to let others smoke", "to smoke a little more", "to enjoy smoking outside"], "answer": 0, "explain": "dejar de + infinitive = to stop doing something; dejar de fumar = to stop smoking."}}, {"title": "Higher: reflexives and future plans", "html": "<p><span class=\"tier-h\">H</span> Many health verbs are <strong>reflexive</strong> — the action is done to yourself, so they take <strong>me / te / se</strong>:</p>\n            <ul>\n              <li><span data-say=\"relajarse\">relajarse</span> → <span data-say=\"me relajo\">me relajo</span> (I relax)</li>\n              <li><span data-say=\"acostarse\">acostarse</span> → <span data-say=\"me acuesto temprano\">me acuesto temprano</span> (I go to bed early)</li>\n            </ul>\n            <p>Combine with a plan or a conditional for the top band:</p>\n            <ul>\n              <li><span data-say=\"Voy a dejar de fumar y acostarme más temprano.\">Voy a dejar de fumar y acostarme más temprano.</span> <span class=\"tier-h\">H</span></li>\n              <li><span data-say=\"Se debería evitar el estrés para mantenerse sano.\">Se debería evitar el estrés para mantenerse sano.</span> <span class=\"tier-h\">H</span></li>\n            </ul>", "check": {"question": "Which sentence correctly uses a reflexive verb?", "options": ["Me acuesto temprano", "Acuesto temprano cada noche", "Yo acuesto muy temprano", "Se acuesto temprano"], "answer": 0, "explain": "acostarse is reflexive: (yo) me acuesto. Dropping ‘me’ or using the wrong pronoun is wrong."}}]}, "terms": {"enabled": true, "pairs": [{"term": "hacer ejercicio", "definition": "to do exercise"}, {"term": "el deporte", "definition": "sport"}, {"term": "estar en forma", "definition": "to be fit"}, {"term": "el gimnasio", "definition": "the gym"}, {"term": "me duele…", "definition": "…hurts (one thing)"}, {"term": "me duelen…", "definition": "…hurt (more than one)"}, {"term": "la cabeza · el estómago", "definition": "head · stomach"}, {"term": "la garganta · la espalda", "definition": "throat · back"}, {"term": "estar enfermo / cansado", "definition": "to be ill / tired"}, {"term": "estar resfriado / constipado", "definition": "to have a cold"}, {"term": "el estrés", "definition": "stress"}, {"term": "fumar · las drogas", "definition": "to smoke · drugs"}, {"term": "dejar de + infinitive", "definition": "to stop doing something"}, {"term": "se debe descansar", "definition": "one should rest"}, {"term": "relajarse (H)", "definition": "to relax (reflexive)"}, {"term": "acostarse (H)", "definition": "to go to bed (reflexive)"}, {"term": "deberías / se debería (H)", "definition": "you should / one should (conditional)"}, {"term": "para mantenerse sano (H)", "definition": "to stay healthy"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"Me duele la cabeza.\" data-listen></span><br>Listen. What is the problem?", "options": ["My head hurts", "My head and my back both hurt", "I have banged my head badly", "My headache has finally gone"], "answer": 0, "explain": "‘me duele la cabeza’ = my head hurts. The traps add a second body part, a cause, or the opposite meaning."}, {"question": "<span data-say=\"Voy a hacer más ejercicio.\" data-listen></span><br>Listen. What is the plan?", "options": ["To do more exercise", "To do a bit less exercise", "One should exercise more often", "I already exercise every day"], "answer": 0, "explain": "‘voy a hacer más ejercicio’ = I’m going to do more exercise. Trap B swaps más→less; C is impersonal advice; D is present tense."}, {"question": "<span data-say=\"No se debe fumar.\" data-listen></span><br>Listen. Which is correct?", "options": ["One must not smoke", "One should smoke only a little", "You are allowed to smoke here", "I have never smoked in my life"], "answer": 0, "explain": "‘no se debe fumar’ = one must not smoke. Every distractor is longer and reverses or weakens the ‘no’."}, {"question": "How do you say ‘my feet hurt’?", "options": ["Me duelen los pies", "Me duele los pies", "Me duelo los pies", "Yo duelo mucho los pies"], "answer": 0, "explain": "doler agrees with the body part; ‘los pies’ is plural → duelen. B fails to agree; C/D conjugate doler as if it were a normal verb."}, {"question": "Careful — ‘Estoy constipado’ means…", "options": ["I have a cold", "I am constipated", "I am very tired today", "I feel completely fine"], "answer": 0, "explain": "False friend! ‘constipado’ = having a cold, NOT constipated. The obvious guess is the trap."}, {"question": "How do you say ‘I go to bed early’?", "options": ["Me acuesto temprano", "Me acuesto muy tarde entre semana", "Acuesto temprano cada noche", "Se acuesta temprano"], "answer": 0, "explain": "acostarse is reflexive → me acuesto; ‘temprano’ = early. B says ‘tarde’ (late); C drops ‘me’; D is ‘he/she’."}, {"question": "Which sentence gives POSITIVE health advice?", "options": ["Se debe descansar más", "No se debe descansar nunca", "No se debe hacer ejercicio", "Se debe fumar a menudo"], "answer": 0, "explain": "‘se debe descansar más’ = one should rest more (good advice). The others are negatives or bad advice."}, {"question": "Complete: ‘Para estar en forma, hay que ___ ejercicio.’", "options": ["hacer", "hago", "haciendo", "hecho"], "answer": 0, "explain": "‘hay que’ takes an infinitive → hacer. The others are conjugated / non-finite forms."}, {"question": "‘Me duele la garganta’ — where does it hurt?", "options": ["throat", "stomach", "back", "head"], "answer": 0, "explain": "la garganta = throat. estómago = stomach, espalda = back, cabeza = head."}, {"question": "‘Se debería evitar el estrés’ uses which verb form?", "options": ["the conditional (should)", "a completed past-tense action", "the ordinary present tense", "a direct command"], "answer": 0, "explain": "‘se debería’ = one should → conditional, a strong Higher-tier feature."}]}, "fib": {"enabled": true, "questions": [{"text": "Me [duele] la cabeza. <span data-say=\"Me duele la cabeza.\" data-listen>Me duele la cabeza.</span>"}, {"text": "No se debe [fumar] porque es malo para la salud. <span data-say=\"No se debe fumar porque es malo para la salud.\" data-listen>No se debe fumar porque es malo para la salud.</span>"}, {"text": "Para estar en forma, hay que hacer [ejercicio]. <span data-say=\"Para estar en forma, hay que hacer ejercicio.\" data-listen>Para estar en forma, hay que hacer ejercicio.</span>"}, {"text": "Me [duelen] los pies. (my feet hurt — plural!)"}, {"text": "Estoy muy [cansado] porque no duermo bien. (tired)"}, {"text": "Voy a [dejar] de fumar. (to stop)"}, {"text": "Me [acuesto] temprano para dormir ocho horas. (I go to bed — reflexive)"}]}, "tf": {"enabled": true, "questions": [{"statement": "‘doler’ works like ‘gustar’ — it agrees with the body part, not the person.", "answer": true, "explain": "Me duele la cabeza / me duelen los pies — the verb matches the body part."}, {"statement": "‘Estoy constipado’ means ‘I am constipated’.", "answer": false, "explain": "False friend! It means ‘I have a cold’."}, {"statement": "‘se debe’ is followed by an infinitive.", "answer": true, "explain": "se debe descansar / fumar / dormir — always an infinitive."}, {"statement": "‘dejar de fumar’ means ‘to start smoking’.", "answer": false, "explain": "dejar de + infinitive = to STOP doing something — to stop smoking."}, {"statement": "For temporary feelings like ‘tired’ you use ‘estar’ (estoy cansado).", "answer": true, "explain": "Temporary states use estar, not ser."}, {"statement": "‘la garganta’ means ‘the stomach’.", "answer": false, "explain": "la garganta = throat; el estómago = stomach."}, {"statement": "‘acostarse’ is a reflexive verb, so ‘I go to bed’ is ‘me acuesto’.", "answer": true, "explain": "Reflexive: me acuesto, te acuestas, se acuesta."}, {"statement": "‘Se debería evitar el estrés’ uses the conditional and suits Higher tier.", "answer": true, "explain": "se debería = one should (conditional)."}]}, "misc": {"enabled": true, "items": [{"myth": "Me duele los pies.", "truth": "Me duelen los pies.", "check": {"question": "Why is ‘Me duele los pies’ wrong?", "options": ["‘los pies’ is plural, so it must be ‘duelen’", "you must always put the verb ‘estar’ in front of it", "‘pies’ needs a written accent", "the pronoun should be ‘te’, not ‘me’"], "answer": 0, "explain": "doler agrees with the body part; plural body part → duelen."}}, {"myth": "Estoy constipado. (= I am constipated)", "truth": "Estoy constipado. (= I have a cold)", "check": {"question": "What does ‘constipado’ really mean?", "options": ["having a cold", "being constipated as you would guess", "feeling completely healthy", "being extremely tired"], "answer": 0, "explain": "Classic false friend: constipado = having a cold."}}, {"myth": "Soy cansado.", "truth": "Estoy cansado.", "check": {"question": "Why ‘Estoy cansado’, not ‘Soy cansado’?", "options": ["tiredness is a temporary state → estar", "you should always use ‘tener’ with any feeling", "‘cansado’ is a plural adjective", "‘ser’ is only for the past"], "answer": 0, "explain": "Temporary states and moods take estar; ser would mean it is a permanent trait."}}, {"myth": "Acuesto temprano.", "truth": "Me acuesto temprano.", "check": {"question": "What is missing in ‘Acuesto temprano’?", "options": ["the reflexive pronoun ‘me’ (me acuesto)", "an accent on the final letter of the verb form", "the linking word ‘a’", "the article ‘la’"], "answer": 0, "explain": "acostarse is reflexive: you need me/te/se — ‘me acuesto’."}}, {"myth": "Se debe fumar para relajarse.", "truth": "No se debe fumar; se debe descansar para relajarse.", "check": {"question": "Why is the ‘wrong’ sentence a problem?", "options": ["it recommends smoking, which is bad advice", "it is missing an infinitive after ‘se debe’", "‘relajarse’ is spelt incorrectly", "it uses the past tense by mistake"], "answer": 0, "explain": "The grammar is fine, but the ADVICE is wrong — smoking is malo para la salud."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 1 — Dictation (listening)", "html": "Health sentences reuse chunks you know: ‘me duele…’, ‘se debe…’, ‘voy a…’. Listen for whether it is ‘duele’ (one thing) or ‘duelen’ (more than one) — the ending tells you if the body part is singular or plural.", "check": {"question": "You hear ‘…duelen…’. What does that tell you?", "options": ["more than one body part hurts", "only one single body part is actually hurting", "nothing hurts at all", "it is a future plan"], "answer": 0, "explain": "The -n ending of ‘duelen’ signals a plural body part (los pies, las piernas…)."}}, {"title": "Paper 3 — Translation into English", "html": "Watch the false friends: ‘constipado’ = having a cold, ‘estar en forma’ = to be fit. Keep ‘me duele la cabeza’ natural: ‘my head hurts’ / ‘I have a headache’, not ‘the head hurts me’.", "check": {"question": "‘Estoy resfriado y me duele la garganta’ =", "options": ["I have a cold and my throat hurts", "I am stressed out and my whole back hurts", "I am tired and my head hurts", "I am fit and my legs hurt"], "answer": 0, "explain": "resfriado = having a cold; la garganta = throat."}}, {"title": "Paper 4 — Writing & translation into Spanish", "html": "Combine a problem, advice and a plan: ‘Estoy estresado, así que se debe descansar y voy a acostarme más temprano.’ At Higher, add a reflexive and a conditional: ‘se debería…’, ‘relajarse’.", "check": {"question": "Which answer reaches the top band?", "options": ["Estoy estresado, así que voy a descansar y acostarme más temprano", "Estoy muy estresado y estresado y cansado todos los días sin parar nunca", "Estoy mal", "Me duele todo"], "answer": 0, "explain": "It links a problem, a plan, a reflexive and a time phrase — range and accuracy, not just length."}}]}, "exam": {"enabled": true, "questions": [{"question": "Read what Elena says. Answer <strong>in English</strong>.<br>(a) Name <strong>one</strong> sport Elena does. (1)<br>(b) What is wrong with her this week? (1)<br>(c) Why does she never smoke? (1)<br>(d) What is she going to change next month? (1)", "marks": 4, "hint": "Find the sports after ‘hago deporte’, the problem after ‘esta semana’, the reason after ‘porque’, and the plan after ‘voy a’.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 4 marks (AO3 Reading)</h5><ul>\n                <li><strong>(a)</strong> swimming / cycling (ANY ONE) <em>(1)</em>.</li>\n                <li><strong>(b)</strong> she has a cold / her throat hurts (ANY ONE) <em>(1)</em>.</li>\n                <li><strong>(c)</strong> (because) it is very bad for your/her health <em>(1)</em>.</li>\n                <li><strong>(d)</strong> go to bed earlier / sleep eight hours <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Answers in English; do not penalise spelling if the meaning is clear.</li>\n            </ul></div>"}, {"question": "Translate these sentences <strong>into Spanish</strong>.<br>(a) My head hurts. <br>(b) One must not smoke. <br>(c) I am going to do more exercise because it is good for your health.", "marks": 5, "hint": "‘My head hurts’ = doler like gustar (Me duele…). ‘One must not smoke’ = No se debe… ‘I am going to do’ = Voy a hacer…", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (AO4 Writing: translation)</h5><ul>\n                <li><strong>(a)</strong> Me duele la cabeza. <em>(1)</em></li>\n                <li><strong>(b)</strong> No se debe fumar. <em>(1)</em></li>\n                <li><strong>(c)</strong> Voy a hacer más ejercicio <em>(1)</em> porque <em>(1)</em> es bueno para la salud <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent errors. ‘Me duele la cabeza’ must use the singular ‘duele’.</li>\n            </ul></div>"}]}}'::jsonb),
